        let benefits = "Base Stats";

        if (level === 0) {
            nextThreshold = MASTERY_THRESHOLDS.ADEPT;
            progress = (count / MASTERY_THRESHOLDS.ADEPT) * 100;
        } else if (level === 1) {
            label = "Adept";
            color = "text-stone-300";
            nextThreshold = MASTERY_THRESHOLDS.ARTISAN;
            progress = ((count - MASTERY_THRESHOLDS.ADEPT) / (MASTERY_THRESHOLDS.ARTISAN - MASTERY_THRESHOLDS.ADEPT)) * 100;
            benefits = "Value +10%, Stats +10%";
        } else {
            label = "Artisan";
            color = "text-yellow-400";
            nextThreshold = count;
            progress = 100;
            benefits = "Value +25%, Stats +20%, Cost -5 Energy";
        }

        masteryInfo = { count, level, nextThreshold, progress, label, color, benefits };
    }

    return (
        <div className="relative h-full w-full bg-stone-950 overflow-hidden">

        {/* Initial Furnace Requirement Overlay */}
        {!hasFurnace && (
            <div className="absolute inset-0 z-[70] flex items-center justify-center">
                <div className="absolute inset-0 bg-stone-950/80 backdrop-blur-md animate-in fade-in duration-1000"></div>
                <div className="relative z-10 p-10 max-w-lg w-full bg-stone-900 border-2 border-amber-900/50 rounded-3xl shadow-[0_0_50px_rgba(0,0,0,0.5)] flex flex-col items-center text-center animate-in zoom-in-95 duration-500">
                    <div className="w-24 h-24 bg-stone-800 rounded-full flex items-center justify-center mb-8 border border-stone-700 shadow-inner relative group">
                        <div className="absolute inset-0 rounded-full bg-amber-500/5 animate-pulse"></div>
