                        </button>
                        {hasWorkbench && (
                            <button 
                                onClick={() => setActiveCategory('ARMOR')}
                                className="w-full py-3 text-stone-500 hover:text-stone-300 font-bold transition-colors text-sm"
                            >
                                I'll stick to Leatherwork for now
                            </button>
