                        ) : !canEnterForge ? (
                            <>
                                <Flame className="w-6 h-6 text-red-500" />
                                Need Heat or Fuel
                            </>
                        ) : !hasEnergy ? (
                             <>
                                <Zap className="w-6 h-6 text-red-500" />
                                Need Energy
                            </>
                        ) : !canAffordResources(selectedItem) ? (
