                        <div className="w-16 h-16 mt-2 mb-2 relative flex items-center justify-center group-hover:scale-110 transition-transform">
                             <img 
                                src={getAssetUrl(`${marketItem.id}.png`)}
                                alt={itemName}
                                className="w-full h-full object-contain filter drop-shadow-lg z-10"
                                onError={(e) => {
                                    e.currentTarget.style.display = 'none';
                                    const fallback = e.currentTarget.parentElement?.querySelector('.fallback-icon');
                                    if (fallback) fallback.classList.remove('hidden');
                                }}
                             />

                             <div className="fallback-icon hidden text-3xl">
                                 {marketItem.id === 'charcoal' ? '⚫' : 
                                  marketItem.id === 'iron_ore' ? '🪨' : 
                                  marketItem.id === 'copper_ore' ? '🔶' : 
                                  marketItem.id === 'tin_ore' ? '⚪' : 
                                  marketItem.id === 'oak_log' ? '🪵' : 
                                  marketItem.id.startsWith('scroll') ? '📜' : 
                                  marketItem.id === 'furnace' ? '🔥' : 
                                  marketItem.id === 'workbench' ? '🛠️' :
                                  marketItem.id === 'energy_potion' ? '🧪' : '📦'}
                             </div>
                        </div>

                        <div className="flex flex-col items-center w-full">
                            <span className={`font-bold text-sm line-clamp-1 leading-tight px-1 ${marketItem.id.startsWith('scroll') || isKeyItem ? 'text-amber-400' : 'text-stone-200'}`}>
                                {itemName}
                            </span>
                            <span className="text-[10px] text-stone-500 mt-0.5">{itemType}</span>
                        </div>

                        <div className="bg-stone-950 px-3 py-1 rounded-full border border-stone-700 text-amber-400 font-mono text-xs font-bold w-full">
                            {isInCart && isOneTimeDisabled ? 'In Cart' : `${marketItem.price} G`}
                        </div>

                        {isKeyItem && !isOneTimeDisabled && (
                            <div className="absolute inset-0 border-2 border-amber-500/50 rounded-lg pointer-events-none animate-pulse"></div>
                        )}
                    </button>
                );
            })}
         </div>
      </div>

      {/* Right: Cart */}
      <div className="w-full md:w-96 bg-stone-950 rounded-xl border border-stone-800 flex flex-col shadow-xl min-h-0">
          <div className="bg-stone-900 p-4 border-b border-stone-800 flex items-center justify-between shrink-0">
              <div className="flex items-center gap-2">
                  <ShoppingCart className="w-5 h-5 text-stone-400" />
                  <h3 className="text-stone-300 font-bold">Cart</h3>
              </div>
              <span className="text-stone-500 text-sm">{Object.keys(cart).length} items</span>
          </div>

          <div className="flex-1 overflow-y-auto p-4 space-y-3 min-h-0">
              {Object.keys(cart).length === 0 ? (
                  <div className="h-full flex flex-col items-center justify-center text-stone-600 italic">
                      <ShoppingBag className="w-10 h-10 mb-2 opacity-20" />
                      Your cart is empty.
                  </div>
              ) : (
                  Object.entries(cart).map(([id, count]) => {
                      const marketItem = MARKET_CATALOG.find(i => i.id === id);

                      let itemName = '';
                      if (id === 'furnace') {
                          itemName = 'Blacksmith Furnace';
                      } else if (id === 'workbench') {
                          itemName = 'Artisan Workbench';
                      } else {
                          const itemDef = Object.values(MATERIALS).find(i => i.id === id);
                          if (!itemDef) return null;
                          itemName = itemDef.name;
                      }

                      if (!marketItem) return null;

                      const isOneTime = id === 'furnace' || id === 'workbench' || id.startsWith('scroll_');

                      return (
                          <div key={id} className="flex items-center justify-between bg-stone-900 p-3 rounded-lg border border-stone-800">
                              <div>
                                  <div className="text-stone-200 font-bold">{itemName}</div>
                                  <div className="text-stone-500 text-xs font-mono">{marketItem.price} G x {count}</div>
                              </div>

                              <div className="flex items-center gap-3">
                                  <div className="text-amber-500 font-bold font-mono">
                                      {marketItem.price * (count as number)}
                                  </div>
                                  <div className="flex items-center gap-1">
                                      {!isOneTime && (
                                        <>
                                            <button onClick={() => removeFromCart(id)} className="p-1 hover:bg-stone-800 rounded text-stone-400">
                                                <Minus className="w-4 h-4" />
                                            </button>
                                        </>
                                      )}
                                      <button onClick={() => deleteFromCart(id)} className="p-1 hover:bg-red-900/30 rounded text-stone-500 hover:text-red-500 ml-1">
                                          <Trash2 className="w-4 h-4" />
                                      </button>
                                  </div>
                              </div>
                          </div>
                      );
                  })
              )}
          </div>

          <div className="bg-stone-900 p-6 border-t border-stone-800 shrink-0">
              <div className="flex justify-between items-end mb-4">
                  <span className="text-stone-400 text-sm uppercase font-bold">Total Cost</span>
                  <span className={`text-2xl font-mono font-bold ${totalCost > state.stats.gold ? 'text-red-500' : 'text-amber-400'}`}>
                      {totalCost} G
                  </span>
              </div>
              <button
                  onClick={handleBuy}
                  disabled={totalCost === 0 || totalCost > state.stats.gold}
                  className="w-full py-4 bg-amber-700 hover:bg-amber-600 disabled:bg-stone-800 disabled:text-stone-600 disabled:cursor-not-allowed text-amber-50 font-bold rounded-lg shadow-lg hover:shadow-amber-900/20 transition-all flex items-center justify-center gap-2"
              >
                  {totalCost > state.stats.gold ? 'Insufficient Gold' : 'Purchase Items'}
              </button>
          </div>
      </div>

    </div>
  );
};

export default MarketTab;

import React, { createContext, useContext, useReducer, useMemo, useEffect, useRef } from 'react';
import { GameContextType } from '../types/index';
import { gameReducer } from '../state/gameReducer';
import { createInitialGameState } from '../state/initial-game-state';
import { EquipmentItem, EquipmentSlotType } from '../types/inventory';
import { ShopCustomer } from '../types/shop';
import { Mercenary } from '../models/Mercenary';
import { PrimaryStats } from '../models/Stats';
import { GAME_CONFIG } from '../config/game-config';
import { getEnergyCost } from '../utils/craftingLogic';
import { GameEvent } from '../types/events';

const GameContext = createContext<GameContextType | undefined>(undefined);

export const useGame = () => {
  const context = useContext(GameContext);
  if (context === undefined) {
    throw new Error('useGame must be used within a GameProvider');
  }
  return context;
};

export const GameProvider: React.FC<React.PropsWithChildren> = ({ children }) => {
  const [state, dispatch] = useReducer(gameReducer, undefined, createInitialGameState);

  // --- Helper Trigger ---
  const triggerEnergyHighlight = () => {
      dispatch({ type: 'SET_UI_EFFECT', payload: { effect: 'energyHighlight', value: true } });
      setTimeout(() => {
          dispatch({ type: 'SET_UI_EFFECT', payload: { effect: 'energyHighlight', value: false } });
      }, 3000);
  };

  // --- ACTIONS ---
  const actions = useMemo(() => ({
    repairItem: () => {
        if (state.stats.energy < GAME_CONFIG.ENERGY_COST.REPAIR) {
            triggerEnergyHighlight();
            return;
        }
        dispatch({ type: 'REPAIR_WORK' });
    },
    rest: () => dispatch({ type: 'SLEEP' }),
    confirmSleep: () => dispatch({ type: 'CONFIRM_SLEEP' }),

    triggerEvent: (event: GameEvent) => dispatch({ type: 'TRIGGER_EVENT', payload: event }),
    handleEventOption: (action: () => void) => {
      action();
      dispatch({ type: 'CLOSE_EVENT' });
    },
    closeEvent: () => dispatch({ type: 'CLOSE_EVENT' }),

    // Crafting
    startCrafting: (item: EquipmentItem) => {
        const masteryCount = state.craftingMastery[item.id] || 0;
        const energyCost = getEnergyCost(item, masteryCount);
        if (state.stats.energy < energyCost) {
            triggerEnergyHighlight();
            return;
        }
        dispatch({ type: 'START_CRAFTING', payload: { item } });
    },
    cancelCrafting: (item: EquipmentItem) => dispatch({ type: 'CANCEL_CRAFTING', payload: { item } }),
    finishCrafting: (item: EquipmentItem, quality: number, bonus?: number) => dispatch({ type: 'FINISH_CRAFTING', payload: { item, quality, bonus } }),
    craftItem: (item: EquipmentItem, quality: number) => dispatch({ type: 'FINISH_CRAFTING', payload: { item, quality } }),

    buyItems: (items: { id: string; count: number }[], totalCost: number) => dispatch({ type: 'BUY_MARKET_ITEMS', payload: { items, totalCost } }),
    sellItem: (itemId: string, count: number, price: number, equipmentInstanceId?: string, customer?: Mercenary) =>
        dispatch({ type: 'SELL_ITEM', payload: { itemId, count, price, equipmentInstanceId, customer } }),
    toggleShop: () => {
        if (!state.forge.isShopOpen && state.stats.energy < GAME_CONFIG.ENERGY_COST.OPEN_SHOP) {
            triggerEnergyHighlight();
            return;
        }
        dispatch({ type: 'TOGGLE_SHOP' });
    },
    addMercenary: (merc: Mercenary) => dispatch({ type: 'ADD_KNOWN_MERCENARY', payload: merc }),

    consumeItem: (id: string, count: number) => dispatch({ type: 'PAY_COST', payload: { items: [{ id, count }] } }),

    enqueueCustomer: (customer: ShopCustomer) => dispatch({ type: 'ENQUEUE_CUSTOMER', payload: customer }),
    nextCustomer: () => dispatch({ type: 'NEXT_CUSTOMER' }),
    dismissCustomer: () => dispatch({ type: 'DISMISS_CUSTOMER' }),

    setCrafting: (isCrafting: boolean) => dispatch({ type: 'SET_CRAFTING', payload: isCrafting }),
    updateForgeStatus: (temp: number) => dispatch({ type: 'UPDATE_FORGE_STATUS', payload: { temp } }),
    toggleJournal: () => dispatch({ type: 'TOGGLE_JOURNAL' }),

    hireMercenary: (mercenaryId: string, cost: number) => dispatch({ type: 'HIRE_MERCENARY', payload: { mercenaryId, cost } }),
    fireMercenary: (mercenaryId: string) => dispatch({ type: 'FIRE_MERCENARY', payload: { mercenaryId } }),

    startExpedition: (dungeonId: string, partyIds: string[]) => dispatch({ type: 'START_EXPEDITION', payload: { dungeonId, partyIds } }),
    completeExpedition: (expeditionId: string) => dispatch({ type: 'COMPLETE_EXPEDITION', payload: { expeditionId } }),
    claimExpedition: (expeditionId: string) => dispatch({ type: 'CLAIM_EXPEDITION', payload: { expeditionId } }),
    dismissDungeonResult: () => dispatch({ type: 'DISMISS_DUNGEON_RESULT' }),

    // Equipment Actions
    equipItem: (mercenaryId: string, inventoryItemId: string) => dispatch({ type: 'EQUIP_ITEM', payload: { mercenaryId, inventoryItemId } }),
    unequipItem: (mercenaryId: string, slot: EquipmentSlotType) => dispatch({ type: 'UNEQUIP_ITEM', payload: { mercenaryId, slot } }),

    // Item Actions
    useItem: (itemId: string) => dispatch({ type: 'USE_ITEM', payload: { itemId } }),

    // Stat Actions
    allocateStat: (mercenaryId: string, stat: keyof PrimaryStats) => dispatch({ type: 'ALLOCATE_STAT', payload: { mercenaryId, stat } }),
    updateMercenaryStats: (mercenaryId: string, stats: PrimaryStats) => dispatch({ type: 'UPDATE_MERCENARY_STATS', payload: { mercenaryId, stats } }),

    triggerEnergyHighlight

  }), [state.stats.energy, state.craftingMastery, state.forge.isShopOpen, state.activeEvent]);

  return (
    <GameContext.Provider value={{ state, actions }}>
      {children}
    </GameContext.Provider>
  );
};

export { GameContext };

import React from 'react';
import { useGame } from '../../context/GameContext';
import { User, XCircle, CheckCircle, Flame, AlertCircle } from 'lucide-react';

const EventModal = () => {
  const { state, actions } = useGame();
  const { activeEvent, inventory, stats } = state;

  if (!activeEvent) return null;

  // Helper to check if player can afford an option
  const canAfford = (option: typeof activeEvent.options[0]) => {
    if (!option.cost) return true;
    if (option.cost.gold && stats.gold < option.cost.gold) return false;
    if (option.cost.items) {
      for (const costItem of option.cost.items) {
        const invItem = inventory.find(i => i.id === costItem.id);
        if (!invItem || invItem.quantity < costItem.count) return false;
      }
    }
    return true;
  };

  // Determine Icon based on title/content
  const getIcon = () => {
      const title = activeEvent.title.toLowerCase();
      if (title.includes('forge') || title.includes('furnace')) return <Flame className="w-8 h-8 text-amber-500" />;
      if (title.includes('warning') || title.includes('attention')) return <AlertCircle className="w-8 h-8 text-amber-500" />;
      return <User className="w-8 h-8 text-amber-500" />;
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
      <div className="bg-stone-900 border-2 border-amber-600 rounded-xl max-w-lg w-full shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-300">

        {/* Header */}
        <div className="bg-stone-800 p-6 border-b border-stone-700 flex items-center space-x-4">
          <div className="bg-amber-900/30 p-3 rounded-full border border-amber-700">
            {getIcon()}
          </div>
          <h2 className="text-2xl font-serif text-amber-100">{activeEvent.title}</h2>
        </div>

        {/* Content */}
        <div className="p-6 space-y-6">
          <p className="text-stone-300 text-lg leading-relaxed italic">
            "{activeEvent.description}"
          </p>

          {/* Options */}
          <div className="space-y-3">
            {activeEvent.options.map((option, idx) => {
              const affordable = canAfford(option);
              return (
                <button
                  key={idx}
                  onClick={() => affordable && actions.handleEventOption(option.action)}
                  disabled={!affordable}
                  className={`w-full text-left p-4 rounded-lg border transition-all flex justify-between items-center group ${
                    affordable 
                      ? 'bg-stone-800 border-stone-600 hover:border-amber-500 hover:bg-stone-750 text-stone-100' 
                      : 'bg-stone-900/50 border-stone-800 text-stone-600 cursor-not-allowed'
                  }`}
                >
                  <span className="font-medium group-hover:text-amber-400 transition-colors">{option.label}</span>
                  {affordable ? (
                     <CheckCircle className="w-5 h-5 text-stone-500 group-hover:text-amber-500" />
                  ) : (
                     <XCircle className="w-5 h-5 text-red-900" />
                  )}
                </button>
              );
            })}
          </div>
        </div>

      </div>
    </div>
  );
};

export default EventModal;

