import React, { useEffect, useRef } from 'react';
import Phaser from 'phaser';
import { X, Hammer, Flame } from 'lucide-react';
import { getAssetUrl } from '../../../utils';
import { useGame } from '../../../context/GameContext';
import { MATERIALS } from '../../../data/materials';

interface SmithingMinigameProps {
  onComplete: (score: number) => void;
  onClose: () => void;
  difficulty?: number;
}

class SmithingScene extends Phaser.Scene {
  add!: Phaser.GameObjects.GameObjectFactory;
  make!: Phaser.GameObjects.GameObjectCreator;
  scale!: Phaser.Scale.ScaleManager;
  tweens!: Phaser.Tweens.TweenManager;
  time!: Phaser.Time.Clock;
  cameras!: Phaser.Cameras.Scene2D.CameraManager;
  input!: Phaser.Input.InputPlugin;
  load!: Phaser.Loader.LoaderPlugin;
  textures!: Phaser.Textures.TextureManager;

  private anvilImage!: Phaser.GameObjects.Image;
  private anvilSurface!: Phaser.GameObjects.Graphics;
  private targetRing!: Phaser.GameObjects.Graphics;
  private approachRing!: Phaser.GameObjects.Graphics;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private comboText!: Phaser.GameObjects.Text;
  private hammer!: Phaser.GameObjects.Container;
  private bladePlaceholder!: Phaser.GameObjects.Rectangle;
  private hammerHitArea!: Phaser.GameObjects.Rectangle;
  private infoText!: Phaser.GameObjects.Text;
  private ambientGlow!: Phaser.GameObjects.Arc;

  private centerX: number = 0;
  private centerY: number = 0;
  private hitX: number = 0;
  private hitY: number = 0;

  // Precision Hit Testing for rotated rectangle
  private hitPoly!: Phaser.Geom.Polygon;

  // Perspective Trapezoid Area (Percentage based)
  private anvilConfig = {
      topWidthRatio: 0.65,
      botWidthRatio: 1.1, 
      heightRatio: 0.4, 
      yOffset: 120,     
      leftHeightFactor: 0.9 
  };

  private startRadius: number = 220; 
  private targetRadius: number = 55;
  private currentRadius: number = 220;
  private shrinkDuration: number = 2000;
  private ringTimer: number = 0;

  private score: number = 0;
  private targetScore: number = 100;
  private combo: number = 0;
  private lastHitTime: number = 0;
  private hitCooldown: number = 200;
  private onComplete?: (score: number) => void;
  private onStatusUpdate?: (temp: number) => void;
  private isFinished: boolean = false;
  private isPlaying: boolean = false;
  private isReadyToStart: boolean = false;

  private temperature: number = 0;
  private coolingRate: number = 2;
  private currentTempStage: 'COLD' | 'AURA' | 'HOT' | 'WARM' | 'NORMAL' = 'COLD';

  private tempBar!: Phaser.GameObjects.Rectangle;
  private tempValueText!: Phaser.GameObjects.Text;
  private bellowsContainer!: Phaser.GameObjects.Container;
  private isPumping: boolean = false;

  private uiContainer!: Phaser.GameObjects.Container;

  constructor() {
    super('SmithingScene');
  }

  init(data: { onComplete: (score: number) => void, difficulty: number, initialTemp: number, onStatusUpdate: (temp: number) => void }) {
    this.onComplete = data.onComplete;
    this.onStatusUpdate = data.onStatusUpdate;
    this.shrinkDuration = Math.max(800, 2000 - (data.difficulty * 200));
    this.coolingRate = 2 + (data.difficulty * 0.8);
    this.score = 0;
    this.combo = 0;
    this.temperature = data.initialTemp || 0;
    this.isFinished = false;
    this.isPlaying = false;
    this.isReadyToStart = this.temperature > 0;
  }

  preload() {
    this.load.crossOrigin = 'anonymous';
    this.load.image('anvil_img', getAssetUrl('anvil.png'));
    this.load.image('spark_perfect', getAssetUrl('particle_spark1.png'));
    this.load.image('spark_normal', getAssetUrl('particle_spark2.png'));
  }

  create() {
    this.setupResponsiveLayout();

    // 1. Base Layer (Anvil Image & Surface)
    this.anvilImage = this.add.image(0, 0, 'anvil_img').setDepth(1).setOrigin(0.5, 0.5);
    this.anvilSurface = this.add.graphics().setDepth(2);

    // 2. The Blade Placeholder (Vertical)
    this.bladePlaceholder = this.add.rectangle(0, 0, 200, 600, 0x57534e).setDepth(3);
    this.bladePlaceholder.setAngle(-100);

    // 2.1 Hit Area (Logical overlay for polygon testing)
    this.hammerHitArea = this.add.rectangle(0, 0, 200, 400, 0x00ff00).setDepth(3).setAlpha(0);
    this.hammerHitArea.setAngle(-100);

    // 3. Interaction Layer
    this.targetRing = this.add.graphics().setDepth(5);
    this.approachRing = this.add.graphics().setDepth(5);

    // 4. Hammer
    this.createHammer();

    // 5. UI Elements Container
    this.uiContainer = this.add.container(0, 0).setDepth(20);
    this.setupUI();

    // 6. Effects
    this.ambientGlow = this.add.circle(0, 0, 500, 0xea580c, 0).setFillStyle(0xea580c, 0.25).setDepth(0);

    // Initial Refresh
    this.handleResize();

    // Inputs
    this.input.keyboard?.on('keydown-SPACE', this.handleInput, this);
    this.input.on('pointerdown', (p: any, objs: any[]) => {
        if (objs.includes(this.bellowsContainer) || this.bellowsContainer.list.some(c => objs.includes(c))) this.pumpBellows();
        else this.handleInput();
    }, this);

    // Resize Event
    this.scale.on('resize', this.handleResize, this);
  }

  setupResponsiveLayout() {
    this.centerX = this.scale.width / 2;
    this.centerY = this.scale.height / 2;
  }

  handleResize() {
      this.centerX = this.scale.width / 2;
      this.centerY = this.scale.height / 2;

      // 1. Redraw Anvil Perspective to fill width
      this.drawAnvilSurface();

      // 2. Position Blade & Hit Area
      const surfaceH = this.scale.height * this.anvilConfig.heightRatio;
      const b = this.centerY + (surfaceH / 2) + this.anvilConfig.yOffset;
      const bladeY = b - (surfaceH * 0.45);

      this.bladePlaceholder.setPosition(this.centerX, bladeY);
      this.hammerHitArea.setPosition(this.centerX, bladeY);

      // Update the hit polygon for precise detection on resize
      this.rebuildHitPoly();

      // 3. Reposition UI Container
      this.uiContainer.setPosition(0, 0);
      this.repositionUIElements();

      // 4. Background
      this.cameras.main.setBackgroundColor('#1c1917');

      // 5. Ambient Glow
      if (this.ambientGlow) {
          this.ambientGlow.setPosition(this.centerX, this.scale.height);
          this.ambientGlow.setRadius(this.scale.width * 0.6);
      }

      if (!this.isPlaying) {
          this.infoText?.setPosition(this.centerX, this.centerY - 220);
      }
  }

  private rebuildHitPoly() {
    // Current visual bounds
    const w = this.hammerHitArea.width * this.hammerHitArea.scaleX;
    const h = this.hammerHitArea.height * this.hammerHitArea.scaleY;

    const cx = this.hammerHitArea.x;
    const cy = this.hammerHitArea.y;

    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    const cos = Math.cos(rad);
    const sin = Math.sin(rad);

    // Calculate rotated world coordinates for the corners
    const corners = [
      { x: -w/2, y: -h/2 },
      { x:  w/2, y: -h/2 },
      { x:  w/2, y:  h/2 },
      { x: -w/2, y:  h/2 },
    ].map(p => ({
      x: cx + p.x * cos - p.y * sin,
      y: cy + p.x * sin + p.y * cos,
    }));

    this.hitPoly = new Phaser.Geom.Polygon(corners);
  }

  private isPointerInHitArea(px: number, py: number) {
    return this.hitPoly && Phaser.Geom.Polygon.Contains(this.hitPoly, px, py);
  }

  drawAnvilSurface() {
      this.anvilSurface.clear();

      const w = this.scale.width;
      const h = this.scale.height;
      const { topWidthRatio, botWidthRatio, heightRatio, yOffset, leftHeightFactor } = this.anvilConfig;

      const topW = w * topWidthRatio;
      const botW = w * botWidthRatio;
      const surfaceH = h * heightRatio;

      const b = this.centerY + (surfaceH / 2) + yOffset;
      const tL = b - (surfaceH * leftHeightFactor);
      const tR = b - surfaceH;

      const points = [
          { x: this.centerX - (topW / 2), y: tL }, 
          { x: this.centerX + (topW / 2), y: tR }, 
          { x: this.centerX + (botW / 2), y: b },  
          { x: this.centerX - (botW / 2), y: b }   
      ];

      if (this.anvilImage) {
          const targetWidth = w * 1.3;
          const scale = targetWidth / this.anvilImage.width;
          this.anvilImage.setScale(scale);
          this.anvilImage.setPosition(this.centerX, b);
          this.anvilImage.setAngle(0); 
      }

      this.anvilSurface.fillStyle(0x27272a, 0.4);
      this.anvilSurface.fillPoints(points, true);
      this.anvilSurface.lineStyle(6, 0x3f3f46, 0.8);
      this.anvilSurface.strokePoints(points, true);

      this.anvilSurface.fillStyle(0x3f3f46, 0.2);
      this.anvilSurface.fillEllipse(this.centerX, (tL + tR + b + b) / 4, botW * 0.6, surfaceH * 0.65);
  }

  createHammer() {
      this.hammer = this.add.container(0, 0).setDepth(15).setAlpha(0);
      const head = this.add.rectangle(0, 0, 100, 60, 0x18181b).setStrokeStyle(3, 0x52525b);
      const handle = this.add.rectangle(-70, 0, 120, 16, 0x451a03).setOrigin(1, 0.5).setStrokeStyle(1, 0x000000);
      this.hammer.add([handle, head]);
  }

  setupUI() {
      this.progressBar = this.add.rectangle(0, 40, 0, 12, 0xeab308).setOrigin(0, 0.5);
      this.uiContainer.add([
          this.add.rectangle(0, 40, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e).setName('progBg'),
          this.progressBar
      ]);

      this.tempBar = this.add.rectangle(0, 0, 18, 250, 0x3b82f6).setOrigin(0.5, 1).setScale(1, 0);
      this.tempValueText = this.add.text(0, 0, '20°C', { fontFamily: 'monospace', fontSize: '16px', color: '#fff', fontStyle: 'bold' }).setOrigin(0.5);

      this.uiContainer.add([
          this.add.rectangle(0, 0, 32, 260, 0x1c1917).setStrokeStyle(3, 0x57534e).setName('tempFrame'),
          this.add.rectangle(0, 0, 24, 250, 0x0c0a09).setName('tempBg'),
          this.tempBar,
          this.tempValueText
      ]);

      this.createBellows();

      this.comboText = this.add.text(0, 0, '', { fontFamily: 'Impact', fontSize: '48px', color: '#fcd34d', stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setAlpha(0);
      this.infoText = this.add.text(0, 0, this.isReadyToStart ? 'CLICK TO START' : 'FORGE IS COLD\nADD FUEL TO HEAT', { fontFamily: 'monospace', fontSize: '28px', color: this.isReadyToStart ? '#fbbf24' : '#3b82f6', align: 'center', stroke: '#000', strokeThickness: 5 }).setOrigin(0.5);

      this.uiContainer.add([this.comboText, this.infoText]);
      this.tweens.add({ targets: this.infoText, alpha: 0.5, yoyo: true, repeat: -1, duration: 800 });
  }

  repositionUIElements() {
      const { width, height } = this.scale;

      const progBg = this.uiContainer.getByName('progBg') as Phaser.GameObjects.Rectangle;
      progBg.setPosition(this.centerX, 40);
      this.progressBar.setPosition(this.centerX - 150, 40);

      const tX = width - 60;
      const tY = this.centerY - 50;
      (this.uiContainer.getByName('tempFrame') as any).setPosition(tX, tY);
      (this.uiContainer.getByName('tempBg') as any).setPosition(tX, tY);
      this.tempBar.setPosition(tX, tY + 125);
      this.tempValueText.setPosition(tX, tY - 160);

      this.bellowsContainer.setPosition(tX, tY + 220);

      this.infoText.setPosition(this.centerX, this.centerY - 220);
      this.comboText.setPosition(this.centerX, this.centerY - 300);
  }

  createBellows() {
      this.bellowsContainer = this.add.container(0, 0);
      const bag = this.add.rectangle(0, 0, 70, 50, 0xa16207).setStrokeStyle(2, 0x451a03);
      const top = this.add.rectangle(0, -25, 75, 14, 0x78350f).setStrokeStyle(2, 0x451a03);
      const bot = this.add.rectangle(0, 25, 75, 14, 0x78350f).setStrokeStyle(2, 0x451a03);
      const txt = this.add.text(0, 55, 'PUMP', { fontSize: '14px', color: '#a8a29e', fontFamily: 'monospace', fontStyle: 'bold' }).setOrigin(0.5);

      this.bellowsContainer.add([bag, top, bot, txt]);
      this.bellowsContainer.setInteractive(new Phaser.Geom.Rectangle(-40, -40, 80, 120), Phaser.Geom.Rectangle.Contains);
      this.uiContainer.add(this.bellowsContainer);
  }

  pumpBellows() {
      if (this.isPumping) return;
      this.isPumping = true;
      this.tweens.add({ targets: this.bellowsContainer, scaleY: 0.7, duration: 80, yoyo: true, onComplete: () => this.isPumping = false });
      if (this.temperature > 0) {
          this.temperature = Math.min(100, this.temperature + 8);
          if (!this.isPlaying && !this.isReadyToStart) {
              this.isReadyToStart = true;
              this.infoText.setText('CLICK TO START').setColor('#fbbf24');
          }
      }
  }

  public heatUp() {
      this.temperature = Math.min(100, this.temperature + 40);
      if (!this.isPlaying) { this.isReadyToStart = true; this.infoText.setText('CLICK TO START').setColor('#fbbf24'); }
  }

  public getTemperature() { return this.temperature; }

  update(time: number, delta: number) {
    if (this.isFinished) return;
    if (this.isPlaying && this.currentTempStage !== 'COLD') this.handleRingLogic(delta);

    this.temperature = Math.max(0, this.temperature - (this.coolingRate * (delta / 1000)));
    this.refreshVisuals();

    if (!this.isPlaying && this.isReadyToStart && this.temperature <= 0) {
        this.isReadyToStart = false;
        this.infoText.setText('FORGE IS COLD\nADD FUEL TO HEAT').setColor('#3b82f6');
    }
  }

  refreshVisuals() {
      const ratio = this.temperature / 100;
      this.tempBar.scaleY = ratio;
      this.tempValueText.setText(`${Math.floor(20 + ratio * 1480)}°C`);

      const progress = this.score / this.targetScore;

      const coldColor = new Phaser.Display.Color(63, 63, 70); 
      const hotColor = new Phaser.Display.Color(253, 230, 138);  
      const currentTint = Phaser.Display.Color.Interpolate.ColorWithColor(coldColor, hotColor, 100, ratio * 100);
      const colorVal = Phaser.Display.Color.GetColor(currentTint.r, currentTint.g, currentTint.b);

      this.bladePlaceholder.setFillStyle(colorVal, 1);
      const targetScale = 0.5 + (progress * 0.8);
      this.bladePlaceholder.setScale(1.1, targetScale);

      if (this.ambientGlow) {
          this.ambientGlow.setFillStyle(0xea580c, ratio * 0.25);
      }

      if (this.temperature <= 0) this.currentTempStage = 'COLD';
      else if (this.temperature > 75) this.currentTempStage = 'AURA';
      else if (this.temperature > 40) this.currentTempStage = 'HOT';
      else if (this.temperature > 15) this.currentTempStage = 'WARM';
      else this.currentTempStage = 'NORMAL';
  }

  handleRingLogic(delta: number) {
      this.ringTimer += delta;
      const t = Math.min(this.ringTimer / this.shrinkDuration, 1.5);
      this.currentRadius = this.startRadius * (1 - (t * t));
      let ringColor = this.currentRadius < this.targetRadius ? 0xffffff : 0xfabf24;

      this.approachRing.clear().lineStyle(8, ringColor, 0.6).strokeCircle(this.hitX, this.hitY, Math.max(0, this.currentRadius));

      if (this.currentRadius < this.targetRadius - 30) { this.combo = 0; this.resetRing(); }
  }

  resetRing() {
      this.currentRadius = this.startRadius;
      this.ringTimer = 0;

      const bw = this.hammerHitArea.width * this.hammerHitArea.scaleX;
      const bh = this.hammerHitArea.height * this.hammerHitArea.scaleY;

      this.hitX = this.hammerHitArea.x + Phaser.Math.Between(-bw * 0.15, bw * 0.15);
      this.hitY = this.hammerHitArea.y + Phaser.Math.Between(-bh * 0.4, bh * 0.4);

      if (this.isPlaying) {
          this.targetRing.clear().fillStyle(0xfabf24, 0.1).fillCircle(this.hitX, this.hitY, this.targetRadius)
              .lineStyle(5, 0xfabf24, 0.4).strokeCircle(this.hitX, this.hitY, this.targetRadius);
      }
  }

  handleInput() {
    if (this.isFinished) return;

    // Precise Hit Test
    const pointer = this.input.activePointer;
    const isInsideMetal = this.isPointerInHitArea(pointer.worldX, pointer.worldY);

    if (!this.isPlaying) {
        if (this.isReadyToStart) { 
            this.isPlaying = true; 
            this.infoText.setVisible(false); 
            this.hammer.setAlpha(1);
            this.resetRing(); 
            this.cameras.main.flash(200); 
        } else { 
            this.cameras.main.shake(50, 0.005); 
            this.showFeedback("TOO COLD!", 0x3b82f6, 1.0); 
        }
        return;
    }

    if (this.time.now - this.lastHitTime < this.hitCooldown) return;
    this.lastHitTime = this.time.now;

    this.hammer.setPosition(this.hitX + 60, this.hitY - 40);
    this.tweens.add({ 
        targets: this.hammer, 
        x: this.hitX + 35, 
        y: this.hitY, 
        angle: -55, 
        duration: 50, 
        yoyo: true, 
        ease: 'Cubic.easeIn' 
    });

    if (this.currentTempStage === 'COLD' || this.currentTempStage === 'NORMAL') {
        this.cameras.main.shake(50, 0.005);
        this.showFeedback("TOO COLD!", 0x3b82f6, 1.0);
        return;
    }

    // Use Precise Hit Testing
    if (!isInsideMetal) {
        this.score = Math.max(0, this.score - 5); 
        this.combo = 0; 
        this.cameras.main.shake(100, 0.015); 
        this.showFeedback("OFF METAL!", 0xffffff, 1.2); 
        this.resetRing(); 
        return;
    }

    const diff = Math.abs(this.currentRadius - this.targetRadius);
    let efficiency = this.currentTempStage === 'AURA' ? 1.5 : (this.currentTempStage === 'HOT' ? 1.0 : 0.5);

    if (diff < 18) { 
        this.score += Math.ceil(15 * efficiency); 
        this.combo++; 
        this.createSparks(40, 0xffaa00, 2.0, 'spark_perfect'); 
        this.showFeedback('PERFECT!', 0xffb300, 1.5); 
        this.cameras.main.shake(200, 0.025); 
    } else if (diff < 55) { 
        this.score += Math.ceil(8 * efficiency); 
        this.combo = 0; 
        this.createSparks(20, 0xffffff, 1.3, 'spark_normal'); 
        this.showFeedback('GOOD', 0xe5e5e5, 1.0); 
        this.cameras.main.shake(80, 0.008); 
    } else { 
        this.score = Math.max(0, this.score - 5); 
        this.combo = 0; 
        this.showFeedback('MISS', 0xef4444, 1.2); 
        this.cameras.main.shake(120, 0.012); 
    }

    this.progressBar.width = Phaser.Math.Clamp(this.score / this.targetScore * 300, 0, 300);
    if (this.score >= this.targetScore) this.winGame();
    else this.resetRing();
  }

  createSparks(count: number, color: number, scale: number, key: string) {
    const emitter = this.add.particles(this.hitX, this.hitY, this.textures.exists(key) ? key : 'white', { lifespan: 800, speed: { min: 300 * scale, max: 700 * scale }, angle: { min: 230, max: 310 }, scale: { start: 0.7, end: 0 }, gravityY: 1200, blendMode: 'ADD', tint: color });
    emitter.explode(count);
  }

  showFeedback(text: string, color: number, scale: number) {
    const fb = this.add.text(this.hitX, this.hitY - 140, text, { fontFamily: 'Arial', fontSize: '36px', fontStyle: 'bold', color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setScale(0.5).setAlpha(0).setDepth(25);
    this.tweens.add({ targets: fb, y: this.hitY - 200, alpha: 1, scale: scale, duration: 250, hold: 400, yoyo: true, onComplete: () => fb.destroy() });
    if (this.combo > 1) {
      this.comboText.setText(`${this.combo} COMBO!`).setAlpha(1); 
      this.tweens.add({ targets: this.comboText, scale: { from: 1.5, to: 1 }, duration: 200, alpha: { from: 1, to: 0 }, delay: 500 });
    }
  }

  winGame() {
    this.isFinished = true; this.isPlaying = false;
    this.targetRing.clear(); this.approachRing.clear();
    this.hammer.setVisible(false);
    if (this.onStatusUpdate) this.onStatusUpdate(this.temperature);
    const bg = this.add.rectangle(this.centerX, this.centerY, this.scale.width, this.scale.height, 0x000000, 0.85).setAlpha(0).setDepth(100);
    this.tweens.add({ targets: bg, alpha: 1, duration: 500 });
    const txt = this.add.text(this.centerX, this.centerY, 'BLADE FORGED!', { fontFamily: 'Georgia', fontSize: '72px', color: '#fbbf24', stroke: '#000', strokeThickness: 3 }).setOrigin(0.5).setAlpha(0).setDepth(101);
    this.tweens.add({ targets: txt, alpha: 1, scale: { from: 0.5, to: 1.2 }, duration: 600, ease: 'Back.out', onComplete: () => { this.time.delayedCall(1000, () => { if (this.onComplete) this.onComplete(100); }); } });
  }
}

