      scale: {
        mode: Phaser.Scale.RESIZE,
        autoCenter: Phaser.Scale.CENTER_BOTH
      }
    };

    const game = new Phaser.Game(config);
    gameRef.current = game;
    game.scene.start('SmithingScene', { onComplete, difficulty, initialTemp, onStatusUpdate: (t: number) => actions.updateForgeStatus(t) });
    return () => { game.destroy(true); gameRef.current = null; };
  }, [onComplete, difficulty]);

  return (
    <div className="w-full h-full flex flex-col bg-stone-950 animate-in fade-in duration-300">
        <div className="w-full h-16 shrink-0 bg-stone-900 border-b border-stone-800 flex items-center justify-between px-6 z-10 shadow-md">
            <div className="flex items-center gap-3">
                <div className="bg-amber-900/30 p-2 rounded-full border border-amber-800"><Flame className="w-5 h-5 text-amber-500 animate-pulse" /></div>
                <div><h2 className="text-stone-200 font-bold tracking-wide leading-none uppercase text-sm">Forge View</h2><p className="text-[10px] text-stone-500 uppercase tracking-widest mt-1">Full-Width Anvil Perspective</p></div>
            </div>
            <button onClick={() => { if (gameRef.current) { const s = gameRef.current.scene.getScene('SmithingScene') as SmithingScene; if (s) actions.updateForgeStatus(s.getTemperature()); } onClose(); }} className="flex items-center gap-2 px-4 py-2 bg-stone-800 hover:bg-red-900/20 text-stone-400 hover:text-red-400 rounded border border-stone-700 transition-all">
                <X className="w-4 h-4" /><span className="text-sm font-bold">Cancel</span>
            </button>
        </div>
        <div className="flex-1 w-full relative bg-stone-950 flex items-center justify-center overflow-hidden">
            <div ref={containerRef} className="w-full h-full" />
            <div className="absolute bottom-6 right-6 z-20 flex flex-col items-center">
                <button onClick={() => { if (gameRef.current) { const s = gameRef.current.scene.getScene('SmithingScene') as SmithingScene; if (s) { actions.consumeItem(MATERIALS.CHARCOAL.id, 1); s.heatUp(); } } }} disabled={charcoalCount <= 0} className={`flex flex-col items-center justify-center w-24 h-24 rounded-full bg-stone-900 border-4 border-stone-700 hover:border-amber-500 transition-all disabled:opacity-50 group shadow-2xl ${charcoalCount > 0 ? 'animate-pulse' : ''}`}>
                    <Flame className="w-8 h-8 text-amber-500 mb-1" /><span className="text-[10px] font-bold text-stone-300 uppercase tracking-tighter">Heat Up</span><span className="text-xs text-stone-500 font-mono">x{charcoalCount}</span>
                </button>
            </div>
        </div>
        <div className="w-full py-3 bg-stone-900 border-t border-stone-800 flex justify-center items-center gap-2 text-stone-500 text-[10px] font-mono uppercase tracking-widest">
            <Hammer className="w-3 h-3" /><span>Target the glowing surface to shape the metal!</span>
        </div>
    </div>
  );
};

