import React, { useEffect, useRef } from 'react';
import Phaser from 'phaser';
import { X, Hammer, Flame } from 'lucide-react';
import { getAssetUrl } from '../../../utils';
import { useGame } from '../../../context/GameContext';
import { MATERIALS } from '../../../data/materials';

interface SmithingMinigameProps {
  onComplete: (score: number) => void;
  onClose: () => void;
  difficulty?: number;
}

class SmithingScene extends Phaser.Scene {
  add!: Phaser.GameObjects.GameObjectFactory;
  make!: Phaser.GameObjects.GameObjectCreator;
  scale!: Phaser.Scale.ScaleManager;
  tweens!: Phaser.Tweens.TweenManager;
  time!: Phaser.Time.Clock;
  cameras!: Phaser.Cameras.Scene2D.CameraManager;
  input!: Phaser.Input.InputPlugin;
  load!: Phaser.Loader.LoaderPlugin;
  textures!: Phaser.Textures.TextureManager;

  private anvilImage!: Phaser.GameObjects.Image;
  private anvilSurface!: Phaser.GameObjects.Graphics;
  private targetRing!: Phaser.GameObjects.Graphics;
  private approachRing!: Phaser.GameObjects.Graphics;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private comboText!: Phaser.GameObjects.Text;
  private infoText!: Phaser.GameObjects.Text;
  private ambientGlow!: Phaser.GameObjects.Arc;

  // ✅ Blade shell = Container( fallback Rect + stage Image )
  private bladeContainer!: Phaser.GameObjects.Container;
  private bladeFallbackRect!: Phaser.GameObjects.Rectangle;
  private bladeImage?: Phaser.GameObjects.Image;

  // ✅ Hit area (rotated rectangle) + precise polygon
  private hammerHitArea!: Phaser.GameObjects.Rectangle;
  private hitPoly!: Phaser.Geom.Polygon;

  private centerX: number = 0;
  private centerY: number = 0;
  private hitX: number = 0;
  private hitY: number = 0;

  private lastStage: number = -1;

  // Perspective Trapezoid Area
  private anvilConfig = {
    topWidthRatio: 0.65,
    botWidthRatio: 1.1,
    heightRatio: 0.4,
    yOffset: 60,
    leftHeightFactor: 0.9,
    imageOffsetX: 0,
    imageOffsetY: 40,
    // ✅ hitArea를 blade "아래"로 내릴 거리 (블레이드 방향 기준)
    hitAreaOffset: 80,
  };

  private startRadius: number = 220;
  private targetRadius: number = 55;
  private currentRadius: number = 220;
  private shrinkDuration: number = 2000;
  private ringTimer: number = 0;

  private score: number = 0;
  private targetScore: number = 100;
  private combo: number = 0;
  private lastHitTime: number = 0;
  private hitCooldown: number = 200;

  private onComplete?: (score: number) => void;
  private onStatusUpdate?: (temp: number) => void;
  private isFinished: boolean = false;
  private isPlaying: boolean = false;
  private isReadyToStart: boolean = false;

  private temperature: number = 0;
  private coolingRate: number = 2;
  private currentTempStage: 'COLD' | 'AURA' | 'HOT' | 'WARM' | 'NORMAL' = 'COLD';

  private tempBar!: Phaser.GameObjects.Rectangle;
  private tempValueText!: Phaser.GameObjects.Text;
  private bellowsContainer!: Phaser.GameObjects.Container;
  private isPumping: boolean = false;

  private uiContainer!: Phaser.GameObjects.Container;

  constructor() {
    super('SmithingScene');
  }

  init(data: { onComplete: (score: number) => void; difficulty: number; initialTemp: number; onStatusUpdate: (temp: number) => void }) {
    this.onComplete = data.onComplete;
    this.onStatusUpdate = data.onStatusUpdate;
    this.shrinkDuration = Math.max(800, 2000 - data.difficulty * 200);
    this.coolingRate = 2 + data.difficulty * 0.8;

    this.score = 0;
    this.combo = 0;
    this.lastStage = -1;

    this.temperature = data.initialTemp || 0;
    this.isFinished = false;
    this.isPlaying = false;
    this.isReadyToStart = this.temperature > 0;
  }

  preload() {
    this.load.crossOrigin = 'anonymous';
    this.load.image('anvil_img', getAssetUrl('anvil.png'));
    this.load.image('spark_perfect', getAssetUrl('particle_spark1.png'));
    this.load.image('spark_normal', getAssetUrl('particle_spark2.png'));

    // ✅ stage 0~5 (총 6장)
    this.load.image('blade_stage_0', getAssetUrl('billet_default.png'));
    this.load.image('blade_stage_1', getAssetUrl('billet_blade_01.png'));
    this.load.image('blade_stage_2', getAssetUrl('billet_blade_02.png'));
    this.load.image('blade_stage_3', getAssetUrl('billet_blade_03.png'));
    this.load.image('blade_stage_4', getAssetUrl('billet_blade_04.png'));
    this.load.image('blade_stage_5', getAssetUrl('billet_blade_05.png'));
  }

  create() {
    this.setupResponsiveLayout();

    this.anvilImage = this.add.image(0, 0, 'anvil_img').setDepth(1).setOrigin(0.5, 0.5);
    this.anvilSurface = this.add.graphics().setDepth(2);

    // ✅ Blade shell container
    this.bladeContainer = this.add.container(0, 0).setDepth(3);

    this.bladeContainer.setScale(1.0);
    this.bladeContainer.setAngle(-12);

    // fallback rect (항상 존재, 이미지 없어도 보이게)
    this.bladeFallbackRect = this.add.rectangle(0, 0, 200, 600, 0x57534e).setOrigin(0.5, 0.5);
    this.bladeContainer.add(this.bladeFallbackRect);

    // stage image (있으면 위에 올림)
    if (this.textures.exists('blade_stage_0')) {
      this.bladeImage = this.add.image(0, 0, 'blade_stage_0').setOrigin(0.5);
      this.bladeContainer.add(this.bladeImage);
    }

    // ✅ hit area (판정용) - blade 아래로 배치할 거라 pos는 handleResize에서
    this.hammerHitArea = this.add.rectangle(0, 0, 200, 400, 0x00ff00).setDepth(3).setAlpha(0);
    this.hammerHitArea.setAngle(-12);

    this.targetRing = this.add.graphics().setDepth(5);
    this.approachRing = this.add.graphics().setDepth(5);

    this.uiContainer = this.add.container(0, 0).setDepth(20);
    this.setupUI();

    this.ambientGlow = this.add.circle(0, 0, 500, 0xea580c, 0).setFillStyle(0xea580c, 0.25).setDepth(0);

    this.handleResize();

    // Inputs
    this.input.keyboard?.on('keydown-SPACE', () => this.handleInput(), this);

    this.input.on(
      'pointerdown',
      (pointer: Phaser.Input.Pointer, objs: any[]) => {
        const isBellows = objs.includes(this.bellowsContainer) || this.bellowsContainer.list.some((c) => objs.includes(c));
        if (isBellows) {
          this.pumpBellows();
          return;
        }

        if (!this.isPlaying) {
          this.handleInput(pointer);
          return;
        }

        const px = pointer.worldX;
        const py = pointer.worldY;

        // 1) 금속 위가 아니면 OFF METAL
        if (!this.isPointerInHitArea(px, py)) {
          this.handleOffMetalMiss();
          return;
        }

        // 2) outer ring 밖이면 MISS
        const dist = Phaser.Math.Distance.Between(px, py, this.hitX, this.hitY);
        const ringThickness = 8;
        const allowRadius = this.currentRadius + ringThickness * 0.5;

        if (dist > allowRadius) {
          this.handleSpatialMiss();
          return;
        }

        this.handleInput(pointer);
      },
      this
    );

    this.scale.on('resize', this.handleResize, this);
  }

  private handleOffMetalMiss() {
    this.score = Math.max(0, this.score - 5);
    this.combo = 0;
    this.cameras.main.shake(100, 0.015);
    this.showFeedback('OFF METAL!', 0xffffff, 1.2);
    this.updateProgressBar();
    this.resetRing();
  }

  private handleSpatialMiss() {
    this.score = Math.max(0, this.score - 5);
    this.combo = 0;
    this.cameras.main.shake(120, 0.012);
    this.showFeedback('MISS', 0xef4444, 1.2);
    this.updateProgressBar();
    this.resetRing();
  }

  setupResponsiveLayout() {
    this.centerX = this.scale.width / 2;
    this.centerY = this.scale.height / 2;
  }

  private positionBladeWithOffset(bladeBaseY: number) {
    // 기본 위치
    this.bladeContainer.setPosition(this.centerX, bladeBaseY);

    // 방향 오프셋(-12도 방향)
    const rad = Phaser.Math.DegToRad(this.bladeContainer.angle);
    const offset = 40;
    this.bladeContainer.x += Math.cos(rad) * offset;
    this.bladeContainer.y += Math.sin(rad) * offset;
  }

  handleResize() {
    this.centerX = this.scale.width / 2;
    this.centerY = this.scale.height / 2;

    this.drawAnvilSurface();

    const surfaceH = this.scale.height * this.anvilConfig.heightRatio;
    const b = this.centerY + surfaceH / 2 + this.anvilConfig.yOffset;
    const bladeY = b - surfaceH * 0.45;

    // ✅ 블레이드 위치 설정 (오프셋 포함)
    this.positionBladeWithOffset(bladeY);

    // ✅ hitArea를 이동된 blade 아래로(블레이드 방향 기준)
    const rad = Phaser.Math.DegToRad(this.bladeContainer.angle);
    const ox = -Math.sin(rad) * this.anvilConfig.hitAreaOffset;
    const oy = Math.cos(rad) * this.anvilConfig.hitAreaOffset;

    this.hammerHitArea.setPosition(this.bladeContainer.x + ox, this.bladeContainer.y + oy);
    this.hammerHitArea.setAngle(this.bladeContainer.angle);

    this.rebuildHitPoly();

    this.uiContainer.setPosition(0, 0);
    this.repositionUIElements();
    this.cameras.main.setBackgroundColor('#1c1917');

    if (this.ambientGlow) {
      this.ambientGlow.setPosition(this.centerX, this.scale.height);
      this.ambientGlow.setRadius(this.scale.width * 0.6);
    }

    if (!this.isPlaying) {
      this.infoText?.setPosition(this.centerX, this.centerY - 220);
    }
  }

  private rebuildHitPoly() {
    const w = this.hammerHitArea.width * this.hammerHitArea.scaleX;
    const h = this.hammerHitArea.height * this.hammerHitArea.scaleY;
    const cx = this.hammerHitArea.x;
    const cy = this.hammerHitArea.y;

    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    const cos = Math.cos(rad);
    const sin = Math.sin(rad);

    const corners = [
      { x: -w / 2, y: -h / 2 },
      { x: w / 2, y: -h / 2 },
      { x: w / 2, y: h / 2 },
      { x: -w / 2, y: h / 2 },
    ].map((p) => ({
      x: cx + p.x * cos - p.y * sin,
      y: cy + p.x * sin + p.y * cos,
    }));

    this.hitPoly = new Phaser.Geom.Polygon(corners);
  }

  private isPointerInHitArea(px: number, py: number) {
    return this.hitPoly && Phaser.Geom.Polygon.Contains(this.hitPoly, px, py);
  }

  drawAnvilSurface() {
    this.anvilSurface.clear();

    const w = this.scale.width;
    const h = this.scale.height;
    const { topWidthRatio, botWidthRatio, heightRatio, yOffset, leftHeightFactor } = this.anvilConfig;

    const topW = w * topWidthRatio;
    const botW = w * botWidthRatio;
    const surfaceH = h * heightRatio;

    const b = this.centerY + surfaceH / 2 + yOffset;
    const tL = b - surfaceH * leftHeightFactor;
    const tR = b - surfaceH;

    const points = [
      { x: this.centerX - topW / 2, y: tL },
      { x: this.centerX + topW / 2, y: tR },
      { x: this.centerX + botW / 2, y: b },
      { x: this.centerX - botW / 2, y: b },
    ];

    const { imageOffsetX, imageOffsetY } = this.anvilConfig;
    if (this.anvilImage) {
      const targetWidth = w * 1.3;
      const scale = targetWidth / this.anvilImage.width;
      this.anvilImage.setScale(scale);
      this.anvilImage.setPosition(this.centerX + imageOffsetX, b + imageOffsetY);
    }

    this.anvilSurface.fillStyle(0x27272a, 0.4);
    this.anvilSurface.fillPoints(points, true);
    this.anvilSurface.lineStyle(6, 0x3f3f46, 0.8);
    this.anvilSurface.strokePoints(points, true);

    this.anvilSurface.fillStyle(0x3f3f46, 0.2);
    this.anvilSurface.fillEllipse(this.centerX, (tL + tR + b + b) / 4, botW * 0.6, surfaceH * 0.65);
  }

  setupUI() {
    this.progressBar = this.add.rectangle(0, 40, 0, 12, 0xeab308).setOrigin(0, 0.5);
    this.uiContainer.add([
      this.add.rectangle(0, 40, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e).setName('progBg'),
      this.progressBar,
    ]);

    this.tempBar = this.add.rectangle(0, 0, 18, 250, 0x3b82f6).setOrigin(0.5, 1).setScale(1, 0);
    this.tempValueText = this.add
      .text(0, 0, '20°C', { fontFamily: 'monospace', fontSize: '16px', color: '#fff', fontStyle: 'bold' })
      .setOrigin(0.5);

    this.uiContainer.add([
      this.add.rectangle(0, 0, 32, 260, 0x1c1917).setStrokeStyle(3, 0x57534e).setName('tempFrame'),
      this.add.rectangle(0, 0, 24, 250, 0x0c0a09).setName('tempBg'),
      this.tempBar,
      this.tempValueText,
    ]);

    this.createBellows();

    this.comboText = this.add
      .text(0, 0, '', { fontFamily: 'Impact', fontSize: '48px', color: '#fcd34d', stroke: '#000', strokeThickness: 5 })
      .setOrigin(0.5)
      .setAlpha(0);

    this.infoText = this.add
      .text(0, 0, this.isReadyToStart ? 'CLICK TO START' : 'FORGE IS COLD\nADD FUEL TO HEAT', {
        fontFamily: 'monospace',
        fontSize: '28px',
        color: this.isReadyToStart ? '#fbbf24' : '#3b82f6',
        align: 'center',
        stroke: '#000',
        strokeThickness: 5,
      })
      .setOrigin(0.5);

    this.uiContainer.add([this.comboText, this.infoText]);
    this.tweens.add({ targets: this.infoText, alpha: 0.5, yoyo: true, repeat: -1, duration: 800 });
  }

  repositionUIElements() {
    const progBg = this.uiContainer.getByName('progBg') as Phaser.GameObjects.Rectangle;
    progBg.setPosition(this.centerX, 40);
    this.progressBar.setPosition(this.centerX - 150, 40);

    const tX = this.scale.width - 60;
    const tY = this.centerY - 50;
    (this.uiContainer.getByName('tempFrame') as any).setPosition(tX, tY);
    (this.uiContainer.getByName('tempBg') as any).setPosition(tX, tY);
    this.tempBar.setPosition(tX, tY + 125);
    this.tempValueText.setPosition(tX, tY - 160);

    this.bellowsContainer.setPosition(tX, tY + 220);

    this.infoText.setPosition(this.centerX, this.centerY - 220);
    this.comboText.setPosition(this.centerX, this.centerY - 300);
  }

  createBellows() {
    this.bellowsContainer = this.add.container(0, 0);
    const bag = this.add.rectangle(0, 0, 70, 50, 0xa16207).setStrokeStyle(2, 0x451a03);
    const top = this.add.rectangle(0, -25, 75, 14, 0x78350f).setStrokeStyle(2, 0x451a03);
    const bot = this.add.rectangle(0, 25, 75, 14, 0x78350f).setStrokeStyle(2, 0x451a03);
    const txt = this.add.text(0, 55, 'PUMP', { fontSize: '14px', color: '#a8a29e', fontFamily: 'monospace', fontStyle: 'bold' }).setOrigin(0.5);

    this.bellowsContainer.add([bag, top, bot, txt]);
    this.bellowsContainer.setInteractive(new Phaser.Geom.Rectangle(-40, -40, 80, 120), Phaser.Geom.Rectangle.Contains);
    this.uiContainer.add(this.bellowsContainer);
  }

  pumpBellows() {
    if (this.isPumping) return;
    this.isPumping = true;
    this.tweens.add({ targets: this.bellowsContainer, scaleY: 0.7, duration: 80, yoyo: true, onComplete: () => (this.isPumping = false) });

    if (this.temperature > 0) {
      this.temperature = Math.min(100, this.temperature + 8);
      if (!this.isPlaying && !this.isReadyToStart) {
        this.isReadyToStart = true;
        this.infoText.setText('CLICK TO START').setColor('#fbbf24');
      }
    }
  }

  public heatUp() {
    this.temperature = Math.min(100, this.temperature + 40);
    if (!this.isPlaying) {
      this.isReadyToStart = true;
      this.infoText.setText('CLICK TO START').setColor('#fbbf24');
    }
  }

  public getTemperature() {
    return this.temperature;
  }

  update(time: number, delta: number) {
    if (this.isFinished) return;

    if (this.isPlaying) this.handleRingLogic(delta);

    this.temperature = Math.max(0, this.temperature - this.coolingRate * (delta / 1000));
    this.refreshVisuals();

    if (!this.isPlaying && this.isReadyToStart && this.temperature <= 0) {
      this.isReadyToStart = false;
      this.infoText.setText('FORGE IS COLD\nADD FUEL TO HEAT').setColor('#3b82f6');
    }
  }

  private setBladeStage(stage: number) {
    const key = `blade_stage_${stage}`;

    // 이미지가 있으면 위에 표시
    if (this.textures.exists(key)) {
      if (!this.bladeImage) {
        this.bladeImage = this.add.image(0, 0, key).setOrigin(0.5);
        this.bladeContainer.add(this.bladeImage);
      } else {
        this.bladeImage.setTexture(key);
      }
      this.bladeImage.setVisible(true);

      // ✅ Rect는 “사라지지 않게” 밑에 항상 두되, 너무 튀면 알파만 낮춤
      this.bladeFallbackRect.setVisible(true);
      this.bladeFallbackRect.setAlpha(0.15);
    } else {
      // 이미지 없으면 fallback만
      if (this.bladeImage) this.bladeImage.setVisible(false);
      this.bladeFallbackRect.setVisible(true);
      this.bladeFallbackRect.setAlpha(1);
    }
  }

  refreshVisuals() {
    const ratio = this.temperature / 100;
    this.tempBar.scaleY = ratio;
    this.tempValueText.setText(`${Math.floor(20 + ratio * 1480)}°C`);

    // 온도에 따른 색상(가열 느낌)
    const coldColor = new Phaser.Display.Color(63, 63, 70);
    const hotColor = new Phaser.Display.Color(253, 230, 138);
    const currentTint = Phaser.Display.Color.Interpolate.ColorWithColor(coldColor, hotColor, 100, ratio * 100);
    const colorVal = Phaser.Display.Color.GetColor(currentTint.r, currentTint.g, currentTint.b);

    // ✅ fallback rect는 fillStyle
    this.bladeFallbackRect.setFillStyle(colorVal, 1);

    // ✅ stage image는 tint (Image에는 setFillStyle 없음!)
    if (this.bladeImage) this.bladeImage.setTint(colorVal);

    // ✅ score 기반 stage 갱신 (0~5)
    const progress = Phaser.Math.Clamp(this.score / this.targetScore, 0, 1);
    const stageCount = 6; // 0..5
    const stage = Math.min(stageCount - 1, Math.floor(progress * stageCount));

    if (stage !== this.lastStage) {
      this.setBladeStage(stage);
      this.lastStage = stage;
    }

    if (this.ambientGlow) this.ambientGlow.setFillStyle(0xea580c, ratio * 0.25);

    if (this.temperature <= 0) this.currentTempStage = 'COLD';
    else if (this.temperature > 75) this.currentTempStage = 'AURA';
    else if (this.temperature > 40) this.currentTempStage = 'HOT';
    else if (this.temperature > 15) this.currentTempStage = 'WARM';
    else this.currentTempStage = 'NORMAL';
  }

  handleRingLogic(delta: number) {
    this.ringTimer += delta;
    const t = Math.min(this.ringTimer / this.shrinkDuration, 1.5);
    this.currentRadius = this.startRadius * (1 - t * t);

    const ringColor = this.currentRadius < this.targetRadius ? 0xffffff : 0xfabf24;
    this.approachRing.clear().lineStyle(8, ringColor, 0.6).strokeCircle(this.hitX, this.hitY, Math.max(0, this.currentRadius));

    if (this.currentRadius < this.targetRadius - 30) {
      this.combo = 0;
      this.resetRing();
    }
  }

  resetRing() {
    if (this.temperature <= 0) {
      this.isPlaying = false;
      this.isReadyToStart = false;
      this.targetRing.clear();
      this.approachRing.clear();
      this.infoText.setVisible(true).setText('FORGE IS COLD\nADD FUEL TO HEAT').setColor('#3b82f6');
      this.showFeedback('FORGE COLD!', 0x3b82f6, 1.0);
      return;
    }

    this.currentRadius = this.startRadius;
    this.ringTimer = 0;

    const w = this.hammerHitArea.width * this.hammerHitArea.scaleX;
    const h = this.hammerHitArea.height * this.hammerHitArea.scaleY;

    const u = Phaser.Math.Between(-w * 0.15, w * 0.15);
    const v = Phaser.Math.Between(-h * 0.4, h * 0.4);

    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    const cos = Math.cos(rad);
    const sin = Math.sin(rad);

    this.hitX = this.hammerHitArea.x + (u * cos - v * sin);
    this.hitY = this.hammerHitArea.y + (u * sin + v * cos);

    if (this.isPlaying) {
      this.targetRing
        .clear()
        .fillStyle(0xfabf24, 0.1)
        .fillCircle(this.hitX, this.hitY, this.targetRadius)
        .lineStyle(5, 0xfabf24, 0.4)
        .strokeCircle(this.hitX, this.hitY, this.targetRadius);
    }
  }

  private pulseHitArea(mult: number) {
    // hit 시 잠깐 커졌다 복귀 + poly 갱신
    this.tweens.add({
      targets: this.hammerHitArea,
      scaleX: mult,
      scaleY: mult,
      duration: 70,
      yoyo: true,
      onUpdate: () => this.rebuildHitPoly(),
      onComplete: () => this.rebuildHitPoly(),
    });
  }

  handleInput(pointer?: Phaser.Input.Pointer) {
    if (this.isFinished) return;

    if (!this.isPlaying) {
      if (this.isReadyToStart) {
        this.isPlaying = true;
        this.infoText.setVisible(false);
        this.resetRing();
        this.cameras.main.flash(200);
      } else {
        this.cameras.main.shake(50, 0.005);
        this.showFeedback('TOO COLD!', 0x3b82f6, 1.0);
      }
      return;
    }

    if (this.time.now - this.lastHitTime < this.hitCooldown) return;
    this.lastHitTime = this.time.now;

    const swingX = pointer ? pointer.worldX : this.hitX;
    const swingY = pointer ? pointer.worldY : this.hitY;

    if (this.currentTempStage === 'COLD' || this.currentTempStage === 'NORMAL') {
      this.cameras.main.shake(50, 0.005);
      this.showFeedback('TOO COLD!', 0x3b82f6, 1.0);
      return;
    }

    const diff = Math.abs(this.currentRadius - this.targetRadius);
    const efficiency = this.currentTempStage === 'AURA' ? 1.5 : this.currentTempStage === 'HOT' ? 1.0 : 0.5;

    if (diff < 18) {
      this.score += Math.ceil(15 * efficiency);
      this.combo++;
      this.pulseHitArea(1.12);
      this.createSparks(40, 0xffaa00, 2.0, 'spark_perfect', swingX, swingY);
      this.showFeedback('PERFECT!', 0xffb300, 1.5, swingX, swingY);
      this.cameras.main.shake(200, 0.025);
    } else if (diff < 55) {
      this.score += Math.ceil(8 * efficiency);
      this.combo = 0;
      this.pulseHitArea(1.06);
      this.createSparks(20, 0xffffff, 1.3, 'spark_normal', swingX, swingY);
      this.showFeedback('GOOD', 0xe5e5e5, 1.0, swingX, swingY);
      this.cameras.main.shake(80, 0.008);
    } else {
      this.score = Math.max(0, this.score - 5);
      this.combo = 0;
      this.pulseHitArea(0.95);
      this.showFeedback('MISS', 0xef4444, 1.2, swingX, swingY);
      this.cameras.main.shake(120, 0.012);
    }

    this.updateProgressBar();
    if (this.score >= this.targetScore) this.winGame();
    else this.resetRing();
  }

  private updateProgressBar() {
    this.progressBar.width = Phaser.Math.Clamp((this.score / this.targetScore) * 300, 0, 300);
  }

  createSparks(count: number, color: number, scale: number, key: string, x: number, y: number) {
    const emitter = this.add.particles(x, y, this.textures.exists(key) ? key : 'white', {
      lifespan: 800,
      speed: { min: 300 * scale, max: 700 * scale },
      angle: { min: 230, max: 310 },
      scale: { start: 0.7, end: 0 },
      gravityY: 1200,
      blendMode: 'ADD',
      tint: color,
    });
    emitter.explode(count);
  }

  showFeedback(text: string, color: number, scale: number, x?: number, y?: number) {
    const fx = x ?? this.hitX;
    const fy = y ?? this.hitY;
    const fb = this.add
      .text(fx, fy - 140, text, {
        fontFamily: 'Arial',
        fontSize: '36px',
        fontStyle: 'bold',
        color: '#' + color.toString(16).padStart(6, '0'),
        stroke: '#000',
        strokeThickness: 5,
      })
      .setOrigin(0.5)
      .setScale(0.5)
      .setAlpha(0)
      .setDepth(25);

    this.tweens.add({ targets: fb, y: fy - 200, alpha: 1, scale: scale, duration: 250, hold: 400, yoyo: true, onComplete: () => fb.destroy() });

    if (this.combo > 1) {
      this.comboText.setText(`${this.combo} COMBO!`).setAlpha(1);
      this.tweens.add({ targets: this.comboText, scale: { from: 1.5, to: 1 }, duration: 200, alpha: { from: 1, to: 0 }, delay: 500 });
    }
  }

  winGame() {
    this.isFinished = true;
    this.isPlaying = false;
    this.targetRing.clear();
    this.approachRing.clear();

    if (this.onStatusUpdate) this.onStatusUpdate(this.temperature);

    const bg = this.add.rectangle(this.centerX, this.centerY, this.scale.width, this.scale.height, 0x000000, 0.85).setAlpha(0).setDepth(100);
    this.tweens.add({ targets: bg, alpha: 1, duration: 500 });

    const txt = this.add
      .text(this.centerX, this.centerY, 'BLADE FORGED!', { fontFamily: 'Georgia', fontSize: '72px', color: '#fbbf24', stroke: '#000', strokeThickness: 3 })
      .setOrigin(0.5)
      .setAlpha(0)
      .setDepth(101);

    this.tweens.add({
      targets: txt,
      alpha: 1,
      scale: { from: 0.5, to: 1.2 },
      duration: 600,
      ease: 'Back.out',
      onComplete: () => {
        this.time.delayedCall(1000, () => {
          if (this.onComplete) this.onComplete(100);
        });
      },
    });
  }
}

const SmithingMinigame: React.FC<SmithingMinigameProps> = ({ onComplete, onClose, difficulty = 1 }) => {
  const { state, actions } = useGame();
  const gameRef = useRef<Phaser.Game | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const charcoalCount = state.inventory.find((i) => i.id === MATERIALS.CHARCOAL.id)?.quantity || 0;

  useEffect(() => {
    if (!containerRef.current) return;
    const timeDiffSec = (Date.now() - (state.lastForgeTime || 0)) / 1000;
    const initialTemp = Math.max(0, (state.forgeTemperature || 0) - timeDiffSec * 5);

    const config: Phaser.Types.Core.GameConfig = {
      type: Phaser.AUTO,
      parent: containerRef.current,
      width: '100%',
      height: '100%',
      backgroundColor: '#0c0a09',
      scene: [SmithingScene],
      scale: {
        mode: Phaser.Scale.RESIZE,
        autoCenter: Phaser.Scale.CENTER_BOTH,
      },
    };

    const game = new Phaser.Game(config);
    gameRef.current = game;
    game.scene.start('SmithingScene', {
      onComplete,
      difficulty,
      initialTemp,
      onStatusUpdate: (t: number) => actions.updateForgeStatus(t),
    });

    return () => {
      game.destroy(true);
      gameRef.current = null;
    };
  }, [onComplete, difficulty]);

  return (
    <div className="w-full h-full flex flex-col bg-stone-950 animate-in fade-in duration-300">
      <div className="w-full h-16 shrink-0 bg-stone-900 border-b border-stone-800 flex items-center justify-between px-6 z-10 shadow-md">
        <div className="flex items-center gap-3">
          <div className="bg-amber-900/30 p-2 rounded-full border border-amber-800">
            <Flame className="w-5 h-5 text-amber-500 animate-pulse" />
          </div>
          <div>
            <h2 className="text-stone-200 font-bold tracking-wide leading-none uppercase text-sm">Forge View</h2>
            <p className="text-[10px] text-stone-500 uppercase tracking-widest mt-1">Full-Width Anvil Perspective</p>
          </div>
        </div>
        <button
          onClick={() => {
            if (gameRef.current) {
              const s = gameRef.current.scene.getScene('SmithingScene') as SmithingScene;
              if (s) actions.updateForgeStatus(s.getTemperature());
            }
            onClose();
          }}
          className="flex items-center gap-2 px-4 py-2 bg-stone-800 hover:bg-red-900/20 text-stone-400 hover:text-red-400 rounded border border-stone-700 transition-all"
        >
          <X className="w-4 h-4" />
          <span className="text-sm font-bold">Cancel</span>
        </button>
      </div>

      <div className="flex-1 w-full relative bg-stone-950 flex items-center justify-center overflow-hidden">
        <div ref={containerRef} className="w-full h-full" />
        <div className="absolute bottom-6 right-6 z-20 flex flex-col items-center">
          <button
            onClick={() => {
              if (gameRef.current) {
                const s = gameRef.current.scene.getScene('SmithingScene') as SmithingScene;
                if (s) {
                  actions.consumeItem(MATERIALS.CHARCOAL.id, 1);
                  s.heatUp();
                }
              }
            }}
            disabled={charcoalCount <= 0}
            className={`flex flex-col items-center justify-center w-24 h-24 rounded-full bg-stone-900 border-4 border-stone-700 hover:border-amber-500 transition-all disabled:opacity-50 group shadow-2xl ${
              charcoalCount > 0 ? 'animate-pulse' : ''
            }`}
          >
            <Flame className="w-8 h-8 text-amber-500 mb-1" />
            <span className="text-[10px] font-bold text-stone-300 uppercase tracking-tighter">Heat Up</span>
            <span className="text-xs text-stone-500 font-mono">x{charcoalCount}</span>
          </button>
        </div>
      </div>

      <div className="w-full py-3 bg-stone-900 border-t border-stone-800 flex justify-center items-center gap-2 text-stone-500 text-[10px] font-mono uppercase tracking-widest">
        <Hammer className="w-3 h-3" />
        <span>Target the glowing surface to shape the metal!</span>
      </div>
    </div>
  );
};

export default SmithingMinigame;

import React, { useEffect, useRef } from 'react';
import Phaser from 'phaser';
import { X, Hammer, Flame } from 'lucide-react';
import { getAssetUrl } from '../../../utils';
import { useGame } from '../../../context/GameContext';
import { MATERIALS } from '../../../data/materials';

interface SmithingMinigameProps {
  onComplete: (score: number) => void;
  onClose: () => void;
  difficulty?: number;
}

class SmithingScene extends Phaser.Scene {
  add!: Phaser.GameObjects.GameObjectFactory;
  make!: Phaser.GameObjects.GameObjectCreator;
  scale!: Phaser.Scale.ScaleManager;
  tweens!: Phaser.Tweens.TweenManager;
  time!: Phaser.Time.Clock;
  cameras!: Phaser.Cameras.Scene2D.CameraManager;
  input!: Phaser.Input.InputPlugin;
  load!: Phaser.Loader.LoaderPlugin;
  textures!: Phaser.Textures.TextureManager;

  private anvilImage!: Phaser.GameObjects.Image;
  private anvilSurface!: Phaser.GameObjects.Graphics;
  private targetRing!: Phaser.GameObjects.Graphics;
  private approachRing!: Phaser.GameObjects.Graphics;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private comboText!: Phaser.GameObjects.Text;
  private infoText!: Phaser.GameObjects.Text;
  private ambientGlow!: Phaser.GameObjects.Arc;

  // ✅ Blade shell = Container( fallback Rect + stage Image )
  private bladeContainer!: Phaser.GameObjects.Container;
  private bladeFallbackRect!: Phaser.GameObjects.Rectangle;
  private bladeImage?: Phaser.GameObjects.Image;

  // ✅ Hit area (rotated rectangle) + precise polygon
  private hammerHitArea!: Phaser.GameObjects.Rectangle;
  private hitPoly!: Phaser.Geom.Polygon;

  private centerX: number = 0;
  private centerY: number = 0;
  private hitX: number = 0;
  private hitY: number = 0;

  private lastStage: number = -1;

  // Perspective Trapezoid Area
  private anvilConfig = {
    topWidthRatio: 0.65,
    botWidthRatio: 1.1,
    heightRatio: 0.4,
    yOffset: 60,
    leftHeightFactor: 0.9,
    imageOffsetX: 0,
    imageOffsetY: 40,
    // ✅ hitArea를 blade 중심으로부터 수직 하단으로 내릴 거리
    hitAreaOffset: 40,
  };

  private startRadius: number = 220;
  private targetRadius: number = 55;
  private currentRadius: number = 220;
  private shrinkDuration: number = 2000;
  private ringTimer: number = 0;

  private score: number = 0;
  private targetScore: number = 100;
  private combo: number = 0;
  private lastHitTime: number = 0;
  private hitCooldown: number = 200;

  private onComplete?: (score: number) => void;
  private onStatusUpdate?: (temp: number) => void;
  private isFinished: boolean = false;
  private isPlaying: boolean = false;
  private isReadyToStart: boolean = false;

  private temperature: number = 0;
  private coolingRate: number = 2;
  private currentTempStage: 'COLD' | 'AURA' | 'HOT' | 'WARM' | 'NORMAL' = 'COLD';

  private tempBar!: Phaser.GameObjects.Rectangle;
  private tempValueText!: Phaser.GameObjects.Text;
  private bellowsContainer!: Phaser.GameObjects.Container;
  private isPumping: boolean = false;

  private uiContainer!: Phaser.GameObjects.Container;

  constructor() {
    super('SmithingScene');
  }

  init(data: { onComplete: (score: number) => void; difficulty: number; initialTemp: number; onStatusUpdate: (temp: number) => void }) {
    this.onComplete = data.onComplete;
    this.onStatusUpdate = data.onStatusUpdate;
    this.shrinkDuration = Math.max(800, 2000 - data.difficulty * 200);
    this.coolingRate = 2 + data.difficulty * 0.8;

    this.score = 0;
    this.combo = 0;
    this.lastStage = -1;

    this.temperature = data.initialTemp || 0;
    this.isFinished = false;
    this.isPlaying = false;
    this.isReadyToStart = this.temperature > 0;
  }

  preload() {
    this.load.crossOrigin = 'anonymous';
    this.load.image('anvil_img', getAssetUrl('anvil.png'));
    this.load.image('spark_perfect', getAssetUrl('particle_spark1.png'));
    this.load.image('spark_normal', getAssetUrl('particle_spark2.png'));

    // ✅ stage 0~5 (총 6장)
    this.load.image('blade_stage_0', getAssetUrl('billet_default.png'));
    this.load.image('blade_stage_1', getAssetUrl('billet_blade_01.png'));
    this.load.image('blade_stage_2', getAssetUrl('billet_blade_02.png'));
    this.load.image('blade_stage_3', getAssetUrl('billet_blade_03.png'));
    this.load.image('blade_stage_4', getAssetUrl('billet_blade_04.png'));
    this.load.image('blade_stage_5', getAssetUrl('billet_blade_05.png'));
  }

  create() {
    this.setupResponsiveLayout();

    this.anvilImage = this.add.image(0, 0, 'anvil_img').setDepth(1).setOrigin(0.5, 0.5);
    this.anvilSurface = this.add.graphics().setDepth(2);

    // ✅ Blade shell container
    this.bladeContainer = this.add.container(0, 0).setDepth(3);
    this.bladeContainer.setAngle(-12);

    // ✅ 가로로 긴 형태로 변경 (600x120)
    this.bladeFallbackRect = this.add.rectangle(0, 0, 600, 120, 0x57534e).setOrigin(0.5, 0.5);
    this.bladeContainer.add(this.bladeFallbackRect);

    // stage image (있으면 위에 올림)
    if (this.textures.exists('blade_stage_0')) {
      this.bladeImage = this.add.image(0, 0, 'blade_stage_0').setOrigin(0.5);
      this.bladeContainer.add(this.bladeImage);
    }

    // ✅ hit area (가로로 긴 판정, 500x120)
    this.hammerHitArea = this.add.rectangle(0, 0, 500, 120, 0x00ff00).setDepth(3).setAlpha(0);
    this.hammerHitArea.setAngle(-12); // 블레이드 각도와 일치

    this.targetRing = this.add.graphics().setDepth(5);
    this.approachRing = this.add.graphics().setDepth(5);

    this.uiContainer = this.add.container(0, 0).setDepth(20);
    this.setupUI();

    this.ambientGlow = this.add.circle(0, 0, 500, 0xea580c, 0).setFillStyle(0xea580c, 0.25).setDepth(0);

    this.handleResize();

    // Inputs
    this.input.keyboard?.on('keydown-SPACE', () => this.handleInput(), this);

    this.input.on(
      'pointerdown',
      (pointer: Phaser.Input.Pointer, objs: any[]) => {
        const isBellows = objs.includes(this.bellowsContainer) || this.bellowsContainer.list.some((c) => objs.includes(c));
        if (isBellows) {
          this.pumpBellows();
          return;
        }

        if (!this.isPlaying) {
          this.handleInput(pointer);
          return;
        }

        const px = pointer.worldX;
        const py = pointer.worldY;

        if (!this.isPointerInHitArea(px, py)) {
          this.handleOffMetalMiss();
          return;
        }

        const dist = Phaser.Math.Distance.Between(px, py, this.hitX, this.hitY);
        const ringThickness = 8;
        const allowRadius = this.currentRadius + ringThickness * 0.5;

        if (dist > allowRadius) {
          this.handleSpatialMiss();
          return;
        }

        this.handleInput(pointer);
      },
      this
    );

    this.scale.on('resize', this.handleResize, this);
  }

  private handleOffMetalMiss() {
    this.score = Math.max(0, this.score - 5);
    this.combo = 0;
    this.cameras.main.shake(100, 0.015);
    this.showFeedback('OFF METAL!', 0xffffff, 1.2);
    this.updateProgressBar();
    this.resetRing();
  }

  private handleSpatialMiss() {
    this.score = Math.max(0, this.score - 5);
    this.combo = 0;
    this.cameras.main.shake(120, 0.012);
    this.showFeedback('MISS', 0xef4444, 1.2);
    this.updateProgressBar();
    this.resetRing();
  }

  setupResponsiveLayout() {
    this.centerX = this.scale.width / 2;
    this.centerY = this.scale.height / 2;
  }

  private positionBladeWithOffset(bladeBaseY: number) {
    // 기본 위치
    this.bladeContainer.setPosition(this.centerX, bladeBaseY);

    // 방향 오프셋(-12도 방향으로 미세 조정)
    const rad = Phaser.Math.DegToRad(this.bladeContainer.angle);
    const offset = 40;
    this.bladeContainer.x += Math.cos(rad) * offset;
    this.bladeContainer.y += Math.sin(rad) * offset;
  }

  handleResize() {
    this.centerX = this.scale.width / 2;
    this.centerY = this.scale.height / 2;

    this.drawAnvilSurface();

    const surfaceH = this.scale.height * this.anvilConfig.heightRatio;
    const b = this.centerY + surfaceH / 2 + this.anvilConfig.yOffset;
    const bladeY = b - surfaceH * 0.45;

    // ✅ 블레이드 위치 설정 (오프셋 포함)
    this.positionBladeWithOffset(bladeY);

    // ✅ hitArea를 이동된 blade 아래로(블레이드 수직 방향 기준)
    const rad = Phaser.Math.DegToRad(this.bladeContainer.angle);
    const ox = -Math.sin(rad) * this.anvilConfig.hitAreaOffset;
    const oy = Math.cos(rad) * this.anvilConfig.hitAreaOffset;

    this.hammerHitArea.setPosition(this.bladeContainer.x + ox, this.bladeContainer.y + oy);

    this.rebuildHitPoly();

    this.uiContainer.setPosition(0, 0);
    this.repositionUIElements();
    this.cameras.main.setBackgroundColor('#1c1917');

    if (this.ambientGlow) {
      this.ambientGlow.setPosition(this.centerX, this.scale.height);
      this.ambientGlow.setRadius(this.scale.width * 0.6);
    }

    if (!this.isPlaying) {
      this.infoText?.setPosition(this.centerX, this.centerY - 220);
    }
  }

  private rebuildHitPoly() {
    const w = this.hammerHitArea.width * this.hammerHitArea.scaleX;
    const h = this.hammerHitArea.height * this.hammerHitArea.scaleY;
    const cx = this.hammerHitArea.x;
    const cy = this.hammerHitArea.y;

    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    const cos = Math.cos(rad);
    const sin = Math.sin(rad);

    const corners = [
      { x: -w / 2, y: -h / 2 },
      { x: w / 2, y: -h / 2 },
      { x: w / 2, y: h / 2 },
      { x: -w / 2, y: h / 2 },
    ].map((p) => ({
      x: cx + p.x * cos - p.y * sin,
      y: cy + p.x * sin + p.y * cos,
    }));

    this.hitPoly = new Phaser.Geom.Polygon(corners);
  }

  private isPointerInHitArea(px: number, py: number) {
    return this.hitPoly && Phaser.Geom.Polygon.Contains(this.hitPoly, px, py);
  }

  drawAnvilSurface() {
    this.anvilSurface.clear();
    const w = this.scale.width;
    const h = this.scale.height;
    const { topWidthRatio, botWidthRatio, heightRatio, yOffset, leftHeightFactor } = this.anvilConfig;
    const topW = w * topWidthRatio;
    const botW = w * botWidthRatio;
    const surfaceH = h * heightRatio;
    const b = this.centerY + surfaceH / 2 + yOffset;
    const tL = b - surfaceH * leftHeightFactor;
    const tR = b - surfaceH;
    const points = [
      { x: this.centerX - topW / 2, y: tL },
      { x: this.centerX + topW / 2, y: tR },
      { x: this.centerX + botW / 2, y: b },
      { x: this.centerX - botW / 2, y: b },
    ];
    const { imageOffsetX, imageOffsetY } = this.anvilConfig;
    if (this.anvilImage) {
      const targetWidth = w * 1.3;
      const scale = targetWidth / this.anvilImage.width;
      this.anvilImage.setScale(scale);
      this.anvilImage.setPosition(this.centerX + imageOffsetX, b + imageOffsetY);
    }
    this.anvilSurface.fillStyle(0x27272a, 0.4);
    this.anvilSurface.fillPoints(points, true);
    this.anvilSurface.lineStyle(6, 0x3f3f46, 0.8);
    this.anvilSurface.strokePoints(points, true);
    this.anvilSurface.fillStyle(0x3f3f46, 0.2);
    this.anvilSurface.fillEllipse(this.centerX, (tL + tR + b + b) / 4, botW * 0.6, surfaceH * 0.65);
  }

  setupUI() {
    this.progressBar = this.add.rectangle(0, 40, 0, 12, 0xeab308).setOrigin(0, 0.5);
    this.uiContainer.add([
      this.add.rectangle(0, 40, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e).setName('progBg'),
      this.progressBar,
    ]);
    this.tempBar = this.add.rectangle(0, 0, 18, 250, 0x3b82f6).setOrigin(0.5, 1).setScale(1, 0);
    this.tempValueText = this.add.text(0, 0, '20°C', { fontFamily: 'monospace', fontSize: '16px', color: '#fff', fontStyle: 'bold' }).setOrigin(0.5);
    this.uiContainer.add([
      this.add.rectangle(0, 0, 32, 260, 0x1c1917).setStrokeStyle(3, 0x57534e).setName('tempFrame'),
      this.add.rectangle(0, 0, 24, 250, 0x0c0a09).setName('tempBg'),
      this.tempBar,
      this.tempValueText,
    ]);
    this.createBellows();
    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Impact', fontSize: '48px', color: '#fcd34d', stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setAlpha(0);
    this.infoText = this.add.text(0, 0, this.isReadyToStart ? 'CLICK TO START' : 'FORGE IS COLD\nADD FUEL TO HEAT', { fontFamily: 'monospace', fontSize: '28px', color: this.isReadyToStart ? '#fbbf24' : '#3b82f6', align: 'center', stroke: '#000', strokeThickness: 5 }).setOrigin(0.5);
    this.uiContainer.add([this.comboText, this.infoText]);
    this.tweens.add({ targets: this.infoText, alpha: 0.5, yoyo: true, repeat: -1, duration: 800 });
  }

  repositionUIElements() {
    const progBg = this.uiContainer.getByName('progBg') as Phaser.GameObjects.Rectangle;
    progBg.setPosition(this.centerX, 40);
    this.progressBar.setPosition(this.centerX - 150, 40);
    const tX = this.scale.width - 60;
    const tY = this.centerY - 50;
    (this.uiContainer.getByName('tempFrame') as any).setPosition(tX, tY);
    (this.uiContainer.getByName('tempBg') as any).setPosition(tX, tY);
    this.tempBar.setPosition(tX, tY + 125);
    this.tempValueText.setPosition(tX, tY - 160);
    this.bellowsContainer.setPosition(tX, tY + 220);
    this.infoText.setPosition(this.centerX, this.centerY - 220);
    this.comboText.setPosition(this.centerX, this.centerY - 300);
  }

  createBellows() {
    this.bellowsContainer = this.add.container(0, 0);
    const bag = this.add.rectangle(0, 0, 70, 50, 0xa16207).setStrokeStyle(2, 0x451a03);
    const top = this.add.rectangle(0, -25, 75, 14, 0x78350f).setStrokeStyle(2, 0x451a03);
    const bot = this.add.rectangle(0, 25, 75, 14, 0x78350f).setStrokeStyle(2, 0x451a03);
    const txt = this.add.text(0, 55, 'PUMP', { fontSize: '14px', color: '#a8a29e', fontFamily: 'monospace', fontStyle: 'bold' }).setOrigin(0.5);
    this.bellowsContainer.add([bag, top, bot, txt]);
    this.bellowsContainer.setInteractive(new Phaser.Geom.Rectangle(-40, -40, 80, 120), Phaser.Geom.Rectangle.Contains);
    this.uiContainer.add(this.bellowsContainer);
  }

  pumpBellows() {
    if (this.isPumping) return;
    this.isPumping = true;
    this.tweens.add({ targets: this.bellowsContainer, scaleY: 0.7, duration: 80, yoyo: true, onComplete: () => (this.isPumping = false) });
    if (this.temperature > 0) {
      this.temperature = Math.min(100, this.temperature + 8);
      if (!this.isPlaying && !this.isReadyToStart) {
        this.isReadyToStart = true;
        this.infoText.setText('CLICK TO START').setColor('#fbbf24');
      }
    }
  }

  public heatUp() {
    this.temperature = Math.min(100, this.temperature + 40);
    if (!this.isPlaying) {
      this.isReadyToStart = true;
      this.infoText.setText('CLICK TO START').setColor('#fbbf24');
    }
  }

  public getTemperature() {
    return this.temperature;
  }

  update(time: number, delta: number) {
    if (this.isFinished) return;
    if (this.isPlaying) this.handleRingLogic(delta);
    this.temperature = Math.max(0, this.temperature - this.coolingRate * (delta / 1000));
    this.refreshVisuals();
    if (!this.isPlaying && this.isReadyToStart && this.temperature <= 0) {
      this.isReadyToStart = false;
      this.infoText.setText('FORGE IS COLD\nADD FUEL TO HEAT').setColor('#3b82f6');
    }
  }

  private setBladeStage(stage: number) {
    const key = `blade_stage_${stage}`;
    if (this.textures.exists(key)) {
      if (!this.bladeImage) {
        this.bladeImage = this.add.image(0, 0, key).setOrigin(0.5);
        this.bladeContainer.add(this.bladeImage);
      } else {
        this.bladeImage.setTexture(key);
      }
      this.bladeImage.setVisible(true);
      this.bladeFallbackRect.setVisible(true);
      this.bladeFallbackRect.setAlpha(0.15);
    } else {
      if (this.bladeImage) this.bladeImage.setVisible(false);
      this.bladeFallbackRect.setVisible(true);
      this.bladeFallbackRect.setAlpha(1);
    }
  }

  refreshVisuals() {
    const ratio = this.temperature / 100;
    this.tempBar.scaleY = ratio;
    this.tempValueText.setText(`${Math.floor(20 + ratio * 1480)}°C`);
    const coldColor = new Phaser.Display.Color(63, 63, 70);
    const hotColor = new Phaser.Display.Color(253, 230, 138);
    const currentTint = Phaser.Display.Color.Interpolate.ColorWithColor(coldColor, hotColor, 100, ratio * 100);
    const colorVal = Phaser.Display.Color.GetColor(currentTint.r, currentTint.g, currentTint.b);
    this.bladeFallbackRect.setFillStyle(colorVal, 1);
    if (this.bladeImage) this.bladeImage.setTint(colorVal);
    const progress = Phaser.Math.Clamp(this.score / this.targetScore, 0, 1);
    const stageCount = 6;
    const stage = Math.min(stageCount - 1, Math.floor(progress * stageCount));
    if (stage !== this.lastStage) {
      this.setBladeStage(stage);
      this.lastStage = stage;
    }
    if (this.ambientGlow) this.ambientGlow.setFillStyle(0xea580c, ratio * 0.25);
    if (this.temperature <= 0) this.currentTempStage = 'COLD';
    else if (this.temperature > 75) this.currentTempStage = 'AURA';
    else if (this.temperature > 40) this.currentTempStage = 'HOT';
    else if (this.temperature > 15) this.currentTempStage = 'WARM';
    else this.currentTempStage = 'NORMAL';
  }

  handleRingLogic(delta: number) {
    this.ringTimer += delta;
    const t = Math.min(this.ringTimer / this.shrinkDuration, 1.5);
    this.currentRadius = this.startRadius * (1 - t * t);
    const ringColor = this.currentRadius < this.targetRadius ? 0xffffff : 0xfabf24;
    this.approachRing.clear().lineStyle(8, ringColor, 0.6).strokeCircle(this.hitX, this.hitY, Math.max(0, this.currentRadius));
    if (this.currentRadius < this.targetRadius - 30) {
      this.combo = 0;
      this.resetRing();
    }
  }

  resetRing() {
    if (this.temperature <= 0) {
      this.isPlaying = false;
      this.isReadyToStart = false;
      this.targetRing.clear();
      this.approachRing.clear();
      this.infoText.setVisible(true).setText('FORGE IS COLD\nADD FUEL TO HEAT').setColor('#3b82f6');
      this.showFeedback('FORGE COLD!', 0x3b82f6, 1.0);
      return;
    }

    this.currentRadius = this.startRadius;
    this.ringTimer = 0;

    const w = this.hammerHitArea.width * this.hammerHitArea.scaleX;
    const h = this.hammerHitArea.height * this.hammerHitArea.scaleY;

    // ✅ 가로로 긴 형태에 맞춰 무작위 지점 선택 로직 조정 (u: 가로 길이 방향, v: 세로 두께 방향)
    const u = Phaser.Math.Between(-w * 0.35, w * 0.35);
    const v = Phaser.Math.Between(-h * 0.25, h * 0.25);

    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    const cos = Math.cos(rad);
    const sin = Math.sin(rad);

    this.hitX = this.hammerHitArea.x + (u * cos - v * sin);
    this.hitY = this.hammerHitArea.y + (u * sin + v * cos);

    if (this.isPlaying) {
      this.targetRing
        .clear()
        .fillStyle(0xfabf24, 0.1)
        .fillCircle(this.hitX, this.hitY, this.targetRadius)
        .lineStyle(5, 0xfabf24, 0.4)
        .strokeCircle(this.hitX, this.hitY, this.targetRadius);
    }
  }

  private pulseHitArea(mult: number) {
    this.tweens.add({
      targets: this.hammerHitArea,
      scaleX: mult,
      scaleY: mult,
      duration: 70,
      yoyo: true,
      onUpdate: () => this.rebuildHitPoly(),
      onComplete: () => this.rebuildHitPoly(),
    });
  }

  handleInput(pointer?: Phaser.Input.Pointer) {
    if (this.isFinished) return;
    if (!this.isPlaying) {
      if (this.isReadyToStart) {
        this.isPlaying = true;
        this.infoText.setVisible(false);
        this.resetRing();
        this.cameras.main.flash(200);
      } else {
        this.cameras.main.shake(50, 0.005);
        this.showFeedback('TOO COLD!', 0x3b82f6, 1.0);
      }
      return;
    }
    if (this.time.now - this.lastHitTime < this.hitCooldown) return;
    this.lastHitTime = this.time.now;
    const swingX = pointer ? pointer.worldX : this.hitX;
    const swingY = pointer ? pointer.worldY : this.hitY;
    if (this.currentTempStage === 'COLD' || this.currentTempStage === 'NORMAL') {
      this.cameras.main.shake(50, 0.005);
      this.showFeedback('TOO COLD!', 0x3b82f6, 1.0);
      return;
    }
    const diff = Math.abs(this.currentRadius - this.targetRadius);
    const efficiency = this.currentTempStage === 'AURA' ? 1.5 : this.currentTempStage === 'HOT' ? 1.0 : 0.5;
    if (diff < 18) {
      this.score += Math.ceil(15 * efficiency);
      this.combo++;
      this.pulseHitArea(1.12);
      this.createSparks(40, 0xffaa00, 2.0, 'spark_perfect', swingX, swingY);
      this.showFeedback('PERFECT!', 0xffb300, 1.5, swingX, swingY);
      this.cameras.main.shake(200, 0.025);
    } else if (diff < 55) {
      this.score += Math.ceil(8 * efficiency);
      this.combo = 0;
      this.pulseHitArea(1.06);
      this.createSparks(20, 0xffffff, 1.3, 'spark_normal', swingX, swingY);
      this.showFeedback('GOOD', 0xe5e5e5, 1.0, swingX, swingY);
      this.cameras.main.shake(80, 0.008);
    } else {
      this.score = Math.max(0, this.score - 5);
      this.combo = 0;
      this.pulseHitArea(0.95);
      this.showFeedback('MISS', 0xef4444, 1.2, swingX, swingY);
      this.cameras.main.shake(120, 0.012);
    }
    this.updateProgressBar();
    if (this.score >= this.targetScore) this.winGame();
    else this.resetRing();
  }

  private updateProgressBar() {
    this.progressBar.width = Phaser.Math.Clamp((this.score / this.targetScore) * 300, 0, 300);
  }

  createSparks(count: number, color: number, scale: number, key: string, x: number, y: number) {
    const emitter = this.add.particles(x, y, this.textures.exists(key) ? key : 'white', { lifespan: 800, speed: { min: 300 * scale, max: 700 * scale }, angle: { min: 230, max: 310 }, scale: { start: 0.7, end: 0 }, gravityY: 1200, blendMode: 'ADD', tint: color });
    emitter.explode(count);
  }

  showFeedback(text: string, color: number, scale: number, x?: number, y?: number) {
    const fx = x ?? this.hitX;
    const fy = y ?? this.hitY;
    const fb = this.add.text(fx, fy - 140, text, { fontFamily: 'Arial', fontSize: '36px', fontStyle: 'bold', color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setScale(0.5).setAlpha(0).setDepth(25);
    this.tweens.add({ targets: fb, y: fy - 200, alpha: 1, scale: scale, duration: 250, hold: 400, yoyo: true, onComplete: () => fb.destroy() });
    if (this.combo > 1) {
      this.comboText.setText(`${this.combo} COMBO!`).setAlpha(1);
      this.tweens.add({ targets: this.comboText, scale: { from: 1.5, to: 1 }, duration: 200, alpha: { from: 1, to: 0 }, delay: 500 });
    }
  }

  winGame() {
    this.isFinished = true;
    this.isPlaying = false;
    this.targetRing.clear();
    this.approachRing.clear();
    if (this.onStatusUpdate) this.onStatusUpdate(this.temperature);
    const bg = this.add.rectangle(this.centerX, this.centerY, this.scale.width, this.scale.height, 0x000000, 0.85).setAlpha(0).setDepth(100);
    this.tweens.add({ targets: bg, alpha: 1, duration: 500 });
    const txt = this.add.text(this.centerX, this.centerY, 'BLADE FORGED!', { fontFamily: 'Georgia', fontSize: '72px', color: '#fbbf24', stroke: '#000', strokeThickness: 3 }).setOrigin(0.5).setAlpha(0).setDepth(101);
    this.tweens.add({ targets: txt, alpha: 1, scale: { from: 0.5, to: 1.2 }, duration: 600, ease: 'Back.out', onComplete: () => { this.time.delayedCall(1000, () => { if (this.onComplete) this.onComplete(100); }); } });
  }
}

const SmithingMinigame: React.FC<SmithingMinigameProps> = ({ onComplete, onClose, difficulty = 1 }) => {
  const { state, actions } = useGame();
  const gameRef = useRef<Phaser.Game | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const charcoalCount = state.inventory.find((i) => i.id === MATERIALS.CHARCOAL.id)?.quantity || 0;

  useEffect(() => {
    if (!containerRef.current) return;
    const timeDiffSec = (Date.now() - (state.lastForgeTime || 0)) / 1000;
    const initialTemp = Math.max(0, (state.forgeTemperature || 0) - timeDiffSec * 5);

    const config: Phaser.Types.Core.GameConfig = {
      type: Phaser.AUTO,
      parent: containerRef.current,
      width: '100%',
      height: '100%',
      backgroundColor: '#0c0a09',
      scene: [SmithingScene],
      scale: {
        mode: Phaser.Scale.RESIZE,
        autoCenter: Phaser.Scale.CENTER_BOTH,
      },
    };

    const game = new Phaser.Game(config);
    gameRef.current = game;
    game.scene.start('SmithingScene', {
      onComplete,
      difficulty,
      initialTemp,
      onStatusUpdate: (t: number) => actions.updateForgeStatus(t),
    });

    return () => {
      game.destroy(true);
      gameRef.current = null;
    };
  }, [onComplete, difficulty]);

  return (
    <div className="w-full h-full flex flex-col bg-stone-950 animate-in fade-in duration-300">
      <div className="w-full h-16 shrink-0 bg-stone-900 border-b border-stone-800 flex items-center justify-between px-6 z-10 shadow-md">
        <div className="flex items-center gap-3">
          <div className="bg-amber-900/30 p-2 rounded-full border border-amber-800">
            <Flame className="w-5 h-5 text-amber-500 animate-pulse" />
          </div>
          <div>
            <h2 className="text-stone-200 font-bold tracking-wide leading-none uppercase text-sm">Forge View</h2>
            <p className="text-[10px] text-stone-500 uppercase tracking-widest mt-1">Full-Width Anvil Perspective</p>
          </div>
        </div>
        <button
          onClick={() => {
            if (gameRef.current) {
              const s = gameRef.current.scene.getScene('SmithingScene') as SmithingScene;
              if (s) actions.updateForgeStatus(s.getTemperature());
            }
            onClose();
          }}
          className="flex items-center gap-2 px-4 py-2 bg-stone-800 hover:bg-red-900/20 text-stone-400 hover:text-red-400 rounded border border-stone-700 transition-all"
        >
          <X className="w-4 h-4" />
          <span className="text-sm font-bold">Cancel</span>
        </button>
      </div>

      <div className="flex-1 w-full relative bg-stone-950 flex items-center justify-center overflow-hidden">
        <div ref={containerRef} className="w-full h-full" />
        <div className="absolute bottom-6 right-6 z-20 flex flex-col items-center">
          <button
            onClick={() => {
              if (gameRef.current) {
                const s = gameRef.current.scene.getScene('SmithingScene') as SmithingScene;
                if (s) {
                  actions.consumeItem(MATERIALS.CHARCOAL.id, 1);
                  s.heatUp();
                }
              }
            }}
            disabled={charcoalCount <= 0}
            className={`flex flex-col items-center justify-center w-24 h-24 rounded-full bg-stone-900 border-4 border-stone-700 hover:border-amber-500 transition-all disabled:opacity-50 group shadow-2xl ${
              charcoalCount > 0 ? 'animate-pulse' : ''
            }`}
          >
            <Flame className="w-8 h-8 text-amber-500 mb-1" />
            <span className="text-[10px] font-bold text-stone-300 uppercase tracking-tighter">Heat Up</span>
            <span className="text-xs text-stone-500 font-mono">x{charcoalCount}</span>
          </button>
        </div>
      </div>

      <div className="w-full py-3 bg-stone-900 border-t border-stone-800 flex justify-center items-center gap-2 text-stone-500 text-[10px] font-mono uppercase tracking-widest">
        <Hammer className="w-3 h-3" />
        <span>Target the glowing surface to shape the metal!</span>
      </div>
    </div>
  );
};

export default SmithingMinigame;

import React, { useEffect, useRef } from 'react';
import Phaser from 'phaser';
import { X, Hammer, Flame } from 'lucide-react';
import { getAssetUrl } from '../../../utils';
import { useGame } from '../../../context/GameContext';
import { MATERIALS } from '../../../data/materials';

interface SmithingMinigameProps {
  onComplete: (score: number) => void;
  onClose: () => void;
  difficulty?: number;
}

class SmithingScene extends Phaser.Scene {
  add!: Phaser.GameObjects.GameObjectFactory;
  make!: Phaser.GameObjects.GameObjectCreator;
  scale!: Phaser.Scale.ScaleManager;
  tweens!: Phaser.Tweens.TweenManager;
  time!: Phaser.Time.Clock;
  cameras!: Phaser.Cameras.Scene2D.CameraManager;
  input!: Phaser.Input.InputPlugin;
  load!: Phaser.Loader.LoaderPlugin;
  textures!: Phaser.Textures.TextureManager;

  private anvilImage!: Phaser.GameObjects.Image;
  private anvilSurface!: Phaser.GameObjects.Graphics;
  private targetRing!: Phaser.GameObjects.Graphics;
  private approachRing!: Phaser.GameObjects.Graphics;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private comboText!: Phaser.GameObjects.Text;
  private infoText!: Phaser.GameObjects.Text;
  private ambientGlow!: Phaser.GameObjects.Arc;

  // ✅ Blade shell = Container( fallback Rect + stage Image )
  private bladeContainer!: Phaser.GameObjects.Container;
  private bladeFallbackRect!: Phaser.GameObjects.Rectangle;
  private bladeImage?: Phaser.GameObjects.Image;

  // ✅ Hit area (rotated rectangle) + precise polygon
  private hammerHitArea!: Phaser.GameObjects.Rectangle;
  private hitPoly!: Phaser.Geom.Polygon;

  private centerX: number = 0;
  private centerY: number = 0;
  private hitX: number = 0;
  private hitY: number = 0;

  private lastStage: number = -1;

  // Perspective Trapezoid Area
  private anvilConfig = {
    topWidthRatio: 0.65,
    botWidthRatio: 1.1,
    heightRatio: 0.4,
    yOffset: 60,
    leftHeightFactor: 0.9,
    imageOffsetX: 0,
    imageOffsetY: 40,
    // ✅ hitArea를 blade 중심으로부터 수직 하단으로 내릴 거리
    hitAreaOffset: 40,
  };

  private startRadius: number = 220;
  private targetRadius: number = 55;
  private currentRadius: number = 220;
  private shrinkDuration: number = 2000;
  private ringTimer: number = 0;

  private score: number = 0;
  private targetScore: number = 100;
  private combo: number = 0;
  private lastHitTime: number = 0;
  private hitCooldown: number = 200;

  private onComplete?: (score: number) => void;
  private onStatusUpdate?: (temp: number) => void;
  private isFinished: boolean = false;
  private isPlaying: boolean = false;
  private isReadyToStart: boolean = false;

  private temperature: number = 0;
  private coolingRate: number = 2;
  private currentTempStage: 'COLD' | 'AURA' | 'HOT' | 'WARM' | 'NORMAL' = 'COLD';

  private tempBar!: Phaser.GameObjects.Rectangle;
  private tempValueText!: Phaser.GameObjects.Text;
  private bellowsContainer!: Phaser.GameObjects.Container;
  private isPumping: boolean = false;

  private uiContainer!: Phaser.GameObjects.Container;

  constructor() {
    super('SmithingScene');
  }

  init(data: { onComplete: (score: number) => void; difficulty: number; initialTemp: number; onStatusUpdate: (temp: number) => void }) {
    this.onComplete = data.onComplete;
    this.onStatusUpdate = data.onStatusUpdate;
    this.shrinkDuration = Math.max(800, 2000 - data.difficulty * 200);
    this.coolingRate = 2 + data.difficulty * 0.8;

    this.score = 0;
    this.combo = 0;
    this.lastStage = -1;

    this.temperature = data.initialTemp || 0;
    this.isFinished = false;
    this.isPlaying = false;
    this.isReadyToStart = this.temperature > 0;
  }

  preload() {
    this.load.crossOrigin = 'anonymous';
    this.load.image('anvil_img', getAssetUrl('anvil.png'));
    this.load.image('spark_perfect', getAssetUrl('particle_spark1.png'));
    this.load.image('spark_normal', getAssetUrl('particle_spark2.png'));

    // ✅ stage 0~5 (총 6장)
    this.load.image('blade_stage_0', getAssetUrl('billet_default.png'));
    this.load.image('blade_stage_1', getAssetUrl('billet_blade_01.png'));
    this.load.image('blade_stage_2', getAssetUrl('billet_blade_02.png'));
    this.load.image('blade_stage_3', getAssetUrl('billet_blade_03.png'));
    this.load.image('blade_stage_4', getAssetUrl('billet_blade_04.png'));
    this.load.image('blade_stage_5', getAssetUrl('billet_blade_05.png'));
  }

  create() {
    this.setupResponsiveLayout();

    this.anvilImage = this.add.image(0, 0, 'anvil_img').setDepth(1).setOrigin(0.5, 0.5);
    this.anvilSurface = this.add.graphics().setDepth(2);

    // ✅ Blade shell container
    this.bladeContainer = this.add.container(0, 0).setDepth(3);
    this.bladeContainer.setAngle(-12);

    // ✅ 가로로 긴 형태로 변경 (600x120)
    this.bladeFallbackRect = this.add.rectangle(0, 0, 600, 120, 0x57534e).setOrigin(0.5, 0.5);
    this.bladeContainer.add(this.bladeFallbackRect);

    // stage image (있으면 위에 올림)
    if (this.textures.exists('blade_stage_0')) {
      this.bladeImage = this.add.image(0, 0, 'blade_stage_0').setOrigin(0.5);
      this.bladeContainer.add(this.bladeImage);
    }

    // ✅ hit area (가로로 긴 판정, 500x120)
    this.hammerHitArea = this.add.rectangle(0, 0, 500, 120, 0x00ff00).setDepth(3).setAlpha(0);
    this.hammerHitArea.setAngle(-12); // 블레이드 각도와 일치

    this.targetRing = this.add.graphics().setDepth(5);
    this.approachRing = this.add.graphics().setDepth(5);

    this.uiContainer = this.add.container(0, 0).setDepth(20);
    this.setupUI();

    this.ambientGlow = this.add.circle(0, 0, 500, 0xea580c, 0).setFillStyle(0xea580c, 0.25).setDepth(0);

    this.handleResize();

    // Inputs
    this.input.keyboard?.on('keydown-SPACE', () => this.handleInput(), this);

    this.input.on(
      'pointerdown',
      (pointer: Phaser.Input.Pointer, objs: any[]) => {
        const isBellows = objs.includes(this.bellowsContainer) || this.bellowsContainer.list.some((c) => objs.includes(c));
        if (isBellows) {
          this.pumpBellows();
          return;
        }

        if (!this.isPlaying) {
          this.handleInput(pointer);
          return;
        }

        const px = pointer.worldX;
        const py = pointer.worldY;

        if (!this.isPointerInHitArea(px, py)) {
          this.handleOffMetalMiss();
          return;
        }

        const dist = Phaser.Math.Distance.Between(px, py, this.hitX, this.hitY);
        const ringThickness = 8;
        const allowRadius = this.currentRadius + ringThickness * 0.5;

        if (dist > allowRadius) {
          this.handleSpatialMiss();
          return;
        }

        this.handleInput(pointer);
      },
      this
    );

    this.scale.on('resize', this.handleResize, this);
  }

  private handleOffMetalMiss() {
    this.score = Math.max(0, this.score - 5);
    this.combo = 0;
    this.cameras.main.shake(100, 0.015);
    this.showFeedback('OFF METAL!', 0xffffff, 1.2);
    this.updateProgressBar();
    this.resetRing();
  }

  private handleSpatialMiss() {
    this.score = Math.max(0, this.score - 5);
    this.combo = 0;
    this.cameras.main.shake(120, 0.012);
    this.showFeedback('MISS', 0xef4444, 1.2);
    this.updateProgressBar();
    this.resetRing();
  }

  setupResponsiveLayout() {
    this.centerX = this.scale.width / 2;
    this.centerY = this.scale.height / 2;
  }

  private positionBladeWithOffset(bladeBaseY: number) {
    // 기본 위치
    this.bladeContainer.setPosition(this.centerX, bladeBaseY);

    // 방향 오프셋(-12도 방향으로 미세 조정)
    const rad = Phaser.Math.DegToRad(this.bladeContainer.angle);
    const offset = 40;
    this.bladeContainer.x += Math.cos(rad) * offset;
    this.bladeContainer.y += Math.sin(rad) * offset;
  }

  handleResize() {
    this.centerX = this.scale.width / 2;
    this.centerY = this.scale.height / 2;

    this.drawAnvilSurface();

    const surfaceH = this.scale.height * this.anvilConfig.heightRatio;
    const b = this.centerY + surfaceH / 2 + this.anvilConfig.yOffset;
    const bladeY = b - surfaceH * 0.45;

    // ✅ 블레이드 위치 설정 (오프셋 포함)
    this.positionBladeWithOffset(bladeY);

    // ✅ hitArea를 이동된 blade 아래로(블레이드 수직 방향 기준)
    const rad = Phaser.Math.DegToRad(this.bladeContainer.angle);
    const ox = -Math.sin(rad) * this.anvilConfig.hitAreaOffset;
    const oy = Math.cos(rad) * this.anvilConfig.hitAreaOffset;

    this.hammerHitArea.setPosition(this.bladeContainer.x + ox, this.bladeContainer.y + oy);

    this.rebuildHitPoly();

    this.uiContainer.setPosition(0, 0);
    this.repositionUIElements();
    this.cameras.main.setBackgroundColor('#1c1917');

    if (this.ambientGlow) {
      this.ambientGlow.setPosition(this.centerX, this.scale.height);
      this.ambientGlow.setRadius(this.scale.width * 0.6);
    }

    if (!this.isPlaying) {
      this.infoText?.setPosition(this.centerX, this.centerY - 220);
    }
  }

  private rebuildHitPoly() {
    const w = this.hammerHitArea.width * this.hammerHitArea.scaleX;
    const h = this.hammerHitArea.height * this.hammerHitArea.scaleY;
    const cx = this.hammerHitArea.x;
    const cy = this.hammerHitArea.y;

    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    const cos = Math.cos(rad);
    const sin = Math.sin(rad);

    const corners = [
      { x: -w / 2, y: -h / 2 },
      { x: w / 2, y: -h / 2 },
      { x: w / 2, y: h / 2 },
      { x: -w / 2, y: h / 2 },
    ].map((p) => ({
      x: cx + p.x * cos - p.y * sin,
      y: cy + p.x * sin + p.y * cos,
    }));

    this.hitPoly = new Phaser.Geom.Polygon(corners);
  }

  private isPointerInHitArea(px: number, py: number) {
    return this.hitPoly && Phaser.Geom.Polygon.Contains(this.hitPoly, px, py);
  }

  drawAnvilSurface() {
    this.anvilSurface.clear();
    const w = this.scale.width;
    const h = this.scale.height;
    const { topWidthRatio, botWidthRatio, heightRatio, yOffset, leftHeightFactor } = this.anvilConfig;
    const topW = w * topWidthRatio;
    const botW = w * botWidthRatio;
    const surfaceH = h * heightRatio;
    const b = this.centerY + surfaceH / 2 + yOffset;
    const tL = b - surfaceH * leftHeightFactor;
    const tR = b - surfaceH;

    const points = [
      { x: this.centerX - topW / 2, y: tL },
      { x: this.centerX + topW / 2, y: tR },
      { x: this.centerX + botW / 2, y: b },
      { x: this.centerX - botW / 2, y: b },
    ];

    const { imageOffsetX, imageOffsetY } = this.anvilConfig;

    // ✅ 이미지가 있으면 이미지를 배치하고 도형 드로잉은 스킵
    if (this.anvilImage && this.anvilImage.texture.key !== '__MISSING') {
      const targetWidth = w * 1.3;
      const scale = targetWidth / this.anvilImage.width;
      this.anvilImage.setScale(scale);
      this.anvilImage.setPosition(this.centerX + imageOffsetX, b + imageOffsetY);
      this.anvilImage.setVisible(true);
      // 도형 드로잉 코드를 건너뜀
      return;
    }

    // ✅ 이미지가 없을 때만 실행되는 백업 드로잉 로직
    this.anvilSurface.fillStyle(0x27272a, 0.4);
    this.anvilSurface.fillPoints(points, true);
    this.anvilSurface.lineStyle(6, 0x3f3f46, 0.8);
    this.anvilSurface.strokePoints(points, true);
    this.anvilSurface.fillStyle(0x3f3f46, 0.2);
    this.anvilSurface.fillEllipse(this.centerX, (tL + tR + b + b) / 4, botW * 0.6, surfaceH * 0.65);
  }

  setupUI() {
    this.progressBar = this.add.rectangle(0, 40, 0, 12, 0xeab308).setOrigin(0, 0.5);
    this.uiContainer.add([
      this.add.rectangle(0, 40, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e).setName('progBg'),
      this.progressBar,
    ]);
    this.tempBar = this.add.rectangle(0, 0, 18, 250, 0x3b82f6).setOrigin(0.5, 1).setScale(1, 0);
    this.tempValueText = this.add.text(0, 0, '20°C', { fontFamily: 'monospace', fontSize: '16px', color: '#fff', fontStyle: 'bold' }).setOrigin(0.5);
    this.uiContainer.add([
      this.add.rectangle(0, 0, 32, 260, 0x1c1917).setStrokeStyle(3, 0x57534e).setName('tempFrame'),
      this.add.rectangle(0, 0, 24, 250, 0x0c0a09).setName('tempBg'),
      this.tempBar,
      this.tempValueText,
    ]);
    this.createBellows();
    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Impact', fontSize: '48px', color: '#fcd34d', stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setAlpha(0);
    this.infoText = this.add.text(0, 0, this.isReadyToStart ? 'CLICK TO START' : 'FORGE IS COLD\nADD FUEL TO HEAT', { fontFamily: 'monospace', fontSize: '28px', color: this.isReadyToStart ? '#fbbf24' : '#3b82f6', align: 'center', stroke: '#000', strokeThickness: 5 }).setOrigin(0.5);
    this.uiContainer.add([this.comboText, this.infoText]);
    this.tweens.add({ targets: this.infoText, alpha: 0.5, yoyo: true, repeat: -1, duration: 800 });
  }

  repositionUIElements() {
    const progBg = this.uiContainer.getByName('progBg') as Phaser.GameObjects.Rectangle;
    progBg.setPosition(this.centerX, 40);
    this.progressBar.setPosition(this.centerX - 150, 40);
    const tX = this.scale.width - 60;
    const tY = this.centerY - 50;
    (this.uiContainer.getByName('tempFrame') as any).setPosition(tX, tY);
    (this.uiContainer.getByName('tempBg') as any).setPosition(tX, tY);
    this.tempBar.setPosition(tX, tY + 125);
    this.tempValueText.setPosition(tX, tY - 160);
    this.bellowsContainer.setPosition(tX, tY + 220);
    this.infoText.setPosition(this.centerX, this.centerY - 220);
    this.comboText.setPosition(this.centerX, this.centerY - 300);
  }

  createBellows() {
    this.bellowsContainer = this.add.container(0, 0);
    const bag = this.add.rectangle(0, 0, 70, 50, 0xa16207).setStrokeStyle(2, 0x451a03);
    const top = this.add.rectangle(0, -25, 75, 14, 0x78350f).setStrokeStyle(2, 0x451a03);
    const bot = this.add.rectangle(0, 25, 75, 14, 0x78350f).setStrokeStyle(2, 0x451a03);
    const txt = this.add.text(0, 55, 'PUMP', { fontSize: '14px', color: '#a8a29e', fontFamily: 'monospace', fontStyle: 'bold' }).setOrigin(0.5);
    this.bellowsContainer.add([bag, top, bot, txt]);
    this.bellowsContainer.setInteractive(new Phaser.Geom.Rectangle(-40, -40, 80, 120), Phaser.Geom.Rectangle.Contains);
    this.uiContainer.add(this.bellowsContainer);
  }

  pumpBellows() {
    if (this.isPumping) return;
    this.isPumping = true;
    this.tweens.add({ targets: this.bellowsContainer, scaleY: 0.7, duration: 80, yoyo: true, onComplete: () => (this.isPumping = false) });
    if (this.temperature > 0) {
      this.temperature = Math.min(100, this.temperature + 8);
      if (!this.isPlaying && !this.isReadyToStart) {
        this.isReadyToStart = true;
        this.infoText.setText('CLICK TO START').setColor('#fbbf24');
      }
    }
  }

  public heatUp() {
    this.temperature = Math.min(100, this.temperature + 40);
    if (!this.isPlaying) {
      this.isReadyToStart = true;
      this.infoText.setText('CLICK TO START').setColor('#fbbf24');
    }
  }

  public getTemperature() {
    return this.temperature;
  }

  update(time: number, delta: number) {
    if (this.isFinished) return;
    if (this.isPlaying) this.handleRingLogic(delta);
    this.temperature = Math.max(0, this.temperature - this.coolingRate * (delta / 1000));
    this.refreshVisuals();
    if (!this.isPlaying && this.isReadyToStart && this.temperature <= 0) {
      this.isReadyToStart = false;
      this.infoText.setText('FORGE IS COLD\nADD FUEL TO HEAT').setColor('#3b82f6');
    }
  }

  private setBladeStage(stage: number) {
    const key = `blade_stage_${stage}`;
    if (this.textures.exists(key)) {
      if (!this.bladeImage) {
        this.bladeImage = this.add.image(0, 0, key).setOrigin(0.5);
        this.bladeContainer.add(this.bladeImage);
      } else {
        this.bladeImage.setTexture(key);
      }
      this.bladeImage.setVisible(true);
      this.bladeFallbackRect.setVisible(true);
      this.bladeFallbackRect.setAlpha(0.15);
    } else {
      if (this.bladeImage) this.bladeImage.setVisible(false);
      this.bladeFallbackRect.setVisible(true);
      this.bladeFallbackRect.setAlpha(1);
    }
  }

  refreshVisuals() {
    const ratio = this.temperature / 100;
    this.tempBar.scaleY = ratio;
    this.tempValueText.setText(`${Math.floor(20 + ratio * 1480)}°C`);
    const coldColor = new Phaser.Display.Color(63, 63, 70);
    const hotColor = new Phaser.Display.Color(253, 230, 138);
    const currentTint = Phaser.Display.Color.Interpolate.ColorWithColor(coldColor, hotColor, 100, ratio * 100);
    const colorVal = Phaser.Display.Color.GetColor(currentTint.r, currentTint.g, currentTint.b);
    this.bladeFallbackRect.setFillStyle(colorVal, 1);
    if (this.bladeImage) this.bladeImage.setTint(colorVal);
    const progress = Phaser.Math.Clamp(this.score / this.targetScore, 0, 1);
    const stageCount = 6;
    const stage = Math.min(stageCount - 1, Math.floor(progress * stageCount));
    if (stage !== this.lastStage) {
      this.setBladeStage(stage);
      this.lastStage = stage;
    }
    if (this.ambientGlow) this.ambientGlow.setFillStyle(0xea580c, ratio * 0.25);
    if (this.temperature <= 0) this.currentTempStage = 'COLD';
    else if (this.temperature > 75) this.currentTempStage = 'AURA';
    else if (this.temperature > 40) this.currentTempStage = 'HOT';
    else if (this.temperature > 15) this.currentTempStage = 'WARM';
    else this.currentTempStage = 'NORMAL';
  }

  handleRingLogic(delta: number) {
    this.ringTimer += delta;
    const t = Math.min(this.ringTimer / this.shrinkDuration, 1.5);
    this.currentRadius = this.startRadius * (1 - t * t);
    const ringColor = this.currentRadius < this.targetRadius ? 0xffffff : 0xfabf24;
    this.approachRing.clear().lineStyle(8, ringColor, 0.6).strokeCircle(this.hitX, this.hitY, Math.max(0, this.currentRadius));
    if (this.currentRadius < this.targetRadius - 30) {
      this.combo = 0;
      this.resetRing();
    }
  }

  resetRing() {
    if (this.temperature <= 0) {
      this.isPlaying = false;
      this.isReadyToStart = false;
      this.targetRing.clear();
      this.approachRing.clear();
      this.infoText.setVisible(true).setText('FORGE IS COLD\nADD FUEL TO HEAT').setColor('#3b82f6');
      this.showFeedback('FORGE COLD!', 0x3b82f6, 1.0);
      return;
    }

    this.currentRadius = this.startRadius;
    this.ringTimer = 0;

    const w = this.hammerHitArea.width * this.hammerHitArea.scaleX;
    const h = this.hammerHitArea.height * this.hammerHitArea.scaleY;

    // ✅ 가로로 긴 형태에 맞춰 무작위 지점 선택 로직 조정 (u: 가로 길이 방향, v: 세로 두께 방향)
    const u = Phaser.Math.Between(-w * 0.35, w * 0.35);
    const v = Phaser.Math.Between(-h * 0.25, h * 0.25);

    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    const cos = Math.cos(rad);
    const sin = Math.sin(rad);

    this.hitX = this.hammerHitArea.x + (u * cos - v * sin);
    this.hitY = this.hammerHitArea.y + (u * sin + v * cos);

    if (this.isPlaying) {
      this.targetRing
        .clear()
        .fillStyle(0xfabf24, 0.1)
        .fillCircle(this.hitX, this.hitY, this.targetRadius)
        .lineStyle(5, 0xfabf24, 0.4)
        .strokeCircle(this.hitX, this.hitY, this.targetRadius);
    }
  }

  private pulseHitArea(mult: number) {
    this.tweens.add({
      targets: this.hammerHitArea,
      scaleX: mult,
      scaleY: mult,
      duration: 70,
      yoyo: true,
      onUpdate: () => this.rebuildHitPoly(),
      onComplete: () => this.rebuildHitPoly(),
    });
  }

  handleInput(pointer?: Phaser.Input.Pointer) {
    if (this.isFinished) return;
    if (!this.isPlaying) {
      if (this.isReadyToStart) {
        this.isPlaying = true;
        this.infoText.setVisible(false);
        this.resetRing();
        this.cameras.main.flash(200);
      } else {
        this.cameras.main.shake(50, 0.005);
        this.showFeedback('TOO COLD!', 0x3b82f6, 1.0);
      }
      return;
    }
    if (this.time.now - this.lastHitTime < this.hitCooldown) return;
    this.lastHitTime = this.time.now;
    const swingX = pointer ? pointer.worldX : this.hitX;
    const swingY = pointer ? pointer.worldY : this.hitY;
    if (this.currentTempStage === 'COLD' || this.currentTempStage === 'NORMAL') {
      this.cameras.main.shake(50, 0.005);
      this.showFeedback('TOO COLD!', 0x3b82f6, 1.0);
      return;
    }
    const diff = Math.abs(this.currentRadius - this.targetRadius);
    const efficiency = this.currentTempStage === 'AURA' ? 1.5 : this.currentTempStage === 'HOT' ? 1.0 : 0.5;
    if (diff < 18) {
      this.score += Math.ceil(15 * efficiency);
      this.combo++;
      this.pulseHitArea(1.12);
      this.createSparks(40, 0xffaa00, 2.0, 'spark_perfect', swingX, swingY);
      this.showFeedback('PERFECT!', 0xffb300, 1.5, swingX, swingY);
      this.cameras.main.shake(200, 0.025);
    } else if (diff < 55) {
      this.score += Math.ceil(8 * efficiency);
      this.combo = 0;
      this.pulseHitArea(1.06);
      this.createSparks(20, 0xffffff, 1.3, 'spark_normal', swingX, swingY);
      this.showFeedback('GOOD', 0xe5e5e5, 1.0, swingX, swingY);
      this.cameras.main.shake(80, 0.008);
    } else {
      this.score = Math.max(0, this.score - 5);
      this.combo = 0;
      this.pulseHitArea(0.95);
      this.showFeedback('MISS', 0xef4444, 1.2, swingX, swingY);
      this.cameras.main.shake(120, 0.012);
    }
    this.updateProgressBar();
    if (this.score >= this.targetScore) this.winGame();
    else this.resetRing();
  }

  private updateProgressBar() {
    this.progressBar.width = Phaser.Math.Clamp((this.score / this.targetScore) * 300, 0, 300);
  }

  createSparks(count: number, color: number, scale: number, key: string, x: number, y: number) {
    const emitter = this.add.particles(x, y, this.textures.exists(key) ? key : 'white', { lifespan: 800, speed: { min: 300 * scale, max: 700 * scale }, angle: { min: 230, max: 310 }, scale: { start: 0.7, end: 0 }, gravityY: 1200, blendMode: 'ADD', tint: color });
    emitter.explode(count);
  }

  showFeedback(text: string, color: number, scale: number, x?: number, y?: number) {
    const fx = x ?? this.hitX;
    const fy = y ?? this.hitY;
    const fb = this.add.text(fx, fy - 140, text, { fontFamily: 'Arial', fontSize: '36px', fontStyle: 'bold', color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setScale(0.5).setAlpha(0).setDepth(25);
    this.tweens.add({ targets: fb, y: fy - 200, alpha: 1, scale: scale, duration: 250, hold: 400, yoyo: true, onComplete: () => fb.destroy() });
    if (this.combo > 1) {
      this.comboText.setText(`${this.combo} COMBO!`).setAlpha(1);
      this.tweens.add({ targets: this.comboText, scale: { from: 1.5, to: 1 }, duration: 200, alpha: { from: 1, to: 0 }, delay: 500 });
    }
  }

  winGame() {
    this.isFinished = true;
    this.isPlaying = false;
    this.targetRing.clear();
    this.approachRing.clear();
    if (this.onStatusUpdate) this.onStatusUpdate(this.temperature);
    const bg = this.add.rectangle(this.centerX, this.centerY, this.scale.width, this.scale.height, 0x000000, 0.85).setAlpha(0).setDepth(100);
    this.tweens.add({ targets: bg, alpha: 1, duration: 500 });
    const txt = this.add.text(this.centerX, this.centerY, 'BLADE FORGED!', { fontFamily: 'Georgia', fontSize: '72px', color: '#fbbf24', stroke: '#000', strokeThickness: 3 }).setOrigin(0.5).setAlpha(0).setDepth(101);
    this.tweens.add({ targets: txt, alpha: 1, scale: { from: 0.5, to: 1.2 }, duration: 600, ease: 'Back.out', onComplete: () => { this.time.delayedCall(1000, () => { if (this.onComplete) this.onComplete(100); }); } });
  }
}

const SmithingMinigame: React.FC<SmithingMinigameProps> = ({ onComplete, onClose, difficulty = 1 }) => {
  const { state, actions } = useGame();
  const gameRef = useRef<Phaser.Game | null>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const charcoalCount = state.inventory.find((i) => i.id === MATERIALS.CHARCOAL.id)?.quantity || 0;

  useEffect(() => {
    if (!containerRef.current) return;
    const timeDiffSec = (Date.now() - (state.lastForgeTime || 0)) / 1000;
    const initialTemp = Math.max(0, (state.forgeTemperature || 0) - timeDiffSec * 5);

    const config: Phaser.Types.Core.GameConfig = {
      type: Phaser.AUTO,
      parent: containerRef.current,
      width: '100%',
      height: '100%',
      backgroundColor: '#0c0a09',
      scene: [SmithingScene],
      scale: {
        mode: Phaser.Scale.RESIZE,
        autoCenter: Phaser.Scale.CENTER_BOTH,
      },
    };

    const game = new Phaser.Game(config);
    gameRef.current = game;
    game.scene.start('SmithingScene', {
      onComplete,
      difficulty,
      initialTemp,
      onStatusUpdate: (t: number) => actions.updateForgeStatus(t),
    });

    return () => {
      game.destroy(true);
      gameRef.current = null;
    };
  }, [onComplete, difficulty]);

  return (
    <div className="w-full h-full flex flex-col bg-stone-950 animate-in fade-in duration-300">
      <div className="w-full h-16 shrink-0 bg-stone-900 border-b border-stone-800 flex items-center justify-between px-6 z-10 shadow-md">
        <div className="flex items-center gap-3">
          <div className="bg-amber-900/30 p-2 rounded-full border border-amber-800">
            <Flame className="w-5 h-5 text-amber-500 animate-pulse" />
          </div>
          <div>
            <h2 className="text-stone-200 font-bold tracking-wide leading-none uppercase text-sm">Forge View</h2>
            <p className="text-[10px] text-stone-500 uppercase tracking-widest mt-1">Full-Width Anvil Perspective</p>
          </div>
        </div>
        <button
          onClick={() => {
            if (gameRef.current) {
              const s = gameRef.current.scene.getScene('SmithingScene') as SmithingScene;
              if (s) actions.updateForgeStatus(s.getTemperature());
            }
            onClose();
          }}
          className="flex items-center gap-2 px-4 py-2 bg-stone-800 hover:bg-red-900/20 text-stone-400 hover:text-red-400 rounded border border-stone-700 transition-all"
        >
          <X className="w-4 h-4" />
          <span className="text-sm font-bold">Cancel</span>
        </button>
      </div>

      <div className="flex-1 w-full relative bg-stone-950 flex items-center justify-center overflow-hidden">
        <div ref={containerRef} className="w-full h-full" />
        <div className="absolute bottom-6 right-6 z-20 flex flex-col items-center">
          <button
            onClick={() => {
              if (gameRef.current) {
                const s = gameRef.current.scene.getScene('SmithingScene') as SmithingScene;
                if (s) {
                  actions.consumeItem(MATERIALS.CHARCOAL.id, 1);
                  s.heatUp();
                }
              }
            }}
            disabled={charcoalCount <= 0}
            className={`flex flex-col items-center justify-center w-24 h-24 rounded-full bg-stone-900 border-4 border-stone-700 hover:border-amber-500 transition-all disabled:opacity-50 group shadow-2xl ${
              charcoalCount > 0 ? 'animate-pulse' : ''
            }`}
          >
            <Flame className="w-8 h-8 text-amber-500 mb-1" />
            <span className="text-[10px] font-bold text-stone-300 uppercase tracking-tighter">Heat Up</span>
            <span className="text-xs text-stone-500 font-mono">x{charcoalCount}</span>
          </button>
        </div>
      </div>

      <div className="w-full py-3 bg-stone-900 border-t border-stone-800 flex justify-center items-center gap-2 text-stone-500 text-[10px] font-mono uppercase tracking-widest">
        <Hammer className="w-3 h-3" />
        <span>Target the glowing surface to shape the metal!</span>
      </div>
    </div>
  );
};

export default SmithingMinigame;

import React, { useEffect, useRef } from 'react';
import Phaser from 'phaser';
import { X, Hammer, Flame } from 'lucide-react';
import { getAssetUrl } from '../../../utils';
import { useGame } from '../../../context/GameContext';
import { MATERIALS } from '../../../data/materials';

interface SmithingMinigameProps {
  onComplete: (score: number) => void;
  onClose: () => void;
  difficulty?: number;
}

class SmithingScene extends Phaser.Scene {
  add!: Phaser.GameObjects.GameObjectFactory;
  make!: Phaser.GameObjects.GameObjectCreator;
  scale!: Phaser.Scale.ScaleManager;
  tweens!: Phaser.Tweens.TweenManager;
  time!: Phaser.Time.Clock;
  cameras!: Phaser.Cameras.Scene2D.CameraManager;
  input!: Phaser.Input.InputPlugin;
  load!: Phaser.Loader.LoaderPlugin;
  textures!: Phaser.Textures.TextureManager;

  private anvilImage!: Phaser.GameObjects.Image;
  private anvilSurface!: Phaser.GameObjects.Graphics;
  private targetRing!: Phaser.GameObjects.Graphics;
  private approachRing!: Phaser.GameObjects.Graphics;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private comboText!: Phaser.GameObjects.Text;
  private infoText!: Phaser.GameObjects.Text;
  private ambientGlow!: Phaser.GameObjects.Arc;

  private bladeContainer!: Phaser.GameObjects.Container;
  private bladeFallbackRect!: Phaser.GameObjects.Rectangle;
  private bladeImage?: Phaser.GameObjects.Image;

  private hammerHitArea!: Phaser.GameObjects.Rectangle;
  private hitPoly!: Phaser.Geom.Polygon;

  private centerX: number = 0;
  private centerY: number = 0;
  private hitX: number = 0;
  private hitY: number = 0;

  private lastStage: number = -1;

  private anvilConfig = {
    topWidthRatio: 0.65,
    botWidthRatio: 1.1,
    heightRatio: 0.4,
    yOffset: 60,
    leftHeightFactor: 0.9,
    imageOffsetX: 0,
    imageOffsetY: 40,
    hitAreaOffset: 45, // 블레이드 중심에서 아래로 판정 영역 이동 거리
  };

  private startRadius: number = 220;
  private targetRadius: number = 55;
  private currentRadius: number = 220;
  private shrinkDuration: number = 2000;
  private ringTimer: number = 0;

  private score: number = 0;
  private targetScore: number = 100;
  private combo: number = 0;
  private lastHitTime: number = 0;
  private hitCooldown: number = 200;

  private onComplete?: (score: number) => void;
  private onStatusUpdate?: (temp: number) => void;
  private isFinished: boolean = false;
  private isPlaying: boolean = false;
  private isReadyToStart: boolean = false;

  private temperature: number = 0;
  private coolingRate: number = 2;
  private currentTempStage: 'COLD' | 'AURA' | 'HOT' | 'WARM' | 'NORMAL' = 'COLD';

  private tempBar!: Phaser.GameObjects.Rectangle;
  private tempValueText!: Phaser.GameObjects.Text;
  private bellowsContainer!: Phaser.GameObjects.Container;
  private isPumping: boolean = false;

  private uiContainer!: Phaser.GameObjects.Container;

  constructor() {
    super('SmithingScene');
  }

  init(data: { onComplete: (score: number) => void; difficulty: number; initialTemp: number; onStatusUpdate: (temp: number) => void }) {
    this.onComplete = data.onComplete;
    this.onStatusUpdate = data.onStatusUpdate;
    this.shrinkDuration = Math.max(800, 2000 - data.difficulty * 200);
    this.coolingRate = 2 + data.difficulty * 0.8;

    this.score = 0;
    this.combo = 0;
    this.lastStage = -1;

    this.temperature = data.initialTemp || 0;
    this.isFinished = false;
    this.isPlaying = false;
    this.isReadyToStart = this.temperature > 0;
  }

  preload() {
    this.load.crossOrigin = 'anonymous';
    this.load.image('anvil_img', getAssetUrl('anvil.png'));
    this.load.image('spark_perfect', getAssetUrl('particle_spark1.png'));
    this.load.image('spark_normal', getAssetUrl('particle_spark2.png'));

    this.load.image('blade_stage_0', getAssetUrl('billet_default.png'));
    this.load.image('blade_stage_1', getAssetUrl('billet_blade_01.png'));
    this.load.image('blade_stage_2', getAssetUrl('billet_blade_02.png'));
    this.load.image('blade_stage_3', getAssetUrl('billet_blade_03.png'));
    this.load.image('blade_stage_4', getAssetUrl('billet_blade_04.png'));
    this.load.image('blade_stage_5', getAssetUrl('billet_blade_05.png'));
  }

  create() {
    this.setupResponsiveLayout();

    this.anvilImage = this.add.image(0, 0, 'anvil_img').setDepth(1).setOrigin(0.5, 0.5);
    this.anvilSurface = this.add.graphics().setDepth(2);

    // Blade shell container
    this.bladeContainer = this.add.container(0, 0).setDepth(3);
    this.bladeContainer.setAngle(-12);

    // 가로로 긴 형태로 변경 (600x120)
    this.bladeFallbackRect = this.add.rectangle(0, 0, 600, 120, 0x57534e).setOrigin(0.5, 0.5);
    this.bladeContainer.add(this.bladeFallbackRect);

    if (this.textures.exists('blade_stage_0')) {
      this.bladeImage = this.add.image(0, 0, 'blade_stage_0').setOrigin(0.5);
      this.bladeContainer.add(this.bladeImage);
    }

    // 가로로 긴 판정 영역 (500x120)
    this.hammerHitArea = this.add.rectangle(0, 0, 500, 120, 0x00ff00).setDepth(3).setAlpha(0);
    this.hammerHitArea.setAngle(-12);

    this.targetRing = this.add.graphics().setDepth(5);
    this.approachRing = this.add.graphics().setDepth(5);

    this.uiContainer = this.add.container(0, 0).setDepth(20);
    this.setupUI();

    this.ambientGlow = this.add.circle(0, 0, 500, 0xea580c, 0).setFillStyle(0xea580c, 0.25).setDepth(0);

    this.handleResize();

    this.input.keyboard?.on('keydown-SPACE', () => this.handleInput(), this);
    this.input.on('pointerdown', (pointer: Phaser.Input.Pointer, objs: any[]) => {
      const isBellows = objs.includes(this.bellowsContainer) || this.bellowsContainer.list.some((c) => objs.includes(c));
      if (isBellows) {
        this.pumpBellows();
        return;
      }
      if (!this.isPlaying) {
        this.handleInput(pointer);
        return;
      }
      const px = pointer.worldX;
      const py = pointer.worldY;
      if (!this.isPointerInHitArea(px, py)) {
        this.handleOffMetalMiss();
        return;
      }
      const dist = Phaser.Math.Distance.Between(px, py, this.hitX, this.hitY);
      if (dist > this.currentRadius + 4) {
        this.handleSpatialMiss();
        return;
      }
      this.handleInput(pointer);
    }, this);

    this.scale.on('resize', this.handleResize, this);
  }

  private handleOffMetalMiss() {
    this.score = Math.max(0, this.score - 5);
    this.combo = 0;
    this.cameras.main.shake(100, 0.015);
    this.showFeedback('OFF METAL!', 0xffffff, 1.2);
    this.updateProgressBar();
    this.resetRing();
  }

  private handleSpatialMiss() {
    this.score = Math.max(0, this.score - 5);
    this.combo = 0;
    this.cameras.main.shake(120, 0.012);
    this.showFeedback('MISS', 0xef4444, 1.2);
    this.updateProgressBar();
    this.resetRing();
  }

  setupResponsiveLayout() {
    this.centerX = this.scale.width / 2;
    this.centerY = this.scale.height / 2;
  }

  private positionBladeWithOffset(bladeBaseY: number) {
    // 기본 위치 설정
    this.bladeContainer.setPosition(this.centerX, bladeBaseY);

    // 오른쪽 위 방향 오프셋 (회전각 -12도 방향)
    const rad = Phaser.Math.DegToRad(this.bladeContainer.angle);
    const offset = 80; // 거리를 80으로 늘려 오른쪽 위로 더 보냄
    this.bladeContainer.x += Math.cos(rad) * offset;
    this.bladeContainer.y += Math.sin(rad) * offset;
  }

  handleResize() {
    this.centerX = this.scale.width / 2;
    this.centerY = this.scale.height / 2;

    this.drawAnvilSurface();

    const surfaceH = this.scale.height * this.anvilConfig.heightRatio;
    const b = this.centerY + surfaceH / 2 + this.anvilConfig.yOffset;
    const bladeY = b - surfaceH * 0.55; // 기존 0.45에서 0.55로 상향 조정하여 더 위로 배치

    this.positionBladeWithOffset(bladeY);

    // 판정 영역을 이동된 블레이드 아래로 정렬
    const rad = Phaser.Math.DegToRad(this.bladeContainer.angle);
    const ox = -Math.sin(rad) * this.anvilConfig.hitAreaOffset;
    const oy = Math.cos(rad) * this.anvilConfig.hitAreaOffset;

    this.hammerHitArea.setPosition(this.bladeContainer.x + ox, this.bladeContainer.y + oy);
    this.rebuildHitPoly();

    this.uiContainer.setPosition(0, 0);
    this.repositionUIElements();
    this.cameras.main.setBackgroundColor('#1c1917');

    if (this.ambientGlow) {
      this.ambientGlow.setPosition(this.centerX, this.scale.height);
      this.ambientGlow.setRadius(this.scale.width * 0.6);
    }
    if (!this.isPlaying) {
      this.infoText?.setPosition(this.centerX, this.centerY - 220);
    }
  }

  private rebuildHitPoly() {
    const w = this.hammerHitArea.width * this.hammerHitArea.scaleX;
    const h = this.hammerHitArea.height * this.hammerHitArea.scaleY;
    const cx = this.hammerHitArea.x;
    const cy = this.hammerHitArea.y;
    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    const cos = Math.cos(rad);
    const sin = Math.sin(rad);
    const corners = [
      { x: -w / 2, y: -h / 2 },
      { x: w / 2, y: -h / 2 },
      { x: w / 2, y: h / 2 },
      { x: -w / 2, y: h / 2 },
    ].map((p) => ({
      x: cx + p.x * cos - p.y * sin,
      y: cy + p.x * sin + p.y * cos,
    }));
    this.hitPoly = new Phaser.Geom.Polygon(corners);
  }

  private isPointerInHitArea(px: number, py: number) {
    return this.hitPoly && Phaser.Geom.Polygon.Contains(this.hitPoly, px, py);
  }

  drawAnvilSurface() {
    this.anvilSurface.clear();
    const w = this.scale.width;
    const h = this.scale.height;
    const { topWidthRatio, botWidthRatio, heightRatio, yOffset, leftHeightFactor, imageOffsetX, imageOffsetY } = this.anvilConfig;

    const b = this.centerY + (h * heightRatio) / 2 + yOffset;

    if (this.anvilImage && this.anvilImage.texture.key !== '__MISSING') {
      const targetWidth = w * 1.3;
      this.anvilImage.setScale(targetWidth / this.anvilImage.width);
      this.anvilImage.setPosition(this.centerX + imageOffsetX, b + imageOffsetY);
      this.anvilImage.setVisible(true);
      return; // 이미지 있으면 그래픽 드로잉 스킵
    }

    const points = [
      { x: this.centerX - (w * topWidthRatio) / 2, y: b - (h * heightRatio) * leftHeightFactor },
      { x: this.centerX + (w * topWidthRatio) / 2, y: b - (h * heightRatio) },
      { x: this.centerX + (w * botWidthRatio) / 2, y: b },
      { x: this.centerX - (w * botWidthRatio) / 2, y: b },
    ];
    this.anvilSurface.fillStyle(0x27272a, 0.4).fillPoints(points, true);
    this.anvilSurface.lineStyle(6, 0x3f3f46, 0.8).strokePoints(points, true);
    this.anvilSurface.fillStyle(0x3f3f46, 0.2).fillEllipse(this.centerX, (points[0].y + points[1].y + b + b) / 4, (w * botWidthRatio) * 0.6, (h * heightRatio) * 0.65);
  }

  setupUI() {
    this.progressBar = this.add.rectangle(0, 40, 0, 12, 0xeab308).setOrigin(0, 0.5);
    this.uiContainer.add([
      this.add.rectangle(0, 40, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e).setName('progBg'),
      this.progressBar,
    ]);
    this.tempBar = this.add.rectangle(0, 0, 18, 250, 0x3b82f6).setOrigin(0.5, 1).setScale(1, 0);
    this.tempValueText = this.add.text(0, 0, '20°C', { fontFamily: 'monospace', fontSize: '16px', color: '#fff', fontStyle: 'bold' }).setOrigin(0.5);
    this.uiContainer.add([
      this.add.rectangle(0, 0, 32, 260, 0x1c1917).setStrokeStyle(3, 0x57534e).setName('tempFrame'),
      this.add.rectangle(0, 0, 24, 250, 0x0c0a09).setName('tempBg'),
      this.tempBar,
      this.tempValueText,
    ]);
    this.createBellows();
    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Impact', fontSize: '48px', color: '#fcd34d', stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setAlpha(0);
    this.infoText = this.add.text(0, 0, this.isReadyToStart ? 'CLICK TO START' : 'FORGE IS COLD\nADD FUEL TO HEAT', { fontFamily: 'monospace', fontSize: '28px', color: this.isReadyToStart ? '#fbbf24' : '#3b82f6', align: 'center', stroke: '#000', strokeThickness: 5 }).setOrigin(0.5);
    this.uiContainer.add([this.comboText, this.infoText]);
    this.tweens.add({ targets: this.infoText, alpha: 0.5, yoyo: true, repeat: -1, duration: 800 });
  }

  repositionUIElements() {
    (this.uiContainer.getByName('progBg') as any).setPosition(this.centerX, 40);
    this.progressBar.setPosition(this.centerX - 150, 40);
    const tX = this.scale.width - 60;
    const tY = this.centerY - 50;
    (this.uiContainer.getByName('tempFrame') as any).setPosition(tX, tY);
    (this.uiContainer.getByName('tempBg') as any).setPosition(tX, tY);
    this.tempBar.setPosition(tX, tY + 125);
    this.tempValueText.setPosition(tX, tY - 160);
    this.bellowsContainer.setPosition(tX, tY + 220);
    this.infoText.setPosition(this.centerX, this.centerY - 220);
    this.comboText.setPosition(this.centerX, this.centerY - 300);
  }

  createBellows() {
    this.bellowsContainer = this.add.container(0, 0);
    const bag = this.add.rectangle(0, 0, 70, 50, 0xa16207).setStrokeStyle(2, 0x451a03);
    const top = this.add.rectangle(0, -25, 75, 14, 0x78350f).setStrokeStyle(2, 0x451a03);
    const bot = this.add.rectangle(0, 25, 75, 14, 0x78350f).setStrokeStyle(2, 0x451a03);
    const txt = this.add.text(0, 55, 'PUMP', { fontSize: '14px', color: '#a8a29e', fontFamily: 'monospace', fontStyle: 'bold' }).setOrigin(0.5);
    this.bellowsContainer.add([bag, top, bot, txt]);
    this.bellowsContainer.setInteractive(new Phaser.Geom.Rectangle(-40, -40, 80, 120), Phaser.Geom.Rectangle.Contains);
    this.uiContainer.add(this.bellowsContainer);
  }

  pumpBellows() {
    if (this.isPumping) return;
    this.isPumping = true;
    this.tweens.add({ targets: this.bellowsContainer, scaleY: 0.7, duration: 80, yoyo: true, onComplete: () => (this.isPumping = false) });
    if (this.temperature > 0) {
      this.temperature = Math.min(100, this.temperature + 8);
      if (!this.isPlaying && !this.isReadyToStart) {
        this.isReadyToStart = true;
        this.infoText.setText('CLICK TO START').setColor('#fbbf24');
      }
    }
  }

  public heatUp() {
    this.temperature = Math.min(100, this.temperature + 40);
    if (!this.isPlaying) {
      this.isReadyToStart = true;
      this.infoText.setText('CLICK TO START').setColor('#fbbf24');
    }
  }

  public getTemperature() { return this.temperature; }

  update(time: number, delta: number) {
    if (this.isFinished) return;
    if (this.isPlaying) this.handleRingLogic(delta);
    this.temperature = Math.max(0, this.temperature - this.coolingRate * (delta / 1000));
    this.refreshVisuals();
    if (!this.isPlaying && this.isReadyToStart && this.temperature <= 0) {
      this.isReadyToStart = false;
      this.infoText.setText('FORGE IS COLD\nADD FUEL TO HEAT').setColor('#3b82f6');
    }
  }

  private setBladeStage(stage: number) {
    const key = `blade_stage_${stage}`;
    if (this.textures.exists(key)) {
      if (!this.bladeImage) {
        this.bladeImage = this.add.image(0, 0, key).setOrigin(0.5);
        this.bladeContainer.add(this.bladeImage);
      } else {
        this.bladeImage.setTexture(key);
      }
      this.bladeImage.setVisible(true);
      this.bladeFallbackRect.setVisible(true).setAlpha(0.15);
    } else {
      if (this.bladeImage) this.bladeImage.setVisible(false);
      this.bladeFallbackRect.setVisible(true).setAlpha(1);
    }
  }

  refreshVisuals() {
    const ratio = this.temperature / 100;
    this.tempBar.scaleY = ratio;
    this.tempValueText.setText(`${Math.floor(20 + ratio * 1480)}°C`);
    const cold = new Phaser.Display.Color(63, 63, 70);
    const hot = new Phaser.Display.Color(253, 230, 138);
    const current = Phaser.Display.Color.Interpolate.ColorWithColor(cold, hot, 100, ratio * 100);
    const color = Phaser.Display.Color.GetColor(current.r, current.g, current.b);
    this.bladeFallbackRect.setFillStyle(color, 1);
    if (this.bladeImage) this.bladeImage.setTint(color);
    const progress = Phaser.Math.Clamp(this.score / this.targetScore, 0, 1);
    const stage = Math.min(5, Math.floor(progress * 6));
    if (stage !== this.lastStage) { this.setBladeStage(stage); this.lastStage = stage; }
    if (this.ambientGlow) this.ambientGlow.setFillStyle(0xea580c, ratio * 0.25);
    if (this.temperature <= 0) this.currentTempStage = 'COLD';
    else if (this.temperature > 75) this.currentTempStage = 'AURA';
    else if (this.temperature > 40) this.currentTempStage = 'HOT';
    else if (this.temperature > 15) this.currentTempStage = 'WARM';
    else this.currentTempStage = 'NORMAL';
  }

  handleRingLogic(delta: number) {
    this.ringTimer += delta;
    const t = Math.min(this.ringTimer / this.shrinkDuration, 1.5);
    this.currentRadius = this.startRadius * (1 - t * t);
    const ringColor = this.currentRadius < this.targetRadius ? 0xffffff : 0xfabf24;
    this.approachRing.clear().lineStyle(8, ringColor, 0.6).strokeCircle(this.hitX, this.hitY, Math.max(0, this.currentRadius));
    if (this.currentRadius < this.targetRadius - 30) { this.combo = 0; this.resetRing(); }
  }

  resetRing() {
    if (this.temperature <= 0) {
      this.isPlaying = false; this.isReadyToStart = false;
      this.targetRing.clear(); this.approachRing.clear();
      this.infoText.setVisible(true).setText('FORGE IS COLD\nADD FUEL TO HEAT').setColor('#3b82f6');
      return;
    }
    this.currentRadius = this.startRadius; this.ringTimer = 0;
    const w = this.hammerHitArea.width * this.hammerHitArea.scaleX;
    const h = this.hammerHitArea.height * this.hammerHitArea.scaleY;
    const u = Phaser.Math.Between(-w * 0.35, w * 0.35);
    const v = Phaser.Math.Between(-h * 0.25, h * 0.25);
    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    this.hitX = this.hammerHitArea.x + (u * Math.cos(rad) - v * Math.sin(rad));
    this.hitY = this.hammerHitArea.y + (u * Math.sin(rad) + v * Math.cos(rad));
    if (this.isPlaying) {
      this.targetRing.clear().fillStyle(0xfabf24, 0.1).fillCircle(this.hitX, this.hitY, this.targetRadius).lineStyle(5, 0xfabf24, 0.4).strokeCircle(this.hitX, this.hitY, this.targetRadius);
    }
  }

  private pulseHitArea(mult: number) {
    this.tweens.add({ targets: this.hammerHitArea, scaleX: mult, scaleY: mult, duration: 70, yoyo: true, onUpdate: () => this.rebuildHitPoly() });
  }

  handleInput(pointer?: Phaser.Input.Pointer) {
    if (this.isFinished) return;
    if (!this.isPlaying) {
      if (this.isReadyToStart) { this.isPlaying = true; this.infoText.setVisible(false); this.resetRing(); this.cameras.main.flash(200); }
      else { this.cameras.main.shake(50, 0.005); this.showFeedback('TOO COLD!', 0x3b82f6, 1.0); }
      return;
    }
    if (this.time.now - this.lastHitTime < this.hitCooldown) return;
    this.lastHitTime = this.time.now;
    const swingX = pointer ? pointer.worldX : this.hitX;
    const swingY = pointer ? pointer.worldY : this.hitY;
    if (this.currentTempStage === 'COLD' || this.currentTempStage === 'NORMAL') { this.showFeedback('TOO COLD!', 0x3b82f6, 1.0); return; }
    const diff = Math.abs(this.currentRadius - this.targetRadius);
    const eff = this.currentTempStage === 'AURA' ? 1.5 : this.currentTempStage === 'HOT' ? 1.0 : 0.5;
    if (diff < 18) { this.score += Math.ceil(15 * eff); this.combo++; this.pulseHitArea(1.12); this.createSparks(40, 0xffaa00, 2.0, 'spark_perfect', swingX, swingY); this.showFeedback('PERFECT!', 0xffb300, 1.5, swingX, swingY); this.cameras.main.shake(200, 0.025); }
    else if (diff < 55) { this.score += Math.ceil(8 * eff); this.combo = 0; this.pulseHitArea(1.06); this.createSparks(20, 0xffffff, 1.3, 'spark_normal', swingX, swingY); this.showFeedback('GOOD', 0xe5e5e5, 1.0, swingX, swingY); }
    else { this.score = Math.max(0, this.score - 5); this.combo = 0; this.pulseHitArea(0.95); this.showFeedback('MISS', 0xef4444, 1.2, swingX, swingY); }
    this.updateProgressBar();
    if (this.score >= this.targetScore) this.winGame(); else this.resetRing();
  }

  private updateProgressBar() { this.progressBar.width = Phaser.Math.Clamp((this.score / this.targetScore) * 300, 0, 300); }

  createSparks(count: number, color: number, scale: number, key: string, x: number, y: number) {
    const emitter = this.add.particles(x, y, this.textures.exists(key) ? key : 'white', { lifespan: 800, speed: { min: 300 * scale, max: 700 * scale }, angle: { min: 230, max: 310 }, scale: { start: 0.7, end: 0 }, gravityY: 1200, blendMode: 'ADD', tint: color });
    emitter.explode(count);
  }

  showFeedback(text: string, color: number, scale: number, x?: number, y?: number) {
    const fx = x ?? this.hitX; const fy = y ?? this.hitY;
    const fb = this.add.text(fx, fy - 140, text, { fontFamily: 'Arial', fontSize: '36px', fontStyle: 'bold', color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setScale(0.5).setAlpha(0).setDepth(25);
    this.tweens.add({ targets: fb, y: fy - 200, alpha: 1, scale: scale, duration: 250, hold: 400, yoyo: true, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, scale: { from: 1.5, to: 1 }, duration: 200, alpha: { from: 1, to: 0 }, delay: 500 }); }
  }

  winGame() {
    this.isFinished = true; this.isPlaying = false; this.targetRing.clear(); this.approachRing.clear();
    if (this.onStatusUpdate) this.onStatusUpdate(this.temperature);
    const bg = this.add.rectangle(this.centerX, this.centerY, this.scale.width, this.scale.height, 0x000000, 0.85).setAlpha(0).setDepth(100);
    this.tweens.add({ targets: bg, alpha: 1, duration: 500 });
    const txt = this.add.text(this.centerX, this.centerY, 'BLADE FORGED!', { fontFamily: 'Georgia', fontSize: '72px', color: '#fbbf24', stroke: '#000', strokeThickness: 3 }).setOrigin(0.5).setAlpha(0).setDepth(101);
    this.tweens.add({ targets: txt, alpha: 1, scale: { from: 0.5, to: 1.2 }, duration: 600, ease: 'Back.out', onComplete: () => { this.time.delayedCall(1000, () => { if (this.onComplete) this.onComplete(100); }); } });
  }
}

const SmithingMinigame: React.FC<SmithingMinigameProps> = ({ onComplete, onClose, difficulty = 1 }) => {
