export const handleEquipItem = (state: GameState, payload: { mercenaryId: string; inventoryItemId: string }): GameState => {
    const { mercenaryId, inventoryItemId } = payload;

    const mercIndex = state.knownMercenaries.findIndex(m => m.id === mercenaryId);
    if (mercIndex === -1) return state;
    const mercenary = { ...state.knownMercenaries[mercIndex] };
    const newEquipment = { ...mercenary.equipment };

    const invItemIndex = state.inventory.findIndex(i => i.id === inventoryItemId);
    if (invItemIndex === -1) return state;
    const invItem = state.inventory[invItemIndex];

    if (invItem.type !== 'EQUIPMENT' || !invItem.equipmentData) return state;

    const equipData: Equipment = { ...invItem.equipmentData };
    const targetSlot: EquipmentSlotType = equipData.slotType;

    let newInventory = [...state.inventory];
    let itemsReturnedToInventory: Equipment[] = [];

    // 장착 슬롯 스왑 로직
    if (targetSlot === 'MAIN_HAND') {
        if (equipData.isTwoHanded) {
            if (newEquipment.OFF_HAND) {
                itemsReturnedToInventory.push(newEquipment.OFF_HAND);
                newEquipment.OFF_HAND = null;
            }
        }
        if (newEquipment.MAIN_HAND) {
            itemsReturnedToInventory.push(newEquipment.MAIN_HAND);
        }
        newEquipment.MAIN_HAND = equipData;
    }
    else if (targetSlot === 'OFF_HAND') {
        if (newEquipment.MAIN_HAND && newEquipment.MAIN_HAND.isTwoHanded) {
             itemsReturnedToInventory.push(newEquipment.MAIN_HAND);
             newEquipment.MAIN_HAND = null;
        }
        if (newEquipment.OFF_HAND) {
            itemsReturnedToInventory.push(newEquipment.OFF_HAND);
        }
        newEquipment.OFF_HAND = equipData;
    }
    else {
        if (newEquipment[targetSlot]) {
            itemsReturnedToInventory.push(newEquipment[targetSlot]!);
        }
        newEquipment[targetSlot] = equipData;
    }

    newInventory.splice(invItemIndex, 1);

    itemsReturnedToInventory.forEach(returnedItem => {
        newInventory.push({
            id: returnedItem.id,
            name: returnedItem.name,
            type: 'EQUIPMENT',
            description: returnedItem.description || 'Returned equipment',
            baseValue: returnedItem.price,
            icon: returnedItem.icon || '📦',
            quantity: 1,
            equipmentData: returnedItem
        });
    });

    // 호감도 상승 로직 (최초 소유 시에만 적용)
    const previousOwners = equipData.previousOwners || [];
    let affinityGain = 0;
    let logMessage = `Equipped ${equipData.name} to ${mercenary.name}.`;

    if (!previousOwners.includes(mercenaryId)) {
        switch (equipData.rarity) {
            case 'Legendary': affinityGain = 5; break;
            case 'Epic': affinityGain = 4; break;
            case 'Rare': affinityGain = 3; break;
            case 'Uncommon': affinityGain = 2; break;
            case 'Common': affinityGain = 1; break;
            default: affinityGain = 1;
        }

        mercenary.affinity = Math.min(100, (mercenary.affinity || 0) + affinityGain);
        equipData.previousOwners = [...previousOwners, mercenaryId];
        logMessage += ` Affinity +${affinityGain}.`;
    }

    const newMercenaries = [...state.knownMercenaries];
    newMercenaries[mercIndex] = { ...mercenary, equipment: newEquipment };

    return {
        ...state,
        inventory: newInventory,
        knownMercenaries: newMercenaries,
        logs: [logMessage, ...state.logs]
    };
};

export const handleUnequipItem = (state: GameState, payload: { mercenaryId: string; slot: EquipmentSlotType }): GameState => {
    const { mercenaryId, slot } = payload;

    const mercIndex = state.knownMercenaries.findIndex(m => m.id === mercenaryId);
    if (mercIndex === -1) return state;
    const mercenary = { ...state.knownMercenaries[mercIndex] };
    const newEquipment = { ...mercenary.equipment };

    const itemToUnequip = newEquipment[slot];
    if (!itemToUnequip) return state;

    const newInventory = [...state.inventory];
    newInventory.push({
        id: itemToUnequip.id,
        name: itemToUnequip.name,
        type: 'EQUIPMENT',
        description: itemToUnequip.description || 'Unequipped item',
        baseValue: itemToUnequip.price,
        icon: itemToUnequip.icon || '📦',
        quantity: 1,
        equipmentData: itemToUnequip
    });

    newEquipment[slot] = null;

    const newMercenaries = [...state.knownMercenaries];
    newMercenaries[mercIndex] = { ...mercenary, equipment: newEquipment };

    return {
        ...state,
        inventory: newInventory,
        knownMercenaries: newMercenaries,
        logs: [`Unequipped ${itemToUnequip.name} from ${mercenary.name}.`, ...state.logs]
    };
};

import { Mercenary, Gender } from '../models/Mercenary';
import { NAMED_MERCENARIES } from '../data/mercenaries';
import { JobClass, JOB_STAT_WEIGHTS } from '../models/JobClass';
import { calculateMaxHp, calculateMaxMp, PrimaryStats, mergePrimaryStats } from '../models/Stats';
import { generateFullName } from './nameGenerator';
import { DUNGEON_CONFIG } from '../config/dungeon-config';
import { Equipment, EquipmentSlotType } from '../models/Equipment';

const distributeRandomPoints = (weights: PrimaryStats, points: number): PrimaryStats => {
    const stats = { str: 0, vit: 0, dex: 0, int: 0, luk: 0 };
    const totalWeight = weights.str + weights.vit + weights.dex + weights.int + weights.luk;

    if (totalWeight === 0) return stats;

    let remaining = points;
    const keys = ['str', 'vit', 'dex', 'int', 'luk'] as const;

    while (remaining > 0) {
        const rand = Math.random() * totalWeight;
        let cumulative = 0;
        for (const key of keys) {
            cumulative += weights[key];
            if (rand <= cumulative) {
                stats[key]++;
                remaining--;
                break;
            }
        }
    }
    return stats;
};

const generateBaseStats = (job: JobClass): PrimaryStats => {
    const weights = JOB_STAT_WEIGHTS[job];
    // Base stats at level 1: 5-8 points distributed randomly using weights
    const baseTotal = 20 + Math.floor(Math.random() * 5);
    return distributeRandomPoints(weights, baseTotal);
};

const defaultEquipment: Record<EquipmentSlotType, Equipment | null> = {
    MAIN_HAND: null,
    OFF_HAND: null,
    HEAD: null,
    BODY: null,
    HANDS: null,
    FEET: null,
    ACCESSORY: null
};

const calculateLevelDataFromTotalXp = (totalXp: number) => {
    let level = 1;
    let xpToNext = 100;
    let remainingXp = totalXp;

    while (remainingXp >= xpToNext) {
        remainingXp -= xpToNext;
        level++;
        xpToNext = level * 100;
    }

    return {
        level,
        currentXp: remainingXp,
        xpToNextLevel: xpToNext
    };
};

export const createRandomMercenary = (currentDay: number): Mercenary => {
    const jobKeys = Object.values(JobClass);
    const job = jobKeys[Math.floor(Math.random() * jobKeys.length)];

    const randomFactor = Math.random(); 
    const totalXp = Math.floor(Math.pow(randomFactor, 2) * 2500); 

    const { level, currentXp, xpToNextLevel } = calculateLevelDataFromTotalXp(totalXp);

    const baseStats = generateBaseStats(job);
    // Level up points: (level - 1) * 3
    const bonusPoints = (level - 1) * 3;
    const allocatedStats = distributeRandomPoints(JOB_STAT_WEIGHTS[job], bonusPoints);

    const merged = mergePrimaryStats(baseStats, allocatedStats);
    const maxHp = calculateMaxHp(merged, level);
    const maxMp = calculateMaxMp(merged, level);

    const gender: Gender = Math.random() < 0.5 ? 'Male' : 'Female';
    const fullName = generateFullName(gender, job);

    return {
        id: `rnd_${Date.now()}_${Math.floor(Math.random() * 1000)}`,
        name: fullName,
        gender: gender,
        job: job,
        level: level,
        stats: baseStats,
        allocatedStats: allocatedStats,
        currentHp: maxHp,
        maxHp: maxHp,
        currentMp: maxMp,
        maxMp: maxMp,
        affinity: 0,
        visitCount: 1,
        isUnique: false,
        lastVisitDay: currentDay,
        icon: '👤',
        expeditionEnergy: DUNGEON_CONFIG.MAX_EXPEDITION_ENERGY,
        currentXp: currentXp,
        xpToNextLevel: xpToNextLevel,
        status: 'VISITOR',
        equipment: { ...defaultEquipment }
    };
};

// Added missing export required by TavernTab.tsx
export const getUnmetNamedMercenary = (knownMercenaries: Mercenary[]): Mercenary | null => {
    const unknownNamed = NAMED_MERCENARIES.filter(
        named => !knownMercenaries.some(known => known.id === named.id)
    );
    if (unknownNamed.length === 0) return null;
    return unknownNamed[Math.floor(Math.random() * unknownNamed.length)];
};

export const generateMercenary = (knownMercenaries: Mercenary[], currentDay: number): Mercenary => {
    const rand = Math.random();

    if (knownMercenaries.length > 0 && rand < 0.3) {
        const potentialRegulars = knownMercenaries.filter(m => m.lastVisitDay !== currentDay);
        if (potentialRegulars.length > 0) {
            const regular = potentialRegulars[Math.floor(Math.random() * potentialRegulars.length)];
            const merged = mergePrimaryStats(regular.stats, regular.allocatedStats);
            const maxHp = calculateMaxHp(merged, regular.level);
            const maxMp = calculateMaxMp(merged, regular.level);
            return { 
                ...regular,
                currentHp: maxHp,
                currentMp: maxMp,
                maxHp,
                maxMp,
                expeditionEnergy: regular.expeditionEnergy ?? DUNGEON_CONFIG.MAX_EXPEDITION_ENERGY,
                currentXp: regular.currentXp ?? 0,
                xpToNextLevel: regular.xpToNextLevel ?? (regular.level * 100),
                equipment: regular.equipment || { ...defaultEquipment }
            }; 
        }
    }

    if (rand < 0.5) {
        const unknownNamed = NAMED_MERCENARIES.filter(
            named => !knownMercenaries.some(known => known.id === named.id)
        );
        if (unknownNamed.length > 0) {
            const merc = unknownNamed[Math.floor(Math.random() * unknownNamed.length)];
            return {
                ...merc,
                visitCount: 1, 
                lastVisitDay: currentDay
            } as Mercenary;
        }
    }

    return createRandomMercenary(currentDay);
};

