                            {currentSelectedItem.type === 'CONSUMABLE' && <button onClick={handleConsume} className="w-full py-3 bg-emerald-800 hover:bg-emerald-700 border border-emerald-600 text-emerald-100 rounded-lg transition-all flex items-center justify-center gap-2 group shadow-lg"><Zap className="w-4 h-4 text-emerald-300 group-hover:scale-110" /><span className="font-bold">Consume Item</span></button>}
                            {currentSelectedItem.baseValue > 0 && currentSelectedItem.type !== 'KEY_ITEM' && currentSelectedItem.type !== 'TOOL' ? (
                                <div className="bg-stone-900 p-4 rounded-lg border border-stone-800 shadow-inner">
                                    <div className="flex justify-between items-center mb-3"><span className="text-stone-400 text-xs font-bold uppercase">Market Value</span><span className="text-amber-500 font-mono font-bold">{currentSelectedItem.baseValue} G</span></div>
                                    <button onClick={handleQuickSell} className="w-full py-3 bg-stone-800 hover:bg-red-900/30 border border-stone-700 hover:border-red-800 text-stone-300 hover:text-red-400 rounded-lg transition-all flex items-center justify-center gap-2"><Coins className="w-4 h-4 text-amber-500" /><span className="font-bold text-sm uppercase">Quick Sell ({Math.floor(currentSelectedItem.baseValue * 0.5)} G)</span></button>
                                </div>
                            ) : <div className="p-4 text-center text-stone-600 text-xs border border-dashed border-stone-800 rounded-lg uppercase font-bold tracking-widest">Permanent Item</div>}
                        </div>
                    </div>
                ) : (
                    <div className="flex-1 flex flex-col items-center justify-center text-stone-600 p-6 text-center"><div className="w-20 h-20 bg-stone-900/50 rounded-full flex items-center justify-center mb-4"><Info className="w-8 h-8 opacity-30" /></div><p className="text-lg font-medium text-stone-500">Select an item</p></div>
                )}
            </div>
        </div>
    );
};

import React, { useState, useMemo, useEffect, useCallback } from 'react';
import { useGame } from '../../context/GameContext';
import { Mercenary } from '../../models/Mercenary';
import { EquipmentSlotType } from '../../types/inventory';
import { X, Sword, Shield, Shirt, Hand, Footprints, Crown, Sparkles, Heart, Activity, Star, Box, MousePointer2, Zap, Brain, Target, Gem, User, ArrowRight, ChevronRight, Plus, Wind, FastForward, Crosshair, Minus, Check, RefreshCw, AlertCircle, ShieldAlert } from 'lucide-react';
import { getAssetUrl } from '../../utils';
import { calculateDerivedStats, applyEquipmentBonuses, DerivedStats, PrimaryStats, mergePrimaryStats } from '../../models/Stats';
import { calculateCombatPower } from '../../utils/combatLogic';
import { InventoryItem } from '../../types/inventory';
import { Equipment } from '../../models/Equipment';

interface MercenaryDetailModalProps {
    mercenary: Mercenary | null;
    onClose: () => void;
    onUnequip: (mercId: string, slot: EquipmentSlotType) => void;
}

const MercenaryPaperDoll = ({ 
    mercenary, 
    combatPower, 
    showAffinityGain, 
    onUnequip, 
    onSlotClick,
    selectedSlot,
}: { 
    mercenary: Mercenary; 
    combatPower: number; 
    showAffinityGain: boolean; 
    onUnequip: (slot: EquipmentSlotType) => void; 
    onSlotClick: (slot: EquipmentSlotType | null) => void;
    selectedSlot: EquipmentSlotType | null;
}) => {
    const renderSlot = ({ slot, icon, style }: { slot: EquipmentSlotType; icon: React.ReactNode; style: string }) => {
        const equippedItem = mercenary.equipment[slot];
        const isSelected = selectedSlot === slot;

        let borderColor = isSelected ? 'border-amber-400' : 'border-stone-700';
        let bgColor = 'bg-stone-900/80';

        if (equippedItem) {
            switch (equippedItem.rarity) {
                case 'Common': borderColor = isSelected ? 'border-amber-400' : 'border-stone-500'; break;
                case 'Uncommon': borderColor = isSelected ? 'border-amber-400' : 'border-emerald-600'; break;
                case 'Rare': borderColor = isSelected ? 'border-amber-400' : 'border-blue-500'; break;
                case 'Epic': borderColor = isSelected ? 'border-amber-400' : 'border-purple-500'; break;
                case 'Legendary': borderColor = isSelected ? 'border-amber-400' : 'border-amber-500'; break;
            }
            bgColor = 'bg-stone-800';
        }

        let imageUrl = '';
        if (equippedItem) {
            imageUrl = equippedItem.recipeId ? getAssetUrl(`${equippedItem.recipeId}.png`) : getAssetUrl(`${equippedItem.id.split('_')[0]}.png`);
        }

        return (
            <div 
                className={`absolute w-12 h-12 rounded-lg border-2 ${borderColor} ${bgColor} flex items-center justify-center shadow-lg transition-all z-20 group ${style} ${isSelected ? 'ring-2 ring-amber-500/50 scale-110' : ''} cursor-pointer`}
                onClick={() => onSlotClick(isSelected ? null : slot)}
            >
                {equippedItem ? (
                    <img 
                        src={imageUrl}
                        className="w-9 h-9 object-contain drop-shadow-md"
                        onError={(e) => { e.currentTarget.style.display = 'none'; e.currentTarget.nextElementSibling?.classList.remove('hidden'); }}
                    />
                ) : (
                    <div className="text-stone-600">{icon}</div>
                )}
                <div className="hidden text-xl">{equippedItem?.icon || '📦'}</div>
                {equippedItem && (
                    <button
                        onClick={(e) => { e.stopPropagation(); onUnequip(slot); }}
                        className="absolute -top-2 -right-2 bg-stone-900 rounded-full border border-stone-600 p-0.5 opacity-0 group-hover:opacity-100 transition-opacity hover:bg-red-900 hover:border-red-500 text-stone-400 hover:text-red-200 z-30"
                    >
                        <X className="w-3 h-3" />
                    </button>
                )}
            </div>
        );
    };

    return (
        <div className="w-full md:w-[40%] relative bg-gradient-to-b from-stone-900 to-stone-950 border-r border-stone-800 flex flex-col items-center justify-center overflow-hidden group select-none">
            <div className="absolute top-8 left-8 z-30">
                <h2 className="text-4xl font-black text-stone-200 font-serif tracking-tight drop-shadow-lg leading-none">{mercenary.name}</h2>
                <div className="flex items-center gap-3 mt-2">
                    <span className="text-sm font-bold text-amber-500 uppercase tracking-widest bg-amber-950/30 px-2 py-0.5 rounded border border-amber-900/50">{mercenary.job}</span>
                    <div className={`flex items-center gap-1 text-sm ${showAffinityGain ? 'text-pink-400 animate-pulse' : 'text-stone-500'}`}>
                        <Heart className={`w-3.5 h-3.5 ${showAffinityGain ? 'fill-pink-500' : ''}`} />
                        <span className="font-mono font-bold">{mercenary.affinity}</span>
                    </div>
                </div>
            </div>
            <div className="absolute top-8 right-8 z-30">
                <div className="flex flex-col items-end">
                    <span className="text-[10px] text-stone-500 uppercase font-bold tracking-wider">Combat Power</span>
                    <div className="flex items-center gap-1 text-xl font-mono font-bold text-stone-300">
                        <Star className="w-4 h-4 text-yellow-500 fill-yellow-500" />
                        {combatPower}
                    </div>
                </div>
            </div>
            <div className="relative w-full h-full flex items-center justify-center mt-12">
                <div className="relative h-[80%] w-full flex items-center justify-center">
                    <img 
                        src={mercenary.sprite ? getAssetUrl(mercenary.sprite) : getAssetUrl('adventurer_wanderer_01.png')}
                        className="h-full object-contain filter drop-shadow-[0_0_20px_rgba(0,0,0,0.8)]"
                    />
                    <div className="absolute inset-0 flex items-center justify-center opacity-10 pointer-events-none -z-10">
                        <User className="w-64 h-64 text-stone-500" />
                    </div>
                </div>
                {renderSlot({ slot: "HEAD", icon: <Crown className="w-6 h-6" />, style: "top-[10%] left-1/2 -translate-x-1/2" })}
                {renderSlot({ slot: "BODY", icon: <Shirt className="w-6 h-6" />, style: "top-[35%] left-1/2 -translate-x-1/2" })}
                {renderSlot({ slot: "HANDS", icon: <Hand className="w-6 h-6" />, style: "top-[35%] left-[20%]" })}
                {renderSlot({ slot: "ACCESSORY", icon: <Sparkles className="w-6 h-6" />, style: "top-[35%] right-[20%]" })}
                {renderSlot({ slot: "MAIN_HAND", icon: <Sword className="w-6 h-6" />, style: "top-[55%] left-[15%]" })}
                {renderSlot({ slot: "OFF_HAND", icon: <Shield className="w-6 h-6" />, style: "top-[55%] right-[15%]" })}
                {renderSlot({ slot: "FEET", icon: <Footprints className="w-6 h-6" />, style: "bottom-[10%] left-1/2 -translate-x-1/2" })}
            </div>
        </div>
    );
};

const MercenaryStatsPanel = ({ 
    mercenary, 
    finalStats, 
    localAllocated, 
    onSetLocalAllocated 
}: { 
    mercenary: Mercenary; 
    finalStats: DerivedStats; 
    localAllocated: PrimaryStats;
    onSetLocalAllocated: (stats: PrimaryStats) => void;
}) => {
    const { actions } = useGame();

    const xpPercent = mercenary.xpToNextLevel > 0 ? Math.min(100, Math.max(0, (mercenary.currentXp / mercenary.xpToNextLevel) * 100)) : 0;
    const hpPercent = finalStats.maxHp > 0 ? (mercenary.currentHp / finalStats.maxHp) * 100 : 0;
    const mpPercent = finalStats.maxMp > 0 ? (mercenary.currentMp / finalStats.maxMp) * 100 : 0;

    const totalUsedLocal = Object.values(localAllocated).reduce((a, b) => a + b, 0);
    const totalPoints = (mercenary.level - 1) * 3;
    const availablePoints = Math.max(0, totalPoints - totalUsedLocal);

    const hasChanges = JSON.stringify(localAllocated) !== JSON.stringify(mercenary.allocatedStats);

    const renderStatRow = (icon: React.ReactNode, label: string, value: number | string, isPercent = false) => (
        <div className="bg-stone-800/50 p-2 rounded-lg border border-stone-800 flex justify-between items-center h-9">
            <span className="text-[10px] text-stone-400 font-bold flex items-center gap-1.5">{icon} {label}</span>
            <span className="font-mono text-sm font-bold text-stone-200">
                {value}{isPercent ? '%' : ''}
            </span>
        </div>
    );

    const updateLocalStat = (key: keyof PrimaryStats, delta: number) => {
        const newVal = localAllocated[key] + delta;
        if (delta > 0 && availablePoints <= 0) return;
        if (delta < 0 && newVal < mercenary.allocatedStats[key]) return;

        onSetLocalAllocated({
            ...localAllocated,
            [key]: newVal
        });
    };

    const handleApply = () => {
        actions.updateMercenaryStats(mercenary.id, localAllocated);
    };

    const handleReset = () => {
        onSetLocalAllocated({ ...mercenary.allocatedStats });
    };

    return (
        <div className="p-5 flex flex-col gap-4 overflow-y-auto shrink-0 border-b border-stone-800 custom-scrollbar max-h-[60%]">
            <div className="bg-stone-800/50 p-3 rounded-xl border border-stone-800 shadow-sm shrink-0">
                <div className="flex justify-between items-end mb-1.5">
                    <span className="text-amber-500 font-bold font-mono text-base">LEVEL {mercenary.level}</span>
                    <span className="text-stone-500 text-xs font-mono">{mercenary.currentXp} / {mercenary.xpToNextLevel} XP</span>
                </div>
                <div className="w-full h-2.5 bg-stone-950 rounded-full overflow-hidden border border-stone-800">
                    <div className="h-full bg-amber-600 shadow-[0_0_10px_rgba(217,119,6,0.5)] transition-all duration-500 ease-out" style={{ width: `${xpPercent}%` }}></div>
                </div>
            </div>

            <div className="bg-stone-950/30 rounded-xl border border-stone-800/50 p-3">
                <div className="flex justify-between items-center mb-3">
                    <h4 className="text-[10px] font-bold text-stone-500 uppercase tracking-widest flex items-center gap-2"><Star className="w-3 h-3" /> Attributes</h4>
                    <div className="flex items-center gap-1.5">
                        {availablePoints > 0 ? (
                             <span className="text-[10px] font-black text-amber-500 animate-pulse">+{availablePoints} POINTS AVAILABLE</span>
                        ) : (
                             <span className="text-[10px] font-bold text-stone-600 uppercase">Points Exhausted</span>
                        )}
                    </div>
                </div>
                <div className="grid grid-cols-5 gap-2">
                    {[
                        { label: 'STR', key: 'str' as const, color: 'text-orange-400' },
                        { label: 'INT', key: 'int' as const, color: 'text-blue-400' },
                        { label: 'DEX', key: 'dex' as const, color: 'text-emerald-400' },
                        { label: 'VIT', key: 'vit' as const, color: 'text-red-400' },
                        { label: 'LUK', key: 'luk' as const, color: 'text-pink-400' }
                    ].map((stat) => {
                        const committedValue = mercenary.stats[stat.key] + mercenary.allocatedStats[stat.key];
                        const currentValue = mercenary.stats[stat.key] + localAllocated[stat.key];
                        const isModified = localAllocated[stat.key] > mercenary.allocatedStats[stat.key];

                        return (
                            <div key={stat.key} className="flex flex-col gap-1">
                                <div className={`bg-stone-800 border ${isModified ? 'border-amber-500/50' : 'border-stone-700'} p-1.5 rounded-lg flex flex-col items-center justify-center relative transition-colors`}>
                                    <span className={`text-[9px] font-bold ${stat.color}`}>{stat.label}</span>
                                    <span className={`text-sm font-mono font-bold ${isModified ? 'text-amber-400 scale-110' : 'text-stone-200'} transition-all`}>{currentValue}</span>
                                </div>
                                <div className="flex gap-1">
                                    <button 
                                        onClick={() => updateLocalStat(stat.key, -1)}
                                        disabled={localAllocated[stat.key] <= mercenary.allocatedStats[stat.key]}
                                        className="flex-1 h-6 bg-stone-800 hover:bg-stone-700 border border-stone-700 rounded flex items-center justify-center text-stone-500 hover:text-red-400 transition-all disabled:opacity-30 disabled:pointer-events-none"
                                    >
                                        <Minus className="w-3 h-3" />
                                    </button>
                                    <button 
                                        onClick={() => updateLocalStat(stat.key, 1)}
                                        disabled={availablePoints <= 0}
                                        className="flex-1 h-6 bg-stone-800 hover:bg-amber-900/40 border border-stone-700 hover:border-amber-600/50 rounded flex items-center justify-center text-stone-500 hover:text-amber-400 transition-all disabled:opacity-30 disabled:pointer-events-none"
                                    >
                                        <Plus className="w-3 h-3" />
                                    </button>
                                </div>
                            </div>
                        );
                    })}
                </div>

                {hasChanges && (
                    <div className="mt-4 flex gap-2 animate-in slide-in-from-top-2 duration-300">
                         <button 
                            onClick={handleReset}
                            className="flex-1 py-2 bg-stone-800 hover:bg-stone-700 text-stone-400 hover:text-stone-200 text-xs font-bold rounded-lg border border-stone-700 transition-all flex items-center justify-center gap-2"
                        >
                            <RefreshCw className="w-3 h-3" /> Reset
                        </button>
                        <button 
                            onClick={handleApply}
                            className="flex-[2] py-2 bg-amber-700 hover:bg-amber-600 text-amber-50 text-xs font-bold rounded-lg shadow-lg border border-amber-500 transition-all flex items-center justify-center gap-2"
                        >
                            <Check className="w-3 h-3" /> Apply Changes
                        </button>
                    </div>
                )}
            </div>

            <div className="grid grid-cols-2 gap-3 shrink-0">
                <div className="bg-stone-800/50 p-2.5 rounded-xl border border-stone-800 flex items-center gap-3">
                    <div className="p-1.5 bg-red-900/20 rounded-lg text-red-500 border border-red-900/30"><Heart className="w-4 h-4" /></div>
                    <div className="flex-1">
                        <div className="flex justify-between text-[10px] text-stone-400 font-bold mb-1">
                            <span>HEALTH</span><span className="text-stone-200">{mercenary.currentHp} / {finalStats.maxHp}</span>
                        </div>
                        <div className="w-full h-1 bg-stone-950 rounded-full overflow-hidden">
                            <div className="h-full bg-red-600 transition-all duration-500" style={{ width: `${hpPercent}%` }}></div>
                        </div>
                    </div>
                </div>
                <div className="bg-stone-800/50 p-2.5 rounded-xl border border-stone-800 flex items-center gap-3">
                    <div className="p-1.5 bg-blue-900/20 rounded-lg text-blue-500 border border-blue-900/30"><Activity className="w-4 h-4" /></div>
                    <div className="flex-1">
                        <div className="flex justify-between text-[10px] text-stone-400 font-bold mb-1">
                            <span>MANA</span><span className="text-stone-200">{mercenary.currentMp} / {finalStats.maxMp}</span>
                        </div>
                        <div className="w-full h-1 bg-stone-950 rounded-full overflow-hidden">
                            <div className="h-full bg-blue-600 transition-all duration-500" style={{ width: `${mpPercent}%` }}></div>
                        </div>
                    </div>
                </div>
            </div>

            <div className="shrink-0">
                <h4 className="text-[10px] font-bold text-stone-500 uppercase tracking-widest mb-2 flex items-center gap-2"><Sword className="w-3 h-3" /> Combat Statistics</h4>
                <div className="grid grid-cols-2 gap-2">
                    {renderStatRow(<Sword className="w-3 h-3" />, 'P.ATK', finalStats.physicalAttack)}
                    {renderStatRow(<Shield className="w-3 h-3" />, 'P.DEF', finalStats.physicalDefense)}
                    {renderStatRow(<Zap className="w-3 h-3" />, 'M.ATK', finalStats.magicalAttack)}
                    {renderStatRow(<Brain className="w-3 h-3" />, 'M.DEF', finalStats.magicalDefense)}
                    {renderStatRow(<Crosshair className="w-3 h-3" />, 'ACC', finalStats.accuracy)}
                    {renderStatRow(<Wind className="w-3 h-3" />, 'EVA', finalStats.evasion)}
                    {renderStatRow(<Target className="w-3 h-3" />, 'CRIT', `${finalStats.critChance}%`, true)}
                    {renderStatRow(<FastForward className="w-3 h-3" />, 'SPD', finalStats.speed)}
                </div>
            </div>
        </div>
    );
};

const EquipmentInventoryList = ({ 
    inventory, 
    selectedItemId,
    onSelect,
    onEquip,
    selectedSlotFilter,
    mercenary
}: { 
    inventory: InventoryItem[]; 
    selectedItemId: string | null;
    onSelect: (itemId: string) => void;
    onEquip: (itemId: string) => void;
    selectedSlotFilter: EquipmentSlotType | null;
    mercenary: Mercenary;
}) => {
    const totalMercStats = useMemo(() => mergePrimaryStats(mercenary.stats, mercenary.allocatedStats), [mercenary]);

    const displayInventory = useMemo(() => {
        let items = selectedSlotFilter 
            ? inventory.filter(item => item.equipmentData?.slotType === selectedSlotFilter)
            : inventory;
        return items;
    }, [inventory, selectedSlotFilter]);

    return (
        <div className="bg-stone-950 p-4 flex-1 flex flex-col min-h-0">
            <div className="flex justify-between items-center mb-3 shrink-0">
                <h3 className="text-xs font-bold text-stone-400 uppercase tracking-wider flex items-center gap-2">
                    <Box className="w-4 h-4 text-amber-600" /> 
                    {selectedSlotFilter ? `${selectedSlotFilter.replace('_', ' ')} Storage` : 'Equipment Storage'}
                </h3>
                <span className="text-[10px] text-stone-600 font-mono">{displayInventory.length} Items</span>
            </div>
            <div className="flex-1 overflow-y-auto custom-scrollbar pr-1">
                {displayInventory.length === 0 ? (
                    <div className="h-full flex items-center justify-center border-2 border-dashed border-stone-800 rounded-lg text-stone-600 text-sm italic">
                        {selectedSlotFilter ? 'No matching equipment.' : 'No equipment available.'}
                    </div>
                ) : (
                    <div className="grid grid-cols-1 gap-2 content-start">
                        {displayInventory.map(item => {
                            if (!item.equipmentData) return null;
                            const isSelected = selectedItemId === item.id;
                            const reqs = item.equipmentData.equipRequirements || {};

                            const failedStats = Object.entries(reqs).filter(([stat, val]) => 
                                totalMercStats[stat as keyof PrimaryStats] < (val as number)
                            );
                            const canEquip = failedStats.length === 0;

                            let rarityColor = item.equipmentData.quality >= 90 ? 'text-purple-400' : item.equipmentData.quality >= 75 ? 'text-blue-400' : item.equipmentData.quality >= 50 ? 'text-emerald-400' : 'text-stone-400';
                            let imageUrl = item.equipmentData.recipeId ? getAssetUrl(`${item.equipmentData.recipeId}.png`) : getAssetUrl(`${item.id.split('_')[0]}.png`);

                            return (
                                <div 
                                    key={item.id}
                                    onClick={() => !isSelected && onSelect(item.id)}
                                    className={`flex flex-col gap-2 p-3 rounded-lg border transition-all ${isSelected ? 'border-amber-500 bg-stone-800' : 'border-stone-800 hover:bg-stone-900'} cursor-pointer group ${!canEquip ? 'opacity-80' : ''}`}
                                >
                                    <div className="flex items-center gap-3">
                                        <div className="w-10 h-10 bg-stone-900 rounded border border-stone-700 flex items-center justify-center relative shrink-0">
                                            <img src={imageUrl} className="w-8 h-8 object-contain" onError={(e) => { e.currentTarget.style.display = 'none'; e.currentTarget.nextElementSibling?.classList.remove('hidden'); }} />
                                            <div className="hidden text-xl">{item.icon || '📦'}</div>
                                        </div>
                                        <div className="flex-1 min-w-0">
                                            <div className="text-sm font-bold truncate text-stone-300">{item.name}</div>
                                            <div className="flex items-center gap-2 text-[10px]">
                                                <span className="text-stone-500 uppercase">{item.equipmentData.slotType.replace('_', ' ')}</span>
                                                <span className={rarityColor}>Quality {item.equipmentData.quality}</span>
                                            </div>
                                        </div>
                                        {isSelected && canEquip && (
                                            <button 
                                                onClick={(e) => { e.stopPropagation(); onEquip(item.id); }}
                                                className="shrink-0 px-3 py-1 bg-amber-700 hover:bg-amber-600 text-white text-[10px] font-bold uppercase rounded-md shadow-lg animate-in fade-in zoom-in duration-200"
                                            >
                                                Equip
                                            </button>
                                        )}
                                    </div>

                                    {/* Additional Info: Durability & Requirements */}
                                    <div className="flex justify-between items-end border-t border-stone-700/50 pt-2">
                                        <div className="flex items-center gap-2">
                                            <div className="flex items-center gap-1 text-[9px] text-stone-500 font-bold" title="Durability">
                                                <ShieldAlert className="w-2.5 h-2.5" />
                                                {item.equipmentData.durability}/{item.equipmentData.maxDurability}
                                            </div>
                                            {!item.equipmentData.isRepairable && <span className="text-[8px] bg-stone-800 text-stone-600 px-1 rounded font-bold uppercase tracking-tighter">Disposable</span>}
                                        </div>

                                        {Object.keys(reqs).length > 0 && (
                                            <div className="flex flex-wrap gap-1 justify-end max-w-[150px]">
                                                {Object.entries(reqs).map(([stat, val]) => {
                                                    const met = totalMercStats[stat as keyof PrimaryStats] >= (val as number);
                                                    return (
                                                        <span key={stat} className={`text-[8px] px-1 rounded font-bold uppercase ${met ? 'text-stone-500 border border-stone-800' : 'text-red-400 border border-red-900/30 bg-red-950/20'}`}>
                                                            {stat} {val}
                                                        </span>
                                                    );
                                                })}
                                            </div>
                                        )}
                                    </div>

                                    {!canEquip && isSelected && (
                                        <div className="mt-1 text-[9px] text-red-500 font-bold bg-red-950/30 p-1.5 rounded border border-red-900/30 flex items-center gap-1.5 animate-in slide-in-from-top-1 duration-200">
                                            <AlertCircle className="w-3 h-3" /> Requirements not met.
                                        </div>
                                    )}
                                </div>
                            );
                        })}
                    </div>
                )}
            </div>
        </div>
    );
};

const MercenaryDetailModal: React.FC<MercenaryDetailModalProps> = ({ mercenary, onClose, onUnequip }) => {
    const { state, actions } = useGame();

    const [selectedSlot, setSelectedSlot] = useState<EquipmentSlotType | null>(null);
    const [selectedInventoryItemId, setSelectedInventoryItemId] = useState<string | null>(null);
    const [prevAffinity, setPrevAffinity] = useState(0);
    const [showAffinityGain, setShowAffinityGain] = useState(false);

    const [localAllocated, setLocalAllocated] = useState<PrimaryStats>({ str: 0, vit: 0, dex: 0, int: 0, luk: 0 });

    useEffect(() => {
        if (mercenary) {
            setPrevAffinity(mercenary.affinity);
            setSelectedSlot(null);
            setSelectedInventoryItemId(null);
            setLocalAllocated({ ...mercenary.allocatedStats });
        }
    }, [mercenary?.id]);

    useEffect(() => {
        if (mercenary && mercenary.affinity > prevAffinity) {
            setShowAffinityGain(true);
            const timer = setTimeout(() => setShowAffinityGain(false), 3000);
            setPrevAffinity(mercenary.affinity);
            return () => clearTimeout(timer);
        }
    }, [mercenary?.affinity]);

    if (!mercenary) return null;

    const mergedPrimary = mergePrimaryStats(mercenary.stats, localAllocated);
    const baseDerived = calculateDerivedStats(mergedPrimary, mercenary.level);

    const currentEquipmentStats = (Object.values(mercenary.equipment) as (Equipment | null)[]).map(eq => eq?.stats).filter(Boolean);
    const finalStats = applyEquipmentBonuses(baseDerived, currentEquipmentStats as any);

    const currentAttackType = mergedPrimary.int > mergedPrimary.str ? 'MAGICAL' : 'PHYSICAL';
    const currentCombatPower = calculateCombatPower(finalStats, currentAttackType);

    let previewStats: DerivedStats | null = null;
    let previewCombatPower: number | null = null;

    if (selectedInventoryItemId) {
        const item = state.inventory.find(i => i.id === selectedInventoryItemId)?.equipmentData;
        if (item) {
            const previewEq = { ...mercenary.equipment };
            if (item.slotType === 'MAIN_HAND' && item.isTwoHanded) previewEq.OFF_HAND = null;
            else if (item.slotType === 'OFF_HAND' && previewEq.MAIN_HAND?.isTwoHanded) previewEq.MAIN_HAND = null;
            previewEq[item.slotType] = item;
            previewStats = applyEquipmentBonuses(baseDerived, (Object.values(previewEq) as (Equipment | null)[]).map(e => e?.stats).filter(Boolean) as any);
            previewCombatPower = calculateCombatPower(previewStats, currentAttackType);
        }
    }

    const effectiveFinalStats = previewStats || finalStats;
    const effectiveCombatPower = previewCombatPower !== null ? previewCombatPower : currentCombatPower;

    return (
        <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/95 backdrop-blur-sm animate-in fade-in duration-300">
            <button onClick={onClose} className="absolute top-6 right-6 z-[220] p-2 bg-stone-900 hover:bg-stone-800 rounded-full text-stone-500 hover:text-white border border-stone-700 transition-colors"><X className="w-6 h-6" /></button>
            <div className="w-full max-w-6xl h-[85vh] bg-stone-950 border border-stone-800 rounded-2xl shadow-2xl flex flex-col md:flex-row overflow-hidden relative">
                <MercenaryPaperDoll 
                    mercenary={mercenary} 
                    combatPower={effectiveCombatPower} 
                    showAffinityGain={showAffinityGain} 
                    onUnequip={(slot) => onUnequip(mercenary.id, slot)} 
                    onSlotClick={setSelectedSlot} 
                    selectedSlot={selectedSlot} 
                />
                <div className="w-full md:w-[60%] bg-stone-900 flex flex-col h-full max-h-full overflow-hidden">
                    <MercenaryStatsPanel 
                        mercenary={mercenary} 
                        finalStats={effectiveFinalStats} 
                        localAllocated={localAllocated}
                        onSetLocalAllocated={setLocalAllocated}
                    />
                    <EquipmentInventoryList 
                        inventory={state.inventory.filter(i => i.type === 'EQUIPMENT')} 
                        selectedItemId={selectedInventoryItemId} 
                        onSelect={setSelectedInventoryItemId} 
                        onEquip={(id) => { actions.equipItem(mercenary.id, id); setSelectedInventoryItemId(null); }} 
                        selectedSlotFilter={selectedSlot}
                        mercenary={mercenary}
                    />
                </div>
            </div>
        </div>
    );
};

export default MercenaryDetailModal;

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

export interface SmithingSceneData {
  onComplete: (score: number) => void;
  onStatusUpdate?: (temp: number) => void;
  onHeatUpRequest?: () => void;
  difficulty: number;
  initialTemp: number;
  charcoalCount: number;
}

export default class SmithingScene extends Phaser.Scene {
  // Core Systems
  private backgroundTile!: Phaser.GameObjects.TileSprite;
  private bgOverlay!: Phaser.GameObjects.Rectangle;
  private anvilImage!: Phaser.GameObjects.Image;
  private anvilSurface!: Phaser.GameObjects.Graphics;
  private targetRing!: Phaser.GameObjects.Graphics;
  private approachRing!: Phaser.GameObjects.Graphics;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private comboText!: Phaser.GameObjects.Text;
  private infoText!: Phaser.GameObjects.Text;
  private ambientGlow!: Phaser.GameObjects.Arc;
  private flashOverlay!: Phaser.GameObjects.Rectangle;

  private bladeContainer!: Phaser.GameObjects.Container;
  private bladeFallbackRect!: Phaser.GameObjects.Rectangle;
  private bladeImage?: Phaser.GameObjects.Image;

  private hammerHitArea!: Phaser.GameObjects.Rectangle;
  private hitPoly!: Phaser.Geom.Polygon;

  // Layout Constants
  private centerX: number = 0;
  private centerY: number = 0;
  private hitX: number = 0;
  private hitY: number = 0;

  private anvilConfig = {
    topWidthRatio: 0.65,
    botWidthRatio: 1.1,
    heightRatio: 0.4,
    yOffset: 60,
    imageOffsetX: 0,
    imageOffsetY: 40,
    hitAreaOffset: 45, 
  };

  // Game State
  private score: number = 0; // Progress
  private targetScore: number = 100;
  private combo: number = 0;
  private lastHitTime: number = 0;
  private hitCooldown: number = 200;
  private lastStage: number = -1;
  private isFinished: boolean = false;
  private isPlaying: boolean = false;
  private isReadyToStart: boolean = false;

  // Quality System
  private currentQuality: number = 100;
  private perfectCount: number = 0;
  private qualityText!: Phaser.GameObjects.Text;

  // Temperature System
  private temperature: number = 0;
  private coolingRate: number = 2;
  private currentTempStage: 'COLD' | 'AURA' | 'HOT' | 'WARM' | 'NORMAL' = 'COLD';
  private charcoalCount: number = 0;

  // Ring System
  private startRadius: number = 220;
  private targetRadius: number = 55;
  private currentRadius: number = 220;
  private shrinkDuration: number = 2000;
  private ringTimer: number = 0;

  // UI
  private tempBar!: Phaser.GameObjects.Rectangle;
  private tempValueText!: Phaser.GameObjects.Text;
  private bellowsContainer!: Phaser.GameObjects.Container;
  private bellowsSprite!: Phaser.GameObjects.Sprite;
  private heatUpBtnContainer!: Phaser.GameObjects.Container;
  private uiContainer!: Phaser.GameObjects.Container;
  private isPumping: boolean = false;

  // External Callbacks
  private onComplete?: (score: number) => void;
  private onStatusUpdate?: (temp: number) => void;
  private onHeatUpRequest?: () => void;

  constructor() {
    super('SmithingScene');
  }

  init(data: SmithingSceneData) {
    this.onComplete = data.onComplete;
    this.onStatusUpdate = data.onStatusUpdate;
    this.onHeatUpRequest = data.onHeatUpRequest;
    this.charcoalCount = data.charcoalCount;
    this.shrinkDuration = Math.max(800, 2000 - data.difficulty * 200);
    this.coolingRate = 2 + data.difficulty * 0.8;

    this.score = 0;
    this.combo = 0;
    this.lastStage = -1;
    this.temperature = data.initialTemp || 0;
    this.isFinished = false;
    this.isPlaying = false;
    this.isReadyToStart = this.temperature > 0;

    // Reset Quality
    this.currentQuality = 100;
    this.perfectCount = 0;
  }

  preload() {
    this.load.crossOrigin = 'anonymous';
    this.load.image('tile_forge', getAssetUrl('tile_forge.png'));
    this.load.image('anvil_img', getAssetUrl('anvil.png'));
    this.load.image('spark_perfect', getAssetUrl('particle_spark1.png'));
    this.load.image('spark_normal', getAssetUrl('particle_spark2.png'));
    this.load.image('blade_stage_0', getAssetUrl('billet_default.png'));
    this.load.image('blade_stage_1', getAssetUrl('billet_blade_01.png'));
    this.load.image('blade_stage_2', getAssetUrl('billet_blade_02.png'));
    this.load.image('blade_stage_3', getAssetUrl('billet_blade_03.png'));
    this.load.image('blade_stage_4', getAssetUrl('billet_blade_04.png'));
    this.load.image('blade_stage_5', getAssetUrl('billet_blade_05.png'));

    this.load.spritesheet('bellows', getAssetUrl('bellows_sprite.png'), {
      frameWidth: 298,
      frameHeight: 188,
    });
  }

  create() {
    if (!this.anims.exists('bellows_pump')) {
      this.anims.create({
        key: 'bellows_pump',
        frames: [0, 1, 2, 3, 4, 5, 6, 7].map(i => ({ key: 'bellows', frame: i })),
        frameRate: 18,
        repeat: 0,
      });
    }

    this.centerX = this.scale.width / 2;
    this.centerY = this.scale.height / 2;

    this.backgroundTile = this.add.tileSprite(0, 0, this.scale.width, this.scale.height, 'tile_forge').setOrigin(0).setDepth(-2).setAlpha(0.7);
    this.bgOverlay = this.add.rectangle(0, 0, this.scale.width, this.scale.height, 0x000000, 0.4).setOrigin(0).setDepth(-1);

    this.anvilImage = this.add.image(0, 0, 'anvil_img').setDepth(1).setOrigin(0.5, 0.5);
    this.anvilSurface = this.add.graphics().setDepth(2);

    this.bladeContainer = this.add.container(0, 0).setDepth(3).setAngle(-12);
    this.bladeFallbackRect = this.add.rectangle(0, 0, 600, 120, 0x57534e).setOrigin(0.5, 0.5);
    this.bladeContainer.add(this.bladeFallbackRect);

    if (this.textures.exists('blade_stage_0')) {
      this.bladeImage = this.add.image(0, 0, 'blade_stage_0').setOrigin(0.5);
      this.bladeContainer.add(this.bladeImage);
    }

    this.hammerHitArea = this.add.rectangle(0, 0, 500, 120, 0x00ff00).setDepth(3).setAlpha(0).setAngle(-12);
    this.targetRing = this.add.graphics().setDepth(5);
    this.approachRing = this.add.graphics().setDepth(5);

    this.uiContainer = this.add.container(0, 0).setDepth(20);
    this.setupUI();

    this.ambientGlow = this.add.circle(0, 0, 500, 0xea580c, 0).setFillStyle(0xea580c, 0.25).setDepth(0);
    this.flashOverlay = this.add.rectangle(0, 0, this.scale.width, this.scale.height, 0xffaa00, 0).setOrigin(0).setDepth(100);

    this.handleResize();

    this.input.keyboard?.on('keydown-SPACE', () => this.handleInput(), this);
    this.input.on('pointerdown', (pointer: Phaser.Input.Pointer, objs: any[]) => {
      if (objs.includes(this.bellowsContainer) || this.bellowsContainer.list.some(c => objs.includes(c))) {
        this.pumpBellows();
        return;
      }
      if (objs.includes(this.heatUpBtnContainer) || this.heatUpBtnContainer.list.some(c => objs.includes(c))) {
        this.requestHeatUp();
        return;
      }

      if (!this.isPlaying) {
        this.handleInput(pointer);
        return;
      }
      const px = pointer.worldX;
      const py = pointer.worldY;
      if (!this.isPointerInHitArea(px, py)) {
        this.handleOffMetalMiss();
        return;
      }
      const dist = Phaser.Math.Distance.Between(px, py, this.hitX, this.hitY);
      if (dist > this.currentRadius + 4) {
        this.handleSpatialMiss();
        return;
      }
      this.handleInput(pointer);
    }, this);

    this.scale.on('resize', this.handleResize, this);
  }

  private setupUI() {
    this.progressBar = this.add.rectangle(0, 40, 0, 12, 0xeab308).setOrigin(0, 0.5);
    this.uiContainer.add([
      this.add.rectangle(0, 40, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e).setName('progBg'),
      this.progressBar,
    ]);

    this.qualityText = this.add.text(0, 65, 'QUALITY: 100%', {
        fontFamily: 'monospace', fontSize: '18px', color: '#10b981', fontStyle: 'bold'
    }).setOrigin(0.5);
    this.uiContainer.add(this.qualityText);

    this.tempBar = this.add.rectangle(0, 0, 18, 250, 0x3b82f6).setOrigin(0.5, 1).setScale(1, 0);
    this.tempValueText = this.add.text(0, 0, '20°C', { fontFamily: 'monospace', fontSize: '18px', color: '#fff', fontStyle: 'bold' }).setOrigin(0.5);
    this.uiContainer.add([
      this.add.rectangle(0, 0, 32, 260, 0x1c1917).setStrokeStyle(3, 0x57534e).setName('tempFrame'),
      this.add.rectangle(0, 0, 24, 250, 0x0c0a09).setName('tempBg'),
      this.tempBar,
      this.tempValueText,
    ]);

    this.createBellows();
    this.createHeatUpButton();

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Impact', fontSize: '48px', color: '#fcd34d', stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setAlpha(0);
    this.infoText = this.add.text(0, 0, this.isReadyToStart ? 'CLICK TO START' : 'FORGE IS COLD\nADD FUEL TO HEAT', { fontFamily: 'monospace', fontSize: '28px', color: this.isReadyToStart ? '#fbbf24' : '#3b82f6', align: 'center', stroke: '#000', strokeThickness: 5 }).setOrigin(0.5);
    this.uiContainer.add([this.comboText, this.infoText]);
    this.tweens.add({ targets: this.infoText, alpha: 0.5, yoyo: true, repeat: -1, duration: 800 });
  }

  private createBellows() {
    this.bellowsContainer = this.add.container(0, 0);
    this.bellowsSprite = this.add.sprite(0, 0, 'bellows').setScale(0.35);
    const txt = this.add.text(0, 25, 'PUMP', { fontSize: '10px', color: '#fde68a', fontFamily: 'monospace', fontStyle: 'bold' }).setOrigin(0.5);
    this.bellowsContainer.add([this.bellowsSprite, txt]);
    this.bellowsContainer.setInteractive(new Phaser.Geom.Rectangle(-60, -45, 120, 90), Phaser.Geom.Rectangle.Contains);
    this.bellowsSprite.on('animationcomplete-bellows_pump', () => { this.isPumping = false; });
    this.uiContainer.add(this.bellowsContainer);
  }

  private createHeatUpButton() {
    this.heatUpBtnContainer = this.add.container(0, 0);
    const bg = this.add.rectangle(0, 0, 90, 70, 0x1c1917).setStrokeStyle(2, 0x57534e).setName('btnBg');
    const icon = this.add.text(0, -12, '🔥', { fontSize: '20px' }).setOrigin(0.5).setName('btnIcon');
    const label = this.add.text(0, 10, 'HEAT UP', { fontSize: '10px', color: '#fbbf24', fontStyle: 'bold', fontFamily: 'monospace' }).setOrigin(0.5);
    const countTxt = this.add.text(0, 22, `x${this.charcoalCount}`, { fontSize: '11px', color: '#78716c', fontFamily: 'monospace' }).setOrigin(0.5).setName('countTxt');
    this.heatUpBtnContainer.add([bg, icon, label, countTxt]);
    this.heatUpBtnContainer.setInteractive(new Phaser.Geom.Rectangle(-45, -35, 90, 70), Phaser.Geom.Rectangle.Contains);
    this.uiContainer.add(this.heatUpBtnContainer);
    this.refreshHeatUpButton();
  }

  private refreshHeatUpButton() {
    if (!this.heatUpBtnContainer) return;
    const bg = this.heatUpBtnContainer.getByName('btnBg') as Phaser.GameObjects.Rectangle;
    const countTxt = this.heatUpBtnContainer.getByName('countTxt') as Phaser.GameObjects.Text;
    const icon = this.heatUpBtnContainer.getByName('btnIcon') as Phaser.GameObjects.Text;
    countTxt.setText(`x${this.charcoalCount}`);
    if (this.charcoalCount > 0) {
      bg.setStrokeStyle(2, 0xea580c);
      countTxt.setColor('#a8a29e');
      icon.setAlpha(1);
    } else {
      bg.setStrokeStyle(2, 0x292524);
      countTxt.setColor('#44403c');
      icon.setAlpha(0.3);
    }
  }

  public updateCharcoalCount(count: number) {
    this.charcoalCount = count;
    this.refreshHeatUpButton();
  }

  private pumpBellows() {
    if (this.isPumping) return;
    this.isPumping = true;
    this.bellowsSprite.play('bellows_pump');

    // ONLY increase temperature if there is already heat/ignition (> 0)
    if (this.temperature > 0) {
      this.temperature = Math.min(100, this.temperature + 5);
      if (!this.isPlaying && !this.isReadyToStart) {
        this.isReadyToStart = true;
        this.infoText.setText('CLICK TO START').setColor('#fbbf24');
      }
    }
  }

  private requestHeatUp() {
    if (this.charcoalCount > 0) {
      this.tweens.add({ targets: this.heatUpBtnContainer, scale: 0.9, duration: 50, yoyo: true });
      if (this.onHeatUpRequest) this.onHeatUpRequest();
    } else {
      this.cameras.main.shake(100, 0.005);
    }
  }

  public heatUp() {
    this.temperature = Math.min(100, this.temperature + 40);
    if (!this.isPlaying) {
      this.isReadyToStart = true;
      this.infoText.setText('CLICK TO START').setColor('#fbbf24');
    }
    this.flashOverlay.setFillStyle(0xff8800, 1).setAlpha(0.4);
    this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 400, ease: 'Cubic.easeOut' });
  }

  private handleResize() {
    this.centerX = this.scale.width / 2;
    this.centerY = this.scale.height / 2;
    if (this.backgroundTile) this.backgroundTile.setSize(this.scale.width, this.scale.height);
    if (this.bgOverlay) this.bgOverlay.setSize(this.scale.width, this.scale.height);
    if (this.flashOverlay) this.flashOverlay.setSize(this.scale.width, this.scale.height);

    const surfaceH = this.scale.height * this.anvilConfig.heightRatio;
    const b = this.centerY + surfaceH / 2 + this.anvilConfig.yOffset;

    if (this.anvilImage && this.anvilImage.texture.key !== '__MISSING') {
      const targetWidth = this.scale.width * 1.3;
      this.anvilImage.setScale(targetWidth / this.anvilImage.width);
      this.anvilImage.setPosition(this.centerX, b + this.anvilConfig.imageOffsetY);
    }

    if (this.ambientGlow) {
      this.ambientGlow.setPosition(this.centerX, b);
    }

    const bladeY = b - surfaceH * 0.55; 
    this.bladeContainer.setPosition(this.centerX, bladeY);
    const rad = Phaser.Math.DegToRad(this.bladeContainer.angle);
    this.bladeContainer.x += Math.cos(rad) * 80;
    this.bladeContainer.y += Math.sin(rad) * 80;

    const ox = -Math.sin(rad) * this.anvilConfig.hitAreaOffset;
    const oy = Math.cos(rad) * this.anvilConfig.hitAreaOffset;
    this.hammerHitArea.setPosition(this.bladeContainer.x + ox, this.bladeContainer.y + oy);
    this.rebuildHitPoly();

    this.repositionUIElements();
  }

  private repositionUIElements() {
    const w = this.scale.width;
    (this.uiContainer.getByName('progBg') as any).setPosition(this.centerX, 40);
    this.progressBar.setPosition(this.centerX - 150, 40);
    this.qualityText.setPosition(this.centerX, 65);
    const stackX = w - 70;
    const stackTopY = this.centerY - 100;
    this.tempValueText.setPosition(stackX, stackTopY - 165);
    (this.uiContainer.getByName('tempFrame') as any).setPosition(stackX, stackTopY);
    (this.uiContainer.getByName('tempBg') as any).setPosition(stackX, stackTopY);
    this.tempBar.setPosition(stackX, stackTopY + 125);
    this.bellowsContainer.setPosition(stackX, stackTopY + 205);
    this.heatUpBtnContainer.setPosition(stackX, stackTopY + 300);
    this.infoText.setPosition(this.centerX, this.centerY - 220);
    this.comboText.setPosition(this.centerX, this.centerY - 300);
  }

  private rebuildHitPoly() {
    const w = this.hammerHitArea.width * this.hammerHitArea.scaleX;
    const h = this.hammerHitArea.height * this.hammerHitArea.scaleY;
    const cx = this.hammerHitArea.x;
    const cy = this.hammerHitArea.y;
    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    const cos = Math.cos(rad);
    const sin = Math.sin(rad);
    const corners = [
      { x: -w / 2, y: -h / 2 }, { x: w / 2, y: -h / 2 },
      { x: w / 2, y: h / 2 }, { x: -w / 2, y: h / 2 },
    ].map((p) => ({ x: cx + p.x * cos - p.y * sin, y: cy + p.x * sin + p.y * cos }));
    this.hitPoly = new Phaser.Geom.Polygon(corners);
  }

  private isPointerInHitArea(px: number, py: number) {
    return this.hitPoly && Phaser.Geom.Polygon.Contains(this.hitPoly, px, py);
  }

  private handleInput(pointer?: Phaser.Input.Pointer) {
    if (this.isFinished) return;
    if (!this.isPlaying) {
      if (this.isReadyToStart) { 
        this.isPlaying = true; 
        this.infoText.setVisible(false); 
        this.resetRing(); 
        this.flashOverlay.setFillStyle(0xffffff, 1).setAlpha(0.2);
        this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 300 });
      } else { this.cameras.main.shake(50, 0.005); this.showFeedback('TOO COLD!', 0x3b82f6, 1.0); }
      return;
    }
    if (this.time.now - this.lastHitTime < this.hitCooldown) return;
    this.lastHitTime = this.time.now;
    const swingX = pointer ? pointer.worldX : this.hitX;
    const swingY = pointer ? pointer.worldY : this.hitY;
    if (this.currentTempStage === 'COLD' || this.currentTempStage === 'NORMAL') { this.showFeedback('TOO COLD!', 0x3b82f6, 1.0); return; }

    const diff = Math.abs(this.currentRadius - this.targetRadius);
    const eff = this.currentTempStage === 'AURA' ? 1.5 : this.currentTempStage === 'HOT' ? 1.0 : 0.5;

    if (diff < 18) {
      // --- PERFECT ---
      this.score += Math.ceil(8 * eff); 
      this.combo++; 
      this.perfectCount++;

      // Accumulate 5 perfects, starting from 6th increase quality by 1
      if (this.perfectCount >= 6) {
          this.currentQuality = Math.min(100, this.currentQuality + 1);
          this.showFeedback('+1 QUALITY!', 0xfbbf24, 1.3, swingX, swingY - 40);
      }

      this.createSparks(40, 0xffaa00, 2.0, 'spark_perfect', swingX, swingY); 
      this.showFeedback('PERFECT!', 0xffb300, 1.5, swingX, swingY); 
      this.cameras.main.shake(200, 0.025);
    } else if (diff < 55) {
      // --- GOOD ---
      this.score += Math.ceil(5 * eff); 
      this.combo = 0; 
      this.currentQuality = Math.max(0, this.currentQuality - 2);

      this.createSparks(20, 0xffffff, 1.3, 'spark_normal', swingX, swingY); 
      this.showFeedback('GOOD', 0xe5e5e5, 1.0, swingX, swingY);
      this.showFeedback('-2 QUALITY', 0xa8a29e, 0.8, swingX, swingY - 40);
    } else {
      // --- MISS ---
      this.score = Math.max(0, this.score - 5); 
      this.combo = 0; 
      this.currentQuality = Math.max(0, this.currentQuality - 5);

      this.showFeedback('MISS', 0xef4444, 1.2, swingX, swingY); 
      this.showFeedback('-5 QUALITY', 0xef4444, 1.0, swingX, swingY - 40);
      this.cameras.main.shake(120, 0.012);
    }

    this.updateProgressBar();
    if (this.score >= this.targetScore) this.winGame(); else this.resetRing();
  }

  private handleOffMetalMiss() {
    this.score = Math.max(0, this.score - 5); 
    this.combo = 0; 
    this.currentQuality = Math.max(0, this.currentQuality - 5);

    this.cameras.main.shake(100, 0.015);
    this.showFeedback('OFF METAL!', 0xffffff, 1.2); 
    this.showFeedback('-5 QUALITY', 0xef4444, 1.0);
    this.updateProgressBar(); 
    this.resetRing();
  }

  private handleSpatialMiss() {
    this.score = Math.max(0, this.score - 5); 
    this.combo = 0; 
    this.currentQuality = Math.max(0, this.currentQuality - 5);

    this.cameras.main.shake(120, 0.012);
    this.showFeedback('MISS', 0xef4444, 1.2); 
    this.showFeedback('-5 QUALITY', 0xef4444, 1.0);
    this.updateProgressBar(); 
    this.resetRing();
  }

  update(time: number, delta: number) {
    if (this.isFinished) return;
    if (this.isPlaying) this.handleRingLogic(delta);
    this.temperature = Math.max(0, this.temperature - this.coolingRate * (delta / 1000));
    this.refreshVisuals();
    if (!this.isPlaying && this.isReadyToStart && this.temperature <= 0) {
      this.isReadyToStart = false;
      this.infoText.setText('FORGE IS COLD\nADD FUEL TO HEAT').setColor('#3b82f6');
    }
  }

  private refreshVisuals() {
    // Quality Text Update
    this.qualityText.setText(`QUALITY: ${this.currentQuality}%`);
    if (this.currentQuality < 40) this.qualityText.setColor('#ef4444');
    else if (this.currentQuality < 75) this.qualityText.setColor('#fbbf24');
    else this.qualityText.setColor('#10b981');

    const ratio = this.temperature / 100;
    this.tempBar.scaleY = ratio;
    this.tempValueText.setText(`${Math.floor(20 + ratio * 1480)}°C`);
    const current = Phaser.Display.Color.Interpolate.ColorWithColor(new Phaser.Display.Color(63, 63, 70), new Phaser.Display.Color(253, 230, 138), 100, ratio * 100);
    const color = Phaser.Display.Color.GetColor(current.r, current.g, current.b);
    this.bladeFallbackRect.setFillStyle(color, 1);
    if (this.bladeImage) this.bladeImage.setTint(color);
    const progress = Phaser.Math.Clamp(this.score / this.targetScore, 0, 1);
    const stage = Math.min(5, Math.floor(progress * 6));
    if (stage !== this.lastStage) { this.setBladeStage(stage); this.lastStage = stage; }
    if (this.ambientGlow) this.ambientGlow.setAlpha(ratio * 0.4);
    if (this.temperature <= 0) this.currentTempStage = 'COLD';
    else if (this.temperature > 75) this.currentTempStage = 'AURA';
    else if (this.temperature > 40) this.currentTempStage = 'HOT';
    else if (this.temperature > 15) this.currentTempStage = 'WARM';
    else this.currentTempStage = 'NORMAL';
  }

  private setBladeStage(stage: number) {
    const key = `blade_stage_${stage}`;
    if (this.textures.exists(key)) {
      if (!this.bladeImage) { this.bladeImage = this.add.image(0, 0, key).setOrigin(0.5); this.bladeContainer.add(this.bladeImage); } 
      else this.bladeImage.setTexture(key);
      this.bladeImage.setVisible(true);
      this.bladeFallbackRect.setVisible(true).setAlpha(0.15);
      if (this.lastStage !== -1) {
          this.createOmniBurst(70, 0xffcc00, 2.5, 'spark_perfect', this.bladeContainer.x, this.bladeContainer.y);
          this.flashOverlay.setFillStyle(0xffcc00, 1).setAlpha(0.35);
          this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 250, ease: 'Quad.easeOut' });
          this.tweens.add({ targets: this.bladeContainer, scale: 1.15, duration: 100, yoyo: true, ease: 'Quad.easeOut' });
      }
    }
  }

  private handleRingLogic(delta: number) {
    this.ringTimer += delta;
    const t = Math.min(this.ringTimer / this.shrinkDuration, 1.5);
    this.currentRadius = this.startRadius * (1 - t * t);
    const ringColor = this.currentRadius < this.targetRadius ? 0xffffff : 0xfabf24;
    this.approachRing.clear().lineStyle(8, ringColor, 0.6).strokeCircle(this.hitX, this.hitY, Math.max(0, this.currentRadius));
    if (this.currentRadius < this.targetRadius - 30) { 
        this.combo = 0; 
        this.resetRing(); 
    }
  }

  private resetRing() {
    if (this.temperature <= 0) {
      this.isPlaying = false; this.isReadyToStart = false;
      this.targetRing.clear(); this.approachRing.clear();
      this.infoText.setVisible(true).setText('FORGE IS COLD\nADD FUEL TO HEAT').setColor('#3b82f6');
      return;
    }
    this.currentRadius = this.startRadius; this.ringTimer = 0;
    const w = this.hammerHitArea.width * this.hammerHitArea.scaleX;
    const h = this.hammerHitArea.height * this.hammerHitArea.scaleY;
    const u = Phaser.Math.Between(-w * 0.35, w * 0.35);
    const v = Phaser.Math.Between(-h * 0.25, h * 0.25);
    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    this.hitX = this.hammerHitArea.x + (u * Math.cos(rad) - v * Math.sin(rad));
    this.hitY = this.hammerHitArea.y + (u * Math.sin(rad) + v * Math.cos(rad));
    if (this.isPlaying) {
      this.targetRing.clear().fillStyle(0xfabf24, 0.1).fillCircle(this.hitX, this.hitY, this.targetRadius).lineStyle(5, 0xfabf24, 0.4).strokeCircle(this.hitX, this.hitY, this.targetRadius);
    }
  }

  private updateProgressBar() { this.progressBar.width = Phaser.Math.Clamp((this.score / this.targetScore) * 300, 0, 300); }

  private createSparks(count: number, color: number, scale: number, key: string, x: number, y: number) {
    const emitter = this.add.particles(x, y, this.textures.exists(key) ? key : 'white', { lifespan: 800, speed: { min: 300 * scale, max: 700 * scale }, angle: { min: 230, max: 310 }, scale: { start: 0.7, end: 0 }, gravityY: 1200, blendMode: 'ADD', tint: color });
    emitter.explode(count);
  }

  private createOmniBurst(count: number, color: number, scale: number, key: string, x: number, y: number) {
    const emitter = this.add.particles(x, y, this.textures.exists(key) ? key : 'white', { lifespan: 1200, speed: { min: 200 * scale, max: 500 * scale }, angle: { min: 0, max: 360 }, scale: { start: 0.8, end: 0 }, gravityY: 400, blendMode: 'ADD', tint: color });
    emitter.explode(count);
  }

  private showFeedback(text: string, color: number, scale: number, x?: number, y?: number) {
    const fx = x ?? this.hitX; const fy = y ?? this.hitY;
    const fb = this.add.text(fx, fy - 140, text, { fontFamily: 'Arial', fontSize: '36px', fontStyle: 'bold', color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setScale(0.5).setAlpha(0).setDepth(25);
    this.tweens.add({ targets: fb, y: fy - 200, alpha: 1, scale: scale, duration: 250, hold: 400, yoyo: true, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, scale: { from: 1.5, to: 1 }, duration: 200, alpha: { from: 1, to: 0 }, delay: 500 }); }
  }

  private winGame() {
    this.isFinished = true; this.isPlaying = false; this.targetRing.clear(); this.approachRing.clear();
    if (this.onStatusUpdate) this.onStatusUpdate(this.temperature);
    const bg = this.add.rectangle(this.centerX, this.centerY, this.scale.width, this.scale.height, 0x000000).setAlpha(0).setDepth(100);
    this.tweens.add({ targets: bg, alpha: 0.85, duration: 500 });
    const txt = this.add.text(this.centerX, this.centerY, 'BLADE FORGED!', { fontFamily: 'Georgia', fontSize: '72px', color: '#fbbf24', stroke: '#000', strokeThickness: 3 }).setOrigin(0.5).setAlpha(0).setDepth(101);
    this.tweens.add({ targets: txt, alpha: 1, scale: { from: 0.5, to: 1.2 }, duration: 600, ease: 'Back.out', onComplete: () => { this.time.delayedCall(1000, () => { if (this.onComplete) this.onComplete(this.currentQuality); }); } });
  }

  public getTemperature() { return this.temperature; }
}

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

export interface SmithingSceneData {
  onComplete: (score: number) => void;
  onStatusUpdate?: (temp: number) => void;
  onHeatUpRequest?: () => void;
  difficulty: number;
  initialTemp: number;
  charcoalCount: number;
}

export default class SmithingScene extends Phaser.Scene {
  // Core Systems
  private backgroundTile!: Phaser.GameObjects.TileSprite;
  private bgOverlay!: Phaser.GameObjects.Rectangle;
  private anvilImage!: Phaser.GameObjects.Image;
  private anvilSurface!: Phaser.GameObjects.Graphics;
  private targetRing!: Phaser.GameObjects.Graphics;
  private approachRing!: Phaser.GameObjects.Graphics;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private comboText!: Phaser.GameObjects.Text;
  private infoText!: Phaser.GameObjects.Text;
  private ambientGlow!: Phaser.GameObjects.Arc;
  private flashOverlay!: Phaser.GameObjects.Rectangle;

  private bladeContainer!: Phaser.GameObjects.Container;
  private bladeFallbackRect!: Phaser.GameObjects.Rectangle;
  private bladeImage?: Phaser.GameObjects.Image;

  private hammerHitArea!: Phaser.GameObjects.Rectangle;
  private hitPoly!: Phaser.Geom.Polygon;

  // Layout Constants
  private centerX: number = 0;
  private centerY: number = 0;
  private hitX: number = 0;
  private hitY: number = 0;

  private anvilConfig = {
    topWidthRatio: 0.65,
    botWidthRatio: 1.1,
    heightRatio: 0.4,
    yOffset: 60,
    imageOffsetX: 0,
    imageOffsetY: 40,
    hitAreaOffset: 45, 
  };

  // Game State
  private score: number = 0; // Progress
  private targetScore: number = 100;
  private combo: number = 0;
  private lastHitTime: number = 0;
  private hitCooldown: number = 200;
  private lastStage: number = -1;
  private isFinished: boolean = false;
  private isPlaying: boolean = false;
  private isReadyToStart: boolean = false;

  // Quality System
  private currentQuality: number = 100;
  private perfectCount: number = 0;
  private qualityText!: Phaser.GameObjects.Text;

  // Temperature System
  private temperature: number = 0;
  private coolingRate: number = 2;
  private currentTempStage: 'COLD' | 'AURA' | 'HOT' | 'WARM' | 'NORMAL' = 'COLD';
  private charcoalCount: number = 0;

  // Ring System
  private startRadius: number = 220;
  private targetRadius: number = 55;
  private currentRadius: number = 220;
  private shrinkDuration: number = 2000;
  private ringTimer: number = 0;

  // UI
  private tempBar!: Phaser.GameObjects.Rectangle;
  private tempValueText!: Phaser.GameObjects.Text;
  private bellowsContainer!: Phaser.GameObjects.Container;
  private bellowsSprite!: Phaser.GameObjects.Sprite;
  private heatUpBtnContainer!: Phaser.GameObjects.Container;
  private uiContainer!: Phaser.GameObjects.Container;
  private isPumping: boolean = false;

  // External Callbacks
  private onComplete?: (score: number) => void;
  private onStatusUpdate?: (temp: number) => void;
  private onHeatUpRequest?: () => void;

  constructor() {
    super('SmithingScene');
  }

  // Helper to determine Grade based on quality percentage
  public getQualityGrade(q: number): string {
    if (q >= 120) return "SSS";
    if (q >= 110) return "SS";
    if (q >= 100) return "S";
    if (q >= 90) return "A";
    if (q >= 80) return "B";
    if (q >= 70) return "C";
    if (q >= 60) return "D";
    return "F";
  }

  // Helper to get Grade Color
  private getGradeColor(q: number): string {
    if (q >= 120) return '#f43f5e'; // Rose 500 (SSS)
    if (q >= 110) return '#f59e0b'; // Amber 500 (SS)
    if (q >= 100) return '#fbbf24'; // Yellow 400 (S)
    if (q >= 90) return '#10b981';  // Emerald 500 (A)
    if (q >= 70) return '#3b82f6';  // Blue 500 (B, C)
    return '#ef4444';               // Red 500 (D, F)
  }

  init(data: SmithingSceneData) {
    this.onComplete = data.onComplete;
    this.onStatusUpdate = data.onStatusUpdate;
    this.onHeatUpRequest = data.onHeatUpRequest;
    this.charcoalCount = data.charcoalCount;
    this.shrinkDuration = Math.max(800, 2000 - data.difficulty * 200);
    this.coolingRate = 2 + data.difficulty * 0.8;

    this.score = 0;
    this.combo = 0;
    this.lastStage = -1;
    this.temperature = data.initialTemp || 0;
    this.isFinished = false;
    this.isPlaying = false;
    this.isReadyToStart = this.temperature > 0;

    // Reset Quality
    this.currentQuality = 100;
    this.perfectCount = 0;
  }

  preload() {
    this.load.crossOrigin = 'anonymous';
    this.load.image('tile_forge', getAssetUrl('tile_forge.png'));
    this.load.image('anvil_img', getAssetUrl('anvil.png'));
    this.load.image('spark_perfect', getAssetUrl('particle_spark1.png'));
    this.load.image('spark_normal', getAssetUrl('particle_spark2.png'));
    this.load.image('blade_stage_0', getAssetUrl('billet_default.png'));
    this.load.image('blade_stage_1', getAssetUrl('billet_blade_01.png'));
    this.load.image('blade_stage_2', getAssetUrl('billet_blade_02.png'));
    this.load.image('blade_stage_3', getAssetUrl('billet_blade_03.png'));
    this.load.image('blade_stage_4', getAssetUrl('billet_blade_04.png'));
    this.load.image('blade_stage_5', getAssetUrl('billet_blade_05.png'));

    this.load.spritesheet('bellows', getAssetUrl('bellows_sprite.png'), {
      frameWidth: 298,
      frameHeight: 188,
    });
  }

  create() {
    if (!this.anims.exists('bellows_pump')) {
      this.anims.create({
        key: 'bellows_pump',
        frames: [0, 1, 2, 3, 4, 5, 6, 7].map(i => ({ key: 'bellows', frame: i })),
        frameRate: 18,
        repeat: 0,
      });
    }

    this.centerX = this.scale.width / 2;
    this.centerY = this.scale.height / 2;

    this.backgroundTile = this.add.tileSprite(0, 0, this.scale.width, this.scale.height, 'tile_forge').setOrigin(0).setDepth(-2).setAlpha(0.7);
    this.bgOverlay = this.add.rectangle(0, 0, this.scale.width, this.scale.height, 0x000000, 0.4).setOrigin(0).setDepth(-1);

    this.anvilImage = this.add.image(0, 0, 'anvil_img').setDepth(1).setOrigin(0.5, 0.5);
    this.anvilSurface = this.add.graphics().setDepth(2);

    this.bladeContainer = this.add.container(0, 0).setDepth(3).setAngle(-12);
    this.bladeFallbackRect = this.add.rectangle(0, 0, 600, 120, 0x57534e).setOrigin(0.5, 0.5);
    this.bladeContainer.add(this.bladeFallbackRect);

    if (this.textures.exists('blade_stage_0')) {
      this.bladeImage = this.add.image(0, 0, 'blade_stage_0').setOrigin(0.5);
      this.bladeContainer.add(this.bladeImage);
    }

    this.hammerHitArea = this.add.rectangle(0, 0, 500, 120, 0x00ff00).setDepth(3).setAlpha(0).setAngle(-12);
    this.targetRing = this.add.graphics().setDepth(5);
    this.approachRing = this.add.graphics().setDepth(5);

    this.uiContainer = this.add.container(0, 0).setDepth(20);
    this.setupUI();

    this.ambientGlow = this.add.circle(0, 0, 500, 0xea580c, 0).setFillStyle(0xea580c, 0.25).setDepth(0);
    this.flashOverlay = this.add.rectangle(0, 0, this.scale.width, this.scale.height, 0xffaa00, 0).setOrigin(0).setDepth(100);

    this.handleResize();

    this.input.keyboard?.on('keydown-SPACE', () => this.handleInput(), this);
    this.input.on('pointerdown', (pointer: Phaser.Input.Pointer, objs: any[]) => {
      if (objs.includes(this.bellowsContainer) || this.bellowsContainer.list.some(c => objs.includes(c))) {
        this.pumpBellows();
        return;
      }
      if (objs.includes(this.heatUpBtnContainer) || this.heatUpBtnContainer.list.some(c => objs.includes(c))) {
        this.requestHeatUp();
        return;
      }

      if (!this.isPlaying) {
        this.handleInput(pointer);
        return;
      }
      const px = pointer.worldX;
      const py = pointer.worldY;
      if (!this.isPointerInHitArea(px, py)) {
        this.handleOffMetalMiss();
        return;
      }
      const dist = Phaser.Math.Distance.Between(px, py, this.hitX, this.hitY);
      if (dist > this.currentRadius + 4) {
        this.handleSpatialMiss();
        return;
      }
      this.handleInput(pointer);
    }, this);

    this.scale.on('resize', this.handleResize, this);
  }

  private setupUI() {
    this.progressBar = this.add.rectangle(0, 40, 0, 12, 0xeab308).setOrigin(0, 0.5);
    this.uiContainer.add([
      this.add.rectangle(0, 40, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e).setName('progBg'),
      this.progressBar,
    ]);

    this.qualityText = this.add.text(0, 65, 'QUALITY: 100% [S]', {
        fontFamily: 'monospace', fontSize: '18px', color: '#fbbf24', fontStyle: 'bold'
    }).setOrigin(0.5);
    this.uiContainer.add(this.qualityText);

    this.tempBar = this.add.rectangle(0, 0, 18, 250, 0x3b82f6).setOrigin(0.5, 1).setScale(1, 0);
    this.tempValueText = this.add.text(0, 0, '20°C', { fontFamily: 'monospace', fontSize: '18px', color: '#fff', fontStyle: 'bold' }).setOrigin(0.5);
    this.uiContainer.add([
      this.add.rectangle(0, 0, 32, 260, 0x1c1917).setStrokeStyle(3, 0x57534e).setName('tempFrame'),
      this.add.rectangle(0, 0, 24, 250, 0x0c0a09).setName('tempBg'),
      this.tempBar,
      this.tempValueText,
    ]);

    this.createBellows();
    this.createHeatUpButton();

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Impact', fontSize: '48px', color: '#fcd34d', stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setAlpha(0);
    this.infoText = this.add.text(0, 0, this.isReadyToStart ? 'CLICK TO START' : 'FORGE IS COLD\nADD FUEL TO HEAT', { fontFamily: 'monospace', fontSize: '28px', color: this.isReadyToStart ? '#fbbf24' : '#3b82f6', align: 'center', stroke: '#000', strokeThickness: 5 }).setOrigin(0.5);
    this.uiContainer.add([this.comboText, this.infoText]);
    this.tweens.add({ targets: this.infoText, alpha: 0.5, yoyo: true, repeat: -1, duration: 800 });
  }

  private createBellows() {
    this.bellowsContainer = this.add.container(0, 0);
    this.bellowsSprite = this.add.sprite(0, 0, 'bellows').setScale(0.35);
    const txt = this.add.text(0, 25, 'PUMP', { fontSize: '10px', color: '#fde68a', fontFamily: 'monospace', fontStyle: 'bold' }).setOrigin(0.5);
    this.bellowsContainer.add([this.bellowsSprite, txt]);
    this.bellowsContainer.setInteractive(new Phaser.Geom.Rectangle(-60, -45, 120, 90), Phaser.Geom.Rectangle.Contains);
    this.bellowsSprite.on('animationcomplete-bellows_pump', () => { this.isPumping = false; });
    this.uiContainer.add(this.bellowsContainer);
  }

  private createHeatUpButton() {
    this.heatUpBtnContainer = this.add.container(0, 0);
    const bg = this.add.rectangle(0, 0, 90, 70, 0x1c1917).setStrokeStyle(2, 0x57534e).setName('btnBg');
    const icon = this.add.text(0, -12, '🔥', { fontSize: '20px' }).setOrigin(0.5).setName('btnIcon');
    const label = this.add.text(0, 10, 'HEAT UP', { fontSize: '10px', color: '#fbbf24', fontStyle: 'bold', fontFamily: 'monospace' }).setOrigin(0.5);
    const countTxt = this.add.text(0, 22, `x${this.charcoalCount}`, { fontSize: '11px', color: '#78716c', fontFamily: 'monospace' }).setOrigin(0.5).setName('countTxt');
    this.heatUpBtnContainer.add([bg, icon, label, countTxt]);
    this.heatUpBtnContainer.setInteractive(new Phaser.Geom.Rectangle(-45, -35, 90, 70), Phaser.Geom.Rectangle.Contains);
    this.uiContainer.add(this.heatUpBtnContainer);
    this.refreshHeatUpButton();
  }

  private refreshHeatUpButton() {
    if (!this.heatUpBtnContainer) return;
    const bg = this.heatUpBtnContainer.getByName('btnBg') as Phaser.GameObjects.Rectangle;
    const countTxt = this.heatUpBtnContainer.getByName('countTxt') as Phaser.GameObjects.Text;
    const icon = this.heatUpBtnContainer.getByName('btnIcon') as Phaser.GameObjects.Text;
    countTxt.setText(`x${this.charcoalCount}`);
    if (this.charcoalCount > 0) {
      bg.setStrokeStyle(2, 0xea580c);
      countTxt.setColor('#a8a29e');
      icon.setAlpha(1);
    } else {
      bg.setStrokeStyle(2, 0x292524);
      countTxt.setColor('#44403c');
      icon.setAlpha(0.3);
    }
  }

  public updateCharcoalCount(count: number) {
    this.charcoalCount = count;
    this.refreshHeatUpButton();
  }

  private pumpBellows() {
    if (this.isPumping) return;
    this.isPumping = true;
    this.bellowsSprite.play('bellows_pump');

    // ONLY increase temperature if there is already heat/ignition (> 0)
    if (this.temperature > 0) {
      this.temperature = Math.min(100, this.temperature + 5);
      if (!this.isPlaying && !this.isReadyToStart) {
        this.isReadyToStart = true;
        this.infoText.setText('CLICK TO START').setColor('#fbbf24');
      }
    }
  }

  private requestHeatUp() {
    if (this.charcoalCount > 0) {
      this.tweens.add({ targets: this.heatUpBtnContainer, scale: 0.9, duration: 50, yoyo: true });
      if (this.onHeatUpRequest) this.onHeatUpRequest();
    } else {
      this.cameras.main.shake(100, 0.005);
    }
  }

  public heatUp() {
    this.temperature = Math.min(100, this.temperature + 40);
    if (!this.isPlaying) {
      this.isReadyToStart = true;
      this.infoText.setText('CLICK TO START').setColor('#fbbf24');
    }
    this.flashOverlay.setFillStyle(0xff8800, 1).setAlpha(0.4);
    this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 400, ease: 'Cubic.easeOut' });
  }

  private handleResize() {
    this.centerX = this.scale.width / 2;
    this.centerY = this.scale.height / 2;
    if (this.backgroundTile) this.backgroundTile.setSize(this.scale.width, this.scale.height);
    if (this.bgOverlay) this.bgOverlay.setSize(this.scale.width, this.scale.height);
    if (this.flashOverlay) this.flashOverlay.setSize(this.scale.width, this.scale.height);

    const surfaceH = this.scale.height * this.anvilConfig.heightRatio;
    const b = this.centerY + surfaceH / 2 + this.anvilConfig.yOffset;

    if (this.anvilImage && this.anvilImage.texture.key !== '__MISSING') {
      const targetWidth = this.scale.width * 1.3;
      this.anvilImage.setScale(targetWidth / this.anvilImage.width);
      this.anvilImage.setPosition(this.centerX, b + this.anvilConfig.imageOffsetY);
    }

    if (this.ambientGlow) {
      this.ambientGlow.setPosition(this.centerX, b);
    }

    const bladeY = b - surfaceH * 0.55; 
    this.bladeContainer.setPosition(this.centerX, bladeY);
    const rad = Phaser.Math.DegToRad(this.bladeContainer.angle);
    this.bladeContainer.x += Math.cos(rad) * 80;
    this.bladeContainer.y += Math.sin(rad) * 80;

    const ox = -Math.sin(rad) * this.anvilConfig.hitAreaOffset;
    const oy = Math.cos(rad) * this.anvilConfig.hitAreaOffset;
    this.hammerHitArea.setPosition(this.bladeContainer.x + ox, this.bladeContainer.y + oy);
    this.rebuildHitPoly();

    this.repositionUIElements();
  }

  private repositionUIElements() {
    const w = this.scale.width;
    (this.uiContainer.getByName('progBg') as any).setPosition(this.centerX, 40);
    this.progressBar.setPosition(this.centerX - 150, 40);
    this.qualityText.setPosition(this.centerX, 65);
    const stackX = w - 70;
    const stackTopY = this.centerY - 100;
    this.tempValueText.setPosition(stackX, stackTopY - 165);
    (this.uiContainer.getByName('tempFrame') as any).setPosition(stackX, stackTopY);
    (this.uiContainer.getByName('tempBg') as any).setPosition(stackX, stackTopY);
    this.tempBar.setPosition(stackX, stackTopY + 125);
    this.bellowsContainer.setPosition(stackX, stackTopY + 205);
    this.heatUpBtnContainer.setPosition(stackX, stackTopY + 300);
    this.infoText.setPosition(this.centerX, this.centerY - 220);
    this.comboText.setPosition(this.centerX, this.centerY - 300);
  }

  private rebuildHitPoly() {
    const w = this.hammerHitArea.width * this.hammerHitArea.scaleX;
    const h = this.hammerHitArea.height * this.hammerHitArea.scaleY;
    const cx = this.hammerHitArea.x;
    const cy = this.hammerHitArea.y;
    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    const cos = Math.cos(rad);
    const sin = Math.sin(rad);
    const corners = [
      { x: -w / 2, y: -h / 2 }, { x: w / 2, y: -h / 2 },
      { x: w / 2, y: h / 2 }, { x: -w / 2, y: h / 2 },
    ].map((p) => ({ x: cx + p.x * cos - p.y * sin, y: cy + p.x * sin + p.y * cos }));
    this.hitPoly = new Phaser.Geom.Polygon(corners);
  }

  private isPointerInHitArea(px: number, py: number) {
    return this.hitPoly && Phaser.Geom.Polygon.Contains(this.hitPoly, px, py);
  }

  private handleInput(pointer?: Phaser.Input.Pointer) {
    if (this.isFinished) return;
    if (!this.isPlaying) {
      if (this.isReadyToStart) { 
        this.isPlaying = true; 
        this.infoText.setVisible(false); 
        this.resetRing(); 
        this.flashOverlay.setFillStyle(0xffffff, 1).setAlpha(0.2);
        this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 300 });
      } else { this.cameras.main.shake(50, 0.005); this.showFeedback('TOO COLD!', 0x3b82f6, 1.0); }
      return;
    }
    if (this.time.now - this.lastHitTime < this.hitCooldown) return;
    this.lastHitTime = this.time.now;
    const swingX = pointer ? pointer.worldX : this.hitX;
    const swingY = pointer ? pointer.worldY : this.hitY;
    if (this.currentTempStage === 'COLD' || this.currentTempStage === 'NORMAL') { this.showFeedback('TOO COLD!', 0x3b82f6, 1.0); return; }

    const diff = Math.abs(this.currentRadius - this.targetRadius);
    const eff = this.currentTempStage === 'AURA' ? 1.5 : this.currentTempStage === 'HOT' ? 1.0 : 0.5;

    if (diff < 18) {
      // --- PERFECT ---
      this.score += Math.ceil(8 * eff); 
      this.combo++; 
      this.perfectCount++;

      // Accumulate 5 perfects, starting from 6th increase quality by 1 (No Max Limit)
      if (this.perfectCount >= 6) {
          this.currentQuality += 1;
          this.showFeedback('+1 QUALITY!', 0xfbbf24, 1.3, swingX, swingY - 40);
      }

      this.createSparks(40, 0xffaa00, 2.0, 'spark_perfect', swingX, swingY); 
      this.showFeedback('PERFECT!', 0xffb300, 1.5, swingX, swingY); 
      this.cameras.main.shake(200, 0.025);
    } else if (diff < 55) {
      // --- GOOD ---
      this.score += Math.ceil(5 * eff); 
      this.combo = 0; 
      this.currentQuality = Math.max(0, this.currentQuality - 2);

      this.createSparks(20, 0xffffff, 1.3, 'spark_normal', swingX, swingY); 
      this.showFeedback('GOOD', 0xe5e5e5, 1.0, swingX, swingY);
      this.showFeedback('-2 QUALITY', 0xa8a29e, 0.8, swingX, swingY - 40);
    } else {
      // --- MISS ---
      this.score = Math.max(0, this.score - 5); 
      this.combo = 0; 
      this.currentQuality = Math.max(0, this.currentQuality - 5);

      this.showFeedback('MISS', 0xef4444, 1.2, swingX, swingY); 
      this.showFeedback('-5 QUALITY', 0xef4444, 1.0, swingX, swingY - 40);
      this.cameras.main.shake(120, 0.012);
    }

    this.updateProgressBar();
    if (this.score >= this.targetScore) this.winGame(); else this.resetRing();
  }

  private handleOffMetalMiss() {
    this.score = Math.max(0, this.score - 5); 
    this.combo = 0; 
    this.currentQuality = Math.max(0, this.currentQuality - 5);

    this.cameras.main.shake(100, 0.015);
    this.showFeedback('OFF METAL!', 0xffffff, 1.2); 
    this.showFeedback('-5 QUALITY', 0xef4444, 1.0);
    this.updateProgressBar(); 
    this.resetRing();
  }

  private handleSpatialMiss() {
    this.score = Math.max(0, this.score - 5); 
    this.combo = 0; 
    this.currentQuality = Math.max(0, this.currentQuality - 5);

    this.cameras.main.shake(120, 0.012);
    this.showFeedback('MISS', 0xef4444, 1.2); 
    this.showFeedback('-5 QUALITY', 0xef4444, 1.0);
    this.updateProgressBar(); 
    this.resetRing();
  }

  update(time: number, delta: number) {
    if (this.isFinished) return;
    if (this.isPlaying) this.handleRingLogic(delta);
    this.temperature = Math.max(0, this.temperature - this.coolingRate * (delta / 1000));
    this.refreshVisuals();
    if (!this.isPlaying && this.isReadyToStart && this.temperature <= 0) {
      this.isReadyToStart = false;
      this.infoText.setText('FORGE IS COLD\nADD FUEL TO HEAT').setColor('#3b82f6');
    }
  }

  private refreshVisuals() {
    // Quality Text & Grade Update
    const grade = this.getQualityGrade(this.currentQuality);
    const colorStr = this.getGradeColor(this.currentQuality);
    this.qualityText.setText(`QUALITY: ${this.currentQuality}% [${grade}]`);
    this.qualityText.setColor(colorStr);

    const ratio = this.temperature / 100;
    this.tempBar.scaleY = ratio;
    this.tempValueText.setText(`${Math.floor(20 + ratio * 1480)}°C`);
    const current = Phaser.Display.Color.Interpolate.ColorWithColor(new Phaser.Display.Color(63, 63, 70), new Phaser.Display.Color(253, 230, 138), 100, ratio * 100);
    const color = Phaser.Display.Color.GetColor(current.r, current.g, current.b);
    this.bladeFallbackRect.setFillStyle(color, 1);
    if (this.bladeImage) this.bladeImage.setTint(color);
    const progress = Phaser.Math.Clamp(this.score / this.targetScore, 0, 1);
    const stage = Math.min(5, Math.floor(progress * 6));
    if (stage !== this.lastStage) { this.setBladeStage(stage); this.lastStage = stage; }
    if (this.ambientGlow) this.ambientGlow.setAlpha(ratio * 0.4);
    if (this.temperature <= 0) this.currentTempStage = 'COLD';
    else if (this.temperature > 75) this.currentTempStage = 'AURA';
    else if (this.temperature > 40) this.currentTempStage = 'HOT';
    else if (this.temperature > 15) this.currentTempStage = 'WARM';
    else this.currentTempStage = 'NORMAL';
  }

  private setBladeStage(stage: number) {
    const key = `blade_stage_${stage}`;
    if (this.textures.exists(key)) {
      if (!this.bladeImage) { this.bladeImage = this.add.image(0, 0, key).setOrigin(0.5); this.bladeContainer.add(this.bladeImage); } 
      else this.bladeImage.setTexture(key);
      this.bladeImage.setVisible(true);
      this.bladeFallbackRect.setVisible(true).setAlpha(0.15);
      if (this.lastStage !== -1) {
          this.createOmniBurst(70, 0xffcc00, 2.5, 'spark_perfect', this.bladeContainer.x, this.bladeContainer.y);
          this.flashOverlay.setFillStyle(0xffcc00, 1).setAlpha(0.35);
          this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 250, ease: 'Quad.easeOut' });
          this.tweens.add({ targets: this.bladeContainer, scale: 1.15, duration: 100, yoyo: true, ease: 'Quad.easeOut' });
      }
    }
  }

  private handleRingLogic(delta: number) {
    this.ringTimer += delta;
    const t = Math.min(this.ringTimer / this.shrinkDuration, 1.5);
    this.currentRadius = this.startRadius * (1 - t * t);
    const ringColor = this.currentRadius < this.targetRadius ? 0xffffff : 0xfabf24;
    this.approachRing.clear().lineStyle(8, ringColor, 0.6).strokeCircle(this.hitX, this.hitY, Math.max(0, this.currentRadius));
    if (this.currentRadius < this.targetRadius - 30) { 
        this.combo = 0; 
        this.resetRing(); 
    }
  }

  private resetRing() {
    if (this.temperature <= 0) {
      this.isPlaying = false; this.isReadyToStart = false;
      this.targetRing.clear(); this.approachRing.clear();
      this.infoText.setVisible(true).setText('FORGE IS COLD\nADD FUEL TO HEAT').setColor('#3b82f6');
      return;
    }
    this.currentRadius = this.startRadius; this.ringTimer = 0;
    const w = this.hammerHitArea.width * this.hammerHitArea.scaleX;
    const h = this.hammerHitArea.height * this.hammerHitArea.scaleY;
    const u = Phaser.Math.Between(-w * 0.35, w * 0.35);
    const v = Phaser.Math.Between(-h * 0.25, h * 0.25);
    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    this.hitX = this.hammerHitArea.x + (u * Math.cos(rad) - v * Math.sin(rad));
    this.hitY = this.hammerHitArea.y + (u * Math.sin(rad) + v * Math.cos(rad));
    if (this.isPlaying) {
      this.targetRing.clear().fillStyle(0xfabf24, 0.1).fillCircle(this.hitX, this.hitY, this.targetRadius).lineStyle(5, 0xfabf24, 0.4).strokeCircle(this.hitX, this.hitY, this.targetRadius);
    }
  }

  private updateProgressBar() { this.progressBar.width = Phaser.Math.Clamp((this.score / this.targetScore) * 300, 0, 300); }

  private createSparks(count: number, color: number, scale: number, key: string, x: number, y: number) {
    const emitter = this.add.particles(x, y, this.textures.exists(key) ? key : 'white', { lifespan: 800, speed: { min: 300 * scale, max: 700 * scale }, angle: { min: 230, max: 310 }, scale: { start: 0.7, end: 0 }, gravityY: 1200, blendMode: 'ADD', tint: color });
    emitter.explode(count);
  }

  private createOmniBurst(count: number, color: number, scale: number, key: string, x: number, y: number) {
    const emitter = this.add.particles(x, y, this.textures.exists(key) ? key : 'white', { lifespan: 1200, speed: { min: 200 * scale, max: 500 * scale }, angle: { min: 0, max: 360 }, scale: { start: 0.8, end: 0 }, gravityY: 400, blendMode: 'ADD', tint: color });
    emitter.explode(count);
  }

  private showFeedback(text: string, color: number, scale: number, x?: number, y?: number) {
    const fx = x ?? this.hitX; const fy = y ?? this.hitY;
    const fb = this.add.text(fx, fy - 140, text, { fontFamily: 'Arial', fontSize: '36px', fontStyle: 'bold', color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setScale(0.5).setAlpha(0).setDepth(25);
    this.tweens.add({ targets: fb, y: fy - 200, alpha: 1, scale: scale, duration: 250, hold: 400, yoyo: true, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, scale: { from: 1.5, to: 1 }, duration: 200, alpha: { from: 1, to: 0 }, delay: 500 }); }
  }

  private winGame() {
    this.isFinished = true; this.isPlaying = false; this.targetRing.clear(); this.approachRing.clear();
    if (this.onStatusUpdate) this.onStatusUpdate(this.temperature);
    const bg = this.add.rectangle(this.centerX, this.centerY, this.scale.width, this.scale.height, 0x000000).setAlpha(0).setDepth(100);
    this.tweens.add({ targets: bg, alpha: 0.85, duration: 500 });
    const grade = this.getQualityGrade(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${grade} GRADE BLADE!`, { fontFamily: 'Georgia', fontSize: '72px', color: this.getGradeColor(this.currentQuality), stroke: '#000', strokeThickness: 3 }).setOrigin(0.5).setAlpha(0).setDepth(101);
    this.tweens.add({ targets: txt, alpha: 1, scale: { from: 0.5, to: 1.2 }, duration: 600, ease: 'Back.out', onComplete: () => { this.time.delayedCall(1000, () => { if (this.onComplete) this.onComplete(this.currentQuality); }); } });
  }

  public getTemperature() { return this.temperature; }
}

import { EquipmentItem } from '../types/inventory';
import { Equipment, EquipmentRarity, EquipmentType, EquipmentStats } from '../models/Equipment';
import { MASTERY_THRESHOLDS } from '../config/mastery-config';

const mapSubCategoryToType = (subCat: string): EquipmentType => {
    return subCat as EquipmentType; 
};

export const getEnergyCost = (item: EquipmentItem, masteryCount: number): number => {
    let cost = 20; 
    if (masteryCount >= MASTERY_THRESHOLDS.ARTISAN) {
        cost -= MASTERY_THRESHOLDS.ARTISAN_BONUS.energyDiscount;
    }
    return Math.max(5, cost);
};

export const generateEquipment = (recipe: EquipmentItem, quality: number, masteryCount: number, bonus: number = 0): Equipment => {
    let statMultiplier = 1.0;
    let priceMultiplier = 1.0;
    let namePrefix = '';

    if (masteryCount >= MASTERY_THRESHOLDS.ARTISAN) {
        statMultiplier = MASTERY_THRESHOLDS.ARTISAN_BONUS.stats;
        priceMultiplier = MASTERY_THRESHOLDS.ARTISAN_BONUS.price;
        namePrefix = MASTERY_THRESHOLDS.ARTISAN_BONUS.prefix;
    } else if (masteryCount >= MASTERY_THRESHOLDS.ADEPT) {
        statMultiplier = MASTERY_THRESHOLDS.ADEPT_BONUS.stats;
        priceMultiplier = MASTERY_THRESHOLDS.ADEPT_BONUS.price;
        namePrefix = MASTERY_THRESHOLDS.ADEPT_BONUS.prefix;
    }

    let rarity = EquipmentRarity.COMMON;
    if (quality >= 110) rarity = EquipmentRarity.LEGENDARY; // S+ Grade
    else if (quality >= 100) rarity = EquipmentRarity.EPIC;  // S Grade
    else if (quality >= 85) rarity = EquipmentRarity.RARE;
    else if (quality >= 60) rarity = EquipmentRarity.UNCOMMON;

    // Quality Multiplier scales linearly even above 100%
    // 100% Quality -> 1.2 Multiplier
    // 120% Quality -> 1.34 Multiplier
    const qualityMultiplier = 0.5 + (quality / 100) * 0.7; 
    const finalMultiplier = qualityMultiplier * statMultiplier;

    const base = recipe.baseStats || { physicalAttack: 0, physicalDefense: 0, magicalAttack: 0, magicalDefense: 0 };

    const stats: EquipmentStats = {
        physicalAttack: Math.round(base.physicalAttack * finalMultiplier),
        physicalDefense: Math.round(base.physicalDefense * finalMultiplier),
        magicalAttack: Math.round(base.magicalAttack * finalMultiplier),
        magicalDefense: Math.round(base.magicalDefense * finalMultiplier),
    };

    if (bonus > 0) {
        const s = stats;
        if (s.physicalAttack >= s.magicalAttack && s.physicalAttack >= s.physicalDefense && s.physicalAttack >= s.magicalDefense) {
            s.physicalAttack += bonus;
        } else if (s.magicalAttack >= s.physicalAttack && s.magicalAttack >= s.physicalDefense && s.magicalAttack >= s.magicalDefense) {
            s.magicalAttack += bonus;
        } else if (s.physicalDefense >= s.physicalAttack && s.physicalDefense >= s.magicalAttack && s.physicalDefense >= s.magicalDefense) {
            s.physicalDefense += bonus;
        } else {
            s.magicalDefense += bonus;
        }
    }

    const price = Math.round(recipe.baseValue * finalMultiplier * priceMultiplier);

    return {
        id: `${recipe.id}_${Date.now()}_${Math.floor(Math.random() * 1000)}`,
        recipeId: recipe.id,
        name: namePrefix ? `${namePrefix} ${recipe.name}` : recipe.name,
        type: mapSubCategoryToType(recipe.subCategoryId),
        quality: quality,
        rarity: rarity,
        price: price,
        icon: recipe.icon,
        description: recipe.description,
        stats: stats,
        specialAbilities: [], 
        durability: recipe.maxDurability, 
        maxDurability: recipe.maxDurability,
        isRepairable: recipe.isRepairable,
        equipRequirements: recipe.equipRequirements,
        craftedDate: Date.now(),
        previousOwners: [], 
        slotType: recipe.slotType,
        isTwoHanded: recipe.isTwoHanded
    };
};

import { GameState, InventoryItem } from '../../types/index';
import { EquipmentItem } from '../../types/inventory';
import { getEnergyCost, generateEquipment } from '../../utils/craftingLogic';
import { MATERIALS } from '../../data/materials';

// Helper for Grade mapping (Matches SmithingScene logic)
const getGrade = (q: number) => {
    if (q >= 120) return "SSS";
    if (q >= 110) return "SS";
    if (q >= 100) return "S";
    if (q >= 90) return "A";
    if (q >= 80) return "B";
    if (q >= 70) return "C";
    if (q >= 60) return "D";
    return "F";
};

export const handleStartCrafting = (state: GameState, payload: { item: EquipmentItem }): GameState => {
    const { item } = payload;
    const masteryCount = state.craftingMastery[item.id] || 0;
    const energyCost = getEnergyCost(item, masteryCount);

    if (state.stats.energy < energyCost) return state;

    // Check Resources
    const hasResources = item.requirements.every(req => {
        const invItem = state.inventory.find(i => i.id === req.id);
        return invItem && invItem.quantity >= req.count;
    });
    if (!hasResources) return state;

    // Deduct Resources
    let newInventory = [...state.inventory];
    item.requirements.forEach(req => {
        newInventory = newInventory.map(invItem => {
            if (invItem.id === req.id) {
                return { ...invItem, quantity: invItem.quantity - req.count };
            }
            return invItem;
        }).filter(i => i.quantity > 0);
    });

    return {
        ...state,
        isCrafting: true,
        stats: { ...state.stats, energy: state.stats.energy - energyCost },
        inventory: newInventory,
    };
};

export const handleCancelCrafting = (state: GameState, payload: { item: EquipmentItem }): GameState => {
    const { item } = payload;
    const masteryCount = state.craftingMastery[item.id] || 0;
    const energyCost = getEnergyCost(item, masteryCount);

    // Refund Resources
    let newInventory = [...state.inventory];
    item.requirements.forEach(req => {
        const existing = newInventory.find(i => i.id === req.id);
        if (existing) {
            newInventory = newInventory.map(i => i.id === req.id ? { ...i, quantity: i.quantity + req.count } : i);
        } else {
            const itemDef = Object.values(MATERIALS).find(m => m.id === req.id);
            if (itemDef) {
                newInventory.push({ ...itemDef, quantity: req.count } as InventoryItem);
            }
        }
    });

    return {
        ...state,
        isCrafting: false,
        stats: { ...state.stats, energy: state.stats.energy + energyCost },
        inventory: newInventory,
        logs: [`Cancelled work on ${item.name}. Materials restored.`, ...state.logs]
    };
};

export const handleFinishCrafting = (state: GameState, payload: { item: EquipmentItem; quality: number; bonus?: number }): GameState => {
    const { item, quality, bonus = 0 } = payload;
    const masteryCount = state.craftingMastery[item.id] || 0;

    const equipment = generateEquipment(item, quality, masteryCount, bonus);
    const newInventory = [...state.inventory];

    newInventory.push({
        id: equipment.id, 
        name: equipment.name,
        type: 'EQUIPMENT',
        description: item.description,
        baseValue: equipment.price,
        icon: item.icon,
        quantity: 1,
        equipmentData: equipment
    });

    const newMastery = { ...state.craftingMastery };
    newMastery[item.id] = (masteryCount || 0) + 1;

    const grade = getGrade(quality);
    let logMsg = `Successfully crafted [Grade ${grade}] ${item.name} (Quality: ${quality}%)!`;
    if (bonus > 0) logMsg += ` Minigame Bonus: +${bonus} Primary Stat.`;

    return {
        ...state,
        isCrafting: false,
        inventory: newInventory,
        craftingMastery: newMastery,
        logs: [logMsg, ...state.logs]
    };
};

export const handleSetCrafting = (state: GameState, isCrafting: boolean): GameState => {
    return { ...state, isCrafting };
};

export const handleUpdateForgeStatus = (state: GameState, payload: { temp: number }): GameState => {
    return {
        ...state,
        forgeTemperature: payload.temp,
        lastForgeTime: Date.now()
    };
};

