import { PrimaryStats } from './Stats';

export type EquipmentSlotType = 'MAIN_HAND' | 'OFF_HAND' | 'HEAD' | 'BODY' | 'HANDS' | 'FEET' | 'ACCESSORY';

export enum EquipmentRarity {
  COMMON = 'Common',
  UNCOMMON = 'Uncommon',
  RARE = 'Rare',
  EPIC = 'Epic',
  LEGENDARY = 'Legendary'
}

export enum EquipmentType {
  SWORD = 'Sword',
  AXE = 'Axe',
  MACE = 'Mace',
  STAFF = 'Staff',
  DAGGER = 'Dagger',
  HELMET = 'Helmet',
  CHESTPLATE = 'Chestplate',
  SHIELD = 'Shield',
  GLOVES = 'Gloves',
  BOOTS = 'Boots',
}

export interface EquipmentStats {
  physicalAttack: number;
  physicalDefense: number;
  magicalAttack: number;
  magicalDefense: number;
}

export interface SpecialAbility {
  id: string;
  name: string;
  description: string;
  value?: number;
}

export interface Equipment {
  id: string;
  recipeId?: string;
  name: string;
  type: EquipmentType;
  quality: number;
  rarity: EquipmentRarity;
  price: number;

  icon?: string;
  description?: string;

  // 전투 스탯
  stats: EquipmentStats;

  // 미니게임 보너스 정보
  appliedBonus?: {
    stat: keyof EquipmentStats;
    value: number;
  };

  // 특수 능력
  specialAbilities: SpecialAbility[];

  // 내구도 시스템
  durability: number;      // 현재 내구도
  maxDurability: number;   // 최대 내구도
  isRepairable: boolean;   // 수리 가능 여부

  // 장착 가이드 (최소 스탯)
  equipRequirements?: Partial<PrimaryStats>;

  // 메타데이터
  craftedDate?: number;
  crafterName?: string;
  previousOwners?: string[]; 

  // 슬롯 정보
  slotType: EquipmentSlotType;
  isTwoHanded?: boolean;
}

import { EquipmentItem } from '../types/inventory';
import { Equipment, EquipmentRarity, EquipmentType, EquipmentStats } from '../models/Equipment';
import { MASTERY_THRESHOLDS } from '../config/mastery-config';

const mapSubCategoryToType = (subCat: string): EquipmentType => {
    return subCat as EquipmentType; 
};

export const getEnergyCost = (item: EquipmentItem, masteryCount: number): number => {
    let cost = 20; 
    if (masteryCount >= MASTERY_THRESHOLDS.ARTISAN) {
        cost -= MASTERY_THRESHOLDS.ARTISAN_BONUS.energyDiscount;
    }
    return Math.max(5, cost);
};

export const generateEquipment = (recipe: EquipmentItem, quality: number, masteryCount: number, bonus: number = 0): Equipment => {
    let statMultiplier = 1.0;
    let priceMultiplier = 1.0;
    let namePrefix = '';

    if (masteryCount >= MASTERY_THRESHOLDS.ARTISAN) {
        statMultiplier = MASTERY_THRESHOLDS.ARTISAN_BONUS.stats;
        priceMultiplier = MASTERY_THRESHOLDS.ARTISAN_BONUS.price;
        namePrefix = MASTERY_THRESHOLDS.ARTISAN_BONUS.prefix;
    } else if (masteryCount >= MASTERY_THRESHOLDS.ADEPT) {
        statMultiplier = MASTERY_THRESHOLDS.ADEPT_BONUS.stats;
        priceMultiplier = MASTERY_THRESHOLDS.ADEPT_BONUS.price;
        namePrefix = MASTERY_THRESHOLDS.ADEPT_BONUS.prefix;
    }

    let rarity = EquipmentRarity.COMMON;
    if (quality >= 110) rarity = EquipmentRarity.LEGENDARY; 
    else if (quality >= 100) rarity = EquipmentRarity.EPIC;  
    else if (quality >= 85) rarity = EquipmentRarity.RARE;
    else if (quality >= 60) rarity = EquipmentRarity.UNCOMMON;

    const qualityMultiplier = (quality / 100); 
    const finalMultiplier = qualityMultiplier * statMultiplier;

    const base = recipe.baseStats || { physicalAttack: 0, physicalDefense: 0, magicalAttack: 0, magicalDefense: 0 };

    const stats: EquipmentStats = {
        physicalAttack: Math.round(base.physicalAttack * finalMultiplier),
        physicalDefense: Math.round(base.physicalDefense * finalMultiplier),
        magicalAttack: Math.round(base.magicalAttack * finalMultiplier),
        magicalDefense: Math.round(base.magicalDefense * finalMultiplier),
    };

    let appliedBonus: Equipment['appliedBonus'] = undefined;

    if (bonus > 0) {
        let targetStat: keyof EquipmentStats = 'physicalAttack';
        if (stats.magicalAttack > stats.physicalAttack) {
            targetStat = 'magicalAttack';
        } else if (stats.physicalDefense > stats.physicalAttack && stats.physicalDefense > stats.magicalAttack) {
            targetStat = 'physicalDefense';
        } else if (stats.magicalDefense > stats.physicalAttack && stats.magicalDefense > stats.magicalAttack) {
            targetStat = 'magicalDefense';
        }

        stats[targetStat] += bonus;
        appliedBonus = { stat: targetStat, value: bonus };
    }

    const price = Math.round(recipe.baseValue * finalMultiplier * priceMultiplier);

    return {
        id: `${recipe.id}_${Date.now()}_${Math.floor(Math.random() * 1000)}`,
        recipeId: recipe.id,
        name: namePrefix ? `${namePrefix} ${recipe.name}` : recipe.name,
        type: mapSubCategoryToType(recipe.subCategoryId),
        quality: quality,
        rarity: rarity,
        price: price,
        icon: recipe.icon,
        description: recipe.description,
        stats: stats,
        appliedBonus,
        specialAbilities: [], 
        durability: recipe.maxDurability, 
        maxDurability: recipe.maxDurability,
        isRepairable: recipe.isRepairable,
        equipRequirements: recipe.equipRequirements,
        craftedDate: Date.now(),
        previousOwners: [], 
        slotType: recipe.slotType,
        isTwoHanded: recipe.isTwoHanded
    };
};

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

export interface SmithingSceneData {
  onComplete: (score: number) => void;
  onStatusUpdate?: (temp: number) => void;
  onHeatUpRequest?: () => void;
  difficulty: number;
  initialTemp: number;
  charcoalCount: number;
}

export default class SmithingScene extends Phaser.Scene {
  // Core Systems
  private backgroundTile!: Phaser.GameObjects.TileSprite;
  private bgOverlay!: Phaser.GameObjects.Rectangle;
  private anvilImage!: Phaser.GameObjects.Image;
  private anvilSurface!: Phaser.GameObjects.Graphics;
  private targetRing!: Phaser.GameObjects.Graphics;
  private approachRing!: Phaser.GameObjects.Graphics;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private comboText!: Phaser.GameObjects.Text;
  private infoText!: Phaser.GameObjects.Text;
  private ambientGlow!: Phaser.GameObjects.Arc;
  private flashOverlay!: Phaser.GameObjects.Rectangle;

  private bladeContainer!: Phaser.GameObjects.Container;
  private bladeFallbackRect!: Phaser.GameObjects.Rectangle;
  private bladeImage?: Phaser.GameObjects.Image;

  private hammerHitArea!: Phaser.GameObjects.Rectangle;
  private hitPoly!: Phaser.Geom.Polygon;

  // Layout Constants
  private centerX: number = 0;
  private centerY: number = 0;
  private hitX: number = 0;
  private hitY: number = 0;

  private anvilConfig = {
    topWidthRatio: 0.65,
    botWidthRatio: 1.1,
    heightRatio: 0.4,
    yOffset: 60,
    imageOffsetX: 0,
    imageOffsetY: 40,
    hitAreaOffset: 45, 
  };

  // Game State
  private score: number = 0; // Progress
  private targetScore: number = 100;
  private combo: number = 0;
  private lastHitTime: number = 0;
  private hitCooldown: number = 200;
  private lastStage: number = -1;
  private isFinished: boolean = false;
  private isPlaying: boolean = false;
  private isReadyToStart: boolean = false;

  // Quality System
  private currentQuality: number = 100;
  private perfectCount: number = 0;
  private qualityText!: Phaser.GameObjects.Text;

  // Temperature System
  private temperature: number = 0;
  private coolingRate: number = 2;
  private currentTempStage: 'COLD' | 'AURA' | 'HOT' | 'WARM' | 'NORMAL' = 'COLD';
  private charcoalCount: number = 0;

  // Ring System
  private startRadius: number = 220;
  private targetRadius: number = 55;
  private currentRadius: number = 220;
  private shrinkDuration: number = 2000;
  private ringTimer: number = 0;

  // UI
  private tempBar!: Phaser.GameObjects.Rectangle;
  private tempValueText!: Phaser.GameObjects.Text;
  private bellowsContainer!: Phaser.GameObjects.Container;
  private bellowsSprite!: Phaser.GameObjects.Sprite;
  private heatUpBtnContainer!: Phaser.GameObjects.Container;
  private uiContainer!: Phaser.GameObjects.Container;
  private isPumping: boolean = false;

  // External Callbacks
  private onComplete?: (score: number) => void;
  private onStatusUpdate?: (temp: number) => void;
  private onHeatUpRequest?: () => void;

  constructor() {
    super('SmithingScene');
  }

  // Helper to determine Thematic Label based on quality percentage (110+ Masterwork)
  public getQualityLabel(q: number): string {
    if (q >= 110) return "MASTERWORK";
    if (q >= 100) return "PRISTINE";
    if (q >= 90) return "SUPERIOR";
    if (q >= 80) return "FINE";
    if (q >= 70) return "STANDARD";
    if (q >= 60) return "RUSTIC";
    return "CRUDE";
  }

  // Helper to get Label Color
  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b'; // Masterwork (Amber/Gold)
    if (q >= 100) return '#fbbf24'; // Pristine (Yellow)
    if (q >= 90) return '#10b981';  // Superior (Emerald)
    if (q >= 80) return '#3b82f6';  // Fine (Blue)
    if (q >= 70) return '#a8a29e';  // Standard (Stone/Slate)
    if (q >= 60) return '#d97706';  // Rustic (Orange/Brown)
    return '#ef4444';               // Crude (Red)
  }

  init(data: SmithingSceneData) {
    this.onComplete = data.onComplete;
    this.onStatusUpdate = data.onStatusUpdate;
    this.onHeatUpRequest = data.onHeatUpRequest;
    this.charcoalCount = data.charcoalCount;
    this.shrinkDuration = Math.max(800, 2000 - data.difficulty * 200);
    this.coolingRate = 2 + data.difficulty * 0.8;

    this.score = 0;
    this.combo = 0;
    this.lastStage = -1;
    this.temperature = data.initialTemp || 0;
    this.isFinished = false;
    this.isPlaying = false;
    this.isReadyToStart = this.temperature > 0;

    this.currentQuality = 100;
    this.perfectCount = 0;
  }

  preload() {
    this.load.crossOrigin = 'anonymous';
    this.load.image('tile_forge', getAssetUrl('tile_forge.png'));
    this.load.image('anvil_img', getAssetUrl('anvil.png'));
    this.load.image('spark_perfect', getAssetUrl('particle_spark1.png'));
    this.load.image('spark_normal', getAssetUrl('particle_spark2.png'));
    this.load.image('blade_stage_0', getAssetUrl('billet_default.png'));
    this.load.image('blade_stage_1', getAssetUrl('billet_blade_01.png'));
    this.load.image('blade_stage_2', getAssetUrl('billet_blade_02.png'));
    this.load.image('blade_stage_3', getAssetUrl('billet_blade_03.png'));
    this.load.image('blade_stage_4', getAssetUrl('billet_blade_04.png'));
    this.load.image('blade_stage_5', getAssetUrl('billet_blade_05.png'));

    this.load.spritesheet('bellows', getAssetUrl('bellows_sprite.png'), {
      frameWidth: 298,
      frameHeight: 188,
    });
  }

  create() {
    if (!this.anims.exists('bellows_pump')) {
      this.anims.create({
        key: 'bellows_pump',
        frames: [0, 1, 2, 3, 4, 5, 6, 7].map(i => ({ key: 'bellows', frame: i })),
        frameRate: 18,
        repeat: 0,
      });
    }

    this.centerX = this.scale.width / 2;
    this.centerY = this.scale.height / 2;

    this.backgroundTile = this.add.tileSprite(0, 0, this.scale.width, this.scale.height, 'tile_forge').setOrigin(0).setDepth(-2).setAlpha(0.7);
    this.bgOverlay = this.add.rectangle(0, 0, this.scale.width, this.scale.height, 0x000000, 0.4).setOrigin(0).setDepth(-1);

    this.anvilImage = this.add.image(0, 0, 'anvil_img').setDepth(1).setOrigin(0.5, 0.5);
    this.anvilSurface = this.add.graphics().setDepth(2);

    this.bladeContainer = this.add.container(0, 0).setDepth(3).setAngle(-12);
    this.bladeFallbackRect = this.add.rectangle(0, 0, 600, 120, 0x57534e).setOrigin(0.5, 0.5);
    this.bladeContainer.add(this.bladeFallbackRect);

    if (this.textures.exists('blade_stage_0')) {
      this.bladeImage = this.add.image(0, 0, 'blade_stage_0').setOrigin(0.5);
      this.bladeContainer.add(this.bladeImage);
    }

    this.hammerHitArea = this.add.rectangle(0, 0, 500, 120, 0x00ff00).setDepth(3).setAlpha(0).setAngle(-12);
    this.targetRing = this.add.graphics().setDepth(5);
    this.approachRing = this.add.graphics().setDepth(5);

    this.uiContainer = this.add.container(0, 0).setDepth(20);
    this.setupUI();

    this.ambientGlow = this.add.circle(0, 0, 500, 0xea580c, 0).setFillStyle(0xea580c, 0.25).setDepth(0);
    this.flashOverlay = this.add.rectangle(0, 0, this.scale.width, this.scale.height, 0xffaa00, 0).setOrigin(0).setDepth(100);

    this.handleResize();

    this.input.keyboard?.on('keydown-SPACE', () => this.handleInput(), this);
    this.input.on('pointerdown', (pointer: Phaser.Input.Pointer, objs: any[]) => {
      if (objs.includes(this.bellowsContainer) || this.bellowsContainer.list.some(c => objs.includes(c))) {
        this.pumpBellows();
        return;
      }
      if (objs.includes(this.heatUpBtnContainer) || this.heatUpBtnContainer.list.some(c => objs.includes(c))) {
        this.requestHeatUp();
        return;
      }

      if (!this.isPlaying) {
        this.handleInput(pointer);
        return;
      }
      const px = pointer.worldX;
      const py = pointer.worldY;
      if (!this.isPointerInHitArea(px, py)) {
        this.handleMiss();
        return;
      }
      const dist = Phaser.Math.Distance.Between(px, py, this.hitX, this.hitY);
      if (dist > this.currentRadius + 4) {
        this.handleMiss();
        return;
      }
      this.handleInput(pointer);
    }, this);

    this.scale.on('resize', this.handleResize, this);
  }

  private setupUI() {
    this.progressBar = this.add.rectangle(0, 40, 0, 12, 0xeab308).setOrigin(0, 0.5);
    this.uiContainer.add([
      this.add.rectangle(0, 40, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e).setName('progBg'),
      this.progressBar,
    ]);

    this.qualityText = this.add.text(0, 65, 'PRISTINE', {
        fontFamily: 'monospace', fontSize: '18px', color: '#fbbf24', fontStyle: 'bold'
    }).setOrigin(0.5);
    this.uiContainer.add(this.qualityText);

    this.tempBar = this.add.rectangle(0, 0, 18, 250, 0x3b82f6).setOrigin(0.5, 1).setScale(1, 0);
    this.tempValueText = this.add.text(0, 0, '20°C', { fontFamily: 'monospace', fontSize: '18px', color: '#fff', fontStyle: 'bold' }).setOrigin(0.5);
    this.uiContainer.add([
      this.add.rectangle(0, 0, 32, 260, 0x1c1917).setStrokeStyle(3, 0x57534e).setName('tempFrame'),
      this.add.rectangle(0, 0, 24, 250, 0x0c0a09).setName('tempBg'),
      this.tempBar,
      this.tempValueText,
    ]);

    this.createBellows();
    this.createHeatUpButton();

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Impact', fontSize: '48px', color: '#fcd34d', stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setAlpha(0);
    this.infoText = this.add.text(0, 0, this.isReadyToStart ? 'CLICK TO START' : 'FORGE IS COLD\nADD FUEL TO HEAT', { fontFamily: 'monospace', fontSize: '28px', color: this.isReadyToStart ? '#fbbf24' : '#3b82f6', align: 'center', stroke: '#000', strokeThickness: 5 }).setOrigin(0.5);
    this.uiContainer.add([this.comboText, this.infoText]);
    this.tweens.add({ targets: this.infoText, alpha: 0.5, yoyo: true, repeat: -1, duration: 800 });
  }

  private createBellows() {
    this.bellowsContainer = this.add.container(0, 0);
    this.bellowsSprite = this.add.sprite(0, 0, 'bellows').setScale(0.35);
    const txt = this.add.text(0, 25, 'PUMP', { fontSize: '10px', color: '#fde68a', fontFamily: 'monospace', fontStyle: 'bold' }).setOrigin(0.5);
    this.bellowsContainer.add([this.bellowsSprite, txt]);
    this.bellowsContainer.setInteractive(new Phaser.Geom.Rectangle(-60, -45, 120, 90), Phaser.Geom.Rectangle.Contains);
    this.bellowsSprite.on('animationcomplete-bellows_pump', () => { this.isPumping = false; });
    this.uiContainer.add(this.bellowsContainer);
  }

  private createHeatUpButton() {
    this.heatUpBtnContainer = this.add.container(0, 0);
    const bg = this.add.rectangle(0, 0, 90, 70, 0x1c1917).setStrokeStyle(2, 0x57534e).setName('btnBg');
    const icon = this.add.text(0, -12, '🔥', { fontSize: '20px' }).setOrigin(0.5).setName('btnIcon');
    const label = this.add.text(0, 10, 'HEAT UP', { fontSize: '10px', color: '#fbbf24', fontStyle: 'bold', fontFamily: 'monospace' }).setOrigin(0.5);
    const countTxt = this.add.text(0, 22, `x${this.charcoalCount}`, { fontSize: '11px', color: '#78716c', fontFamily: 'monospace' }).setOrigin(0.5).setName('countTxt');
    this.heatUpBtnContainer.add([bg, icon, label, countTxt]);
    this.heatUpBtnContainer.setInteractive(new Phaser.Geom.Rectangle(-45, -35, 90, 70), Phaser.Geom.Rectangle.Contains);
    this.uiContainer.add(this.heatUpBtnContainer);
    this.refreshHeatUpButton();
  }

  private refreshHeatUpButton() {
    if (!this.heatUpBtnContainer) return;
    const bg = this.heatUpBtnContainer.getByName('btnBg') as Phaser.GameObjects.Rectangle;
    const countTxt = this.heatUpBtnContainer.getByName('countTxt') as Phaser.GameObjects.Text;
    const icon = this.heatUpBtnContainer.getByName('btnIcon') as Phaser.GameObjects.Text;
    countTxt.setText(`x${this.charcoalCount}`);
    if (this.charcoalCount > 0) {
      bg.setStrokeStyle(2, 0xea580c);
      countTxt.setColor('#a8a29e');
      icon.setAlpha(1);
    } else {
      bg.setStrokeStyle(2, 0x292524);
      countTxt.setColor('#44403c');
      icon.setAlpha(0.3);
    }
  }

  public updateCharcoalCount(count: number) {
    this.charcoalCount = count;
    this.refreshHeatUpButton();
  }

  private pumpBellows() {
    if (this.isPumping) return;
    this.isPumping = true;
    this.bellowsSprite.play('bellows_pump');

    if (this.temperature > 0) {
      this.temperature = Math.min(100, this.temperature + 5);
      if (!this.isPlaying && !this.isReadyToStart) {
        this.isReadyToStart = true;
        this.infoText.setText('CLICK TO START').setColor('#fbbf24');
      }
    }
  }

  private requestHeatUp() {
    if (this.charcoalCount > 0) {
      this.tweens.add({ targets: this.heatUpBtnContainer, scale: 0.9, duration: 50, yoyo: true });
      if (this.onHeatUpRequest) this.onHeatUpRequest();
    } else {
      this.cameras.main.shake(100, 0.005);
    }
  }

  public heatUp() {
    this.temperature = Math.min(100, this.temperature + 40);
    if (!this.isPlaying) {
      this.isReadyToStart = true;
      this.infoText.setText('CLICK TO START').setColor('#fbbf24');
    }
    this.flashOverlay.setFillStyle(0xff8800, 1).setAlpha(0.4);
    this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 400, ease: 'Cubic.easeOut' });
  }

  private handleResize() {
    this.centerX = this.scale.width / 2;
    this.centerY = this.scale.height / 2;
    if (this.backgroundTile) this.backgroundTile.setSize(this.scale.width, this.scale.height);
    if (this.bgOverlay) this.bgOverlay.setSize(this.scale.width, this.scale.height);
    if (this.flashOverlay) this.flashOverlay.setSize(this.scale.width, this.scale.height);

    const surfaceH = this.scale.height * this.anvilConfig.heightRatio;
    const b = this.centerY + surfaceH / 2 + this.anvilConfig.yOffset;

    if (this.anvilImage && this.anvilImage.texture.key !== '__MISSING') {
      const targetWidth = this.scale.width * 1.3;
      this.anvilImage.setScale(targetWidth / this.anvilImage.width);
      this.anvilImage.setPosition(this.centerX, b + this.anvilConfig.imageOffsetY);
    }

    if (this.ambientGlow) {
      this.ambientGlow.setPosition(this.centerX, b);
    }

    const bladeY = b - surfaceH * 0.55; 
    this.bladeContainer.setPosition(this.centerX, bladeY);
    const rad = Phaser.Math.DegToRad(this.bladeContainer.angle);
    this.bladeContainer.x += Math.cos(rad) * 80;
    this.bladeContainer.y += Math.sin(rad) * 80;

    const ox = -Math.sin(rad) * this.anvilConfig.hitAreaOffset;
    const oy = Math.cos(rad) * this.anvilConfig.hitAreaOffset;
    this.hammerHitArea.setPosition(this.bladeContainer.x + ox, this.bladeContainer.y + oy);
    this.rebuildHitPoly();

    this.repositionUIElements();
  }

  private repositionUIElements() {
    const w = this.scale.width;
    (this.uiContainer.getByName('progBg') as any).setPosition(this.centerX, 40);
    this.progressBar.setPosition(this.centerX - 150, 40);
    this.qualityText.setPosition(this.centerX, 65);
    const stackX = w - 70;
    const stackTopY = this.centerY - 100;
    this.tempValueText.setPosition(stackX, stackTopY - 165);
    (this.uiContainer.getByName('tempFrame') as any).setPosition(stackX, stackTopY);
    (this.uiContainer.getByName('tempBg') as any).setPosition(stackX, stackTopY);
    this.tempBar.setPosition(stackX, stackTopY + 125);
    this.bellowsContainer.setPosition(stackX, stackTopY + 205);
    this.heatUpBtnContainer.setPosition(stackX, stackTopY + 300);
    this.infoText.setPosition(this.centerX, this.centerY - 220);
    this.comboText.setPosition(this.centerX, this.centerY - 300);
  }

  private rebuildHitPoly() {
    const w = this.hammerHitArea.width * this.hammerHitArea.scaleX;
    const h = this.hammerHitArea.height * this.hammerHitArea.scaleY;
    const cx = this.hammerHitArea.x;
    const cy = this.hammerHitArea.y;
    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    const cos = Math.cos(rad);
    const sin = Math.sin(rad);
    const corners = [
      { x: -w / 2, y: -h / 2 }, { x: w / 2, y: -h / 2 },
      { x: w / 2, y: h / 2 }, { x: -w / 2, y: h / 2 },
    ].map((p) => ({ x: cx + p.x * cos - p.y * sin, y: cy + p.x * sin + p.y * cos }));
    this.hitPoly = new Phaser.Geom.Polygon(corners);
  }

  private isPointerInHitArea(px: number, py: number) {
    return this.hitPoly && Phaser.Geom.Polygon.Contains(this.hitPoly, px, py);
  }

  private handleInput(pointer?: Phaser.Input.Pointer) {
    if (this.isFinished) return;
    if (!this.isPlaying) {
      if (this.isReadyToStart) { 
        this.isPlaying = true; 
        this.infoText.setVisible(false); 
        this.resetRing(); 
        this.flashOverlay.setFillStyle(0xffffff, 1).setAlpha(0.2);
        this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 300 });
      } else { this.cameras.main.shake(50, 0.005); this.showFeedback('TOO COLD!', 0x3b82f6, 1.0); }
      return;
    }
    if (this.time.now - this.lastHitTime < this.hitCooldown) return;
    this.lastHitTime = this.time.now;
    const swingX = pointer ? pointer.worldX : this.hitX;
    const swingY = pointer ? pointer.worldY : this.hitY;
    if (this.currentTempStage === 'COLD' || this.currentTempStage === 'NORMAL') { this.showFeedback('TOO COLD!', 0x3b82f6, 1.0); return; }

    const diff = Math.abs(this.currentRadius - this.targetRadius);
    const eff = this.currentTempStage === 'AURA' ? 1.5 : this.currentTempStage === 'HOT' ? 1.0 : 0.5;

    if (diff < 18) {
      // --- PERFECT ---
      this.score += Math.ceil(8 * eff); 
      this.combo++; 
      this.perfectCount++;

      if (this.perfectCount >= 6) {
          this.currentQuality += 1;
          this.showFeedback('QUALITY UP!', 0xfbbf24, 1.3, swingX, swingY - 40);
      }

      this.createSparks(40, 0xffaa00, 2.0, 'spark_perfect', swingX, swingY); 
      this.showFeedback('PERFECT!', 0xffb300, 1.5, swingX, swingY); 
      this.cameras.main.shake(200, 0.025);
    } else if (diff < 55) {
      // --- GOOD ---
      this.score += Math.ceil(5 * eff); 
      this.combo = 0; 
      this.currentQuality = Math.max(0, this.currentQuality - 2);

      this.createSparks(20, 0xffffff, 1.3, 'spark_normal', swingX, swingY); 
      this.showFeedback('GOOD', 0xe5e5e5, 1.0, swingX, swingY);
    } else {
      // --- MISS ---
      this.handleMiss(swingX, swingY);
    }

    this.updateProgressBar();
    if (this.score >= this.targetScore) this.winGame(); else this.resetRing();
  }

  private handleMiss(x?: number, y?: number) {
    this.score = Math.max(0, this.score - 5); 
    this.combo = 0; 
    this.currentQuality = Math.max(0, this.currentQuality - 5);

    this.cameras.main.shake(120, 0.012);
    // Unified MISS message
    this.showFeedback('MISS', 0xef4444, 1.2, x, y); 
    this.updateProgressBar(); 
    this.resetRing();
  }

  update(time: number, delta: number) {
    if (this.isFinished) return;
    if (this.isPlaying) this.handleRingLogic(delta);
    this.temperature = Math.max(0, this.temperature - this.coolingRate * (delta / 1000));
    this.refreshVisuals();
    if (!this.isPlaying && this.isReadyToStart && this.temperature <= 0) {
      this.isReadyToStart = false;
      this.infoText.setText('FORGE IS COLD\nADD FUEL TO HEAT').setColor('#3b82f6');
    }
  }

  private refreshVisuals() {
    const label = this.getQualityLabel(this.currentQuality);
    const colorStr = this.getLabelColor(this.currentQuality);
    this.qualityText.setText(label);
    this.qualityText.setColor(colorStr);

    const ratio = this.temperature / 100;
    this.tempBar.scaleY = ratio;
    this.tempValueText.setText(`${Math.floor(20 + ratio * 1480)}°C`);
    const current = Phaser.Display.Color.Interpolate.ColorWithColor(new Phaser.Display.Color(63, 63, 70), new Phaser.Display.Color(253, 230, 138), 100, ratio * 100);
    const color = Phaser.Display.Color.GetColor(current.r, current.g, current.b);
    this.bladeFallbackRect.setFillStyle(color, 1);
    if (this.bladeImage) this.bladeImage.setTint(color);
    const progress = Phaser.Math.Clamp(this.score / this.targetScore, 0, 1);
    const stage = Math.min(5, Math.floor(progress * 6));
    if (stage !== this.lastStage) { this.setBladeStage(stage); this.lastStage = stage; }
    if (this.ambientGlow) this.ambientGlow.setAlpha(ratio * 0.4);
    if (this.temperature <= 0) this.currentTempStage = 'COLD';
    else if (this.temperature > 75) this.currentTempStage = 'AURA';
    else if (this.temperature > 40) this.currentTempStage = 'HOT';
    else if (this.temperature > 15) this.currentTempStage = 'WARM';
    else this.currentTempStage = 'NORMAL';
  }

  private setBladeStage(stage: number) {
    const key = `blade_stage_${stage}`;
    if (this.textures.exists(key)) {
      if (!this.bladeImage) { this.bladeImage = this.add.image(0, 0, key).setOrigin(0.5); this.bladeContainer.add(this.bladeImage); } 
      else this.bladeImage.setTexture(key);
      this.bladeImage.setVisible(true);
      this.bladeFallbackRect.setVisible(true).setAlpha(0.15);
      if (this.lastStage !== -1) {
          this.createOmniBurst(70, 0xffcc00, 2.5, 'spark_perfect', this.bladeContainer.x, this.bladeContainer.y);
          this.flashOverlay.setFillStyle(0xffcc00, 1).setAlpha(0.35);
          this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 250, ease: 'Quad.easeOut' });
          this.tweens.add({ targets: this.bladeContainer, scale: 1.15, duration: 100, yoyo: true, ease: 'Quad.easeOut' });
      }
    }
  }

  private handleRingLogic(delta: number) {
    this.ringTimer += delta;
    const t = Math.min(this.ringTimer / this.shrinkDuration, 1.5);
    this.currentRadius = this.startRadius * (1 - t * t);
    const ringColor = this.currentRadius < this.targetRadius ? 0xffffff : 0xfabf24;
    this.approachRing.clear().lineStyle(8, ringColor, 0.6).strokeCircle(this.hitX, this.hitY, Math.max(0, this.currentRadius));
    if (this.currentRadius < this.targetRadius - 30) { 
        this.combo = 0; 
        this.resetRing(); 
    }
  }

  private resetRing() {
    if (this.temperature <= 0) {
      this.isPlaying = false; this.isReadyToStart = false;
      this.targetRing.clear(); this.approachRing.clear();
      this.infoText.setVisible(true).setText('FORGE IS COLD\nADD FUEL TO HEAT').setColor('#3b82f6');
      return;
    }
    this.currentRadius = this.startRadius; this.ringTimer = 0;
    const w = this.hammerHitArea.width * this.hammerHitArea.scaleX;
    const h = this.hammerHitArea.height * this.hammerHitArea.scaleY;
    const u = Phaser.Math.Between(-w * 0.35, w * 0.35);
    const v = Phaser.Math.Between(-h * 0.25, h * 0.25);
    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    this.hitX = this.hammerHitArea.x + (u * Math.cos(rad) - v * Math.sin(rad));
    this.hitY = this.hammerHitArea.y + (u * Math.sin(rad) + v * Math.cos(rad));
    if (this.isPlaying) {
      this.targetRing.clear().fillStyle(0xfabf24, 0.1).fillCircle(this.hitX, this.hitY, this.targetRadius).lineStyle(5, 0xfabf24, 0.4).strokeCircle(this.hitX, this.hitY, this.targetRadius);
    }
  }

  private updateProgressBar() { this.progressBar.width = Phaser.Math.Clamp((this.score / this.targetScore) * 300, 0, 300); }

  private createSparks(count: number, color: number, scale: number, key: string, x: number, y: number) {
    const emitter = this.add.particles(x, y, this.textures.exists(key) ? key : 'white', { lifespan: 800, speed: { min: 300 * scale, max: 700 * scale }, angle: { min: 230, max: 310 }, scale: { start: 0.7, end: 0 }, gravityY: 1200, blendMode: 'ADD', tint: color });
    emitter.explode(count);
  }

  private createOmniBurst(count: number, color: number, scale: number, key: string, x: number, y: number) {
    const emitter = this.add.particles(x, y, this.textures.exists(key) ? key : 'white', { lifespan: 1200, speed: { min: 200 * scale, max: 500 * scale }, angle: { min: 0, max: 360 }, scale: { start: 0.8, end: 0 }, gravityY: 400, blendMode: 'ADD', tint: color });
    emitter.explode(count);
  }

  private showFeedback(text: string, color: number, scale: number, x?: number, y?: number) {
    const fx = x ?? this.hitX; const fy = y ?? this.hitY;
    const fb = this.add.text(fx, fy - 140, text, { fontFamily: 'Arial', fontSize: '36px', fontStyle: 'bold', color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setScale(0.5).setAlpha(0).setDepth(25);
    this.tweens.add({ targets: fb, y: fy - 200, alpha: 1, scale: scale, duration: 250, hold: 400, yoyo: true, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, scale: { from: 1.5, to: 1 }, duration: 200, alpha: { from: 1, to: 0 }, delay: 500 }); }
  }

  private winGame() {
    this.isFinished = true; this.isPlaying = false; this.targetRing.clear(); this.approachRing.clear();
    if (this.onStatusUpdate) this.onStatusUpdate(this.temperature);
    const bg = this.add.rectangle(this.centerX, this.centerY, this.scale.width, this.scale.height, 0x000000).setAlpha(0).setDepth(100);
    this.tweens.add({ targets: bg, alpha: 0.85, duration: 500 });
    const label = this.getQualityLabel(this.currentQuality);
    // Generic text: label + CRAFT!
    const txt = this.add.text(this.centerX, this.centerY, `${label} CRAFT!`, { fontFamily: 'Georgia', fontSize: '72px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 3 }).setOrigin(0.5).setAlpha(0).setDepth(101);
    this.tweens.add({ targets: txt, alpha: 1, scale: { from: 0.5, to: 1.2 }, duration: 600, ease: 'Back.out', onComplete: () => { this.time.delayedCall(1000, () => { if (this.onComplete) this.onComplete(this.currentQuality); }); } });
  }

  public getTemperature() { return this.temperature; }
}

import React from 'react';
import { useGame } from '../../context/GameContext';
import { Hammer, Sword, Shield, Zap, Brain, Check, Star } from 'lucide-react';
import { getAssetUrl } from '../../utils';
import { EquipmentStats } from '../../models/Equipment';

const CraftingResultModal = () => {
    const { state, actions } = useGame();
    const item = state.lastCraftedItem;

    if (!item || !item.equipmentData) return null;

    const data = item.equipmentData;
    const imageUrl = data.recipeId ? getAssetUrl(`${data.recipeId}.png`) : getAssetUrl(`${item.id.split('_')[0]}.png`);

    const getQualityLabel = (q: number): string => {
        if (q >= 110) return "Masterwork";
        if (q >= 100) return "Pristine";
        if (q >= 90) return "Superior";
        if (q >= 80) return "Fine";
        if (q >= 70) return "Standard";
        if (q >= 60) return "Rustic";
        return "Crude";
    };

    const getQualityColor = (q: number): string => {
        if (q >= 110) return 'text-amber-400';
        if (q >= 100) return 'text-yellow-400';
        if (q >= 90) return 'text-emerald-400';
        if (q >= 80) return 'text-blue-400';
        return 'text-stone-400';
    };

    const label = getQualityLabel(data.quality);
    const qColor = getQualityColor(data.quality);

    const renderStatItem = (icon: React.ReactNode, labelStr: string, statKey: keyof EquipmentStats, value: number) => {
        const bonusInfo = data.appliedBonus?.stat === statKey ? data.appliedBonus : null;
        const isBoosted = !!bonusInfo;

        // Tooltip for breakdown: "Base 14 + Bonus 3"
        const tooltip = isBoosted ? `Base ${value - bonusInfo!.value} + Bonus ${bonusInfo!.value}` : undefined;

        return (
            <div 
                className="bg-stone-950/50 p-3 rounded-xl border border-stone-800 flex justify-between items-center transition-all hover:bg-stone-900 group"
                title={tooltip}
            >
                <span className="text-[10px] text-stone-500 font-bold uppercase flex items-center gap-1.5 group-hover:text-stone-400">
                    {icon} {labelStr}
                </span>
                <span className={`text-sm font-mono font-bold ${isBoosted ? 'text-amber-400 drop-shadow-[0_0_8px_rgba(245,158,11,0.4)]' : 'text-stone-200'}`}>
                    {value}
                    {isBoosted && <span className="ml-1 text-[9px] animate-pulse">▲</span>}
                </span>
            </div>
        );
    };

    return (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/90 backdrop-blur-md animate-in fade-in duration-500">
            <div className="relative z-10 w-full max-w-md bg-stone-900 border-2 border-amber-600 rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95 duration-500">

                <div className="absolute top-20 left-1/2 -translate-x-1/2 w-48 h-48 bg-amber-500/10 blur-3xl rounded-full pointer-events-none"></div>

                {/* Header */}
                <div className="bg-stone-850 p-6 border-b border-stone-800 flex flex-col items-center text-center relative overflow-hidden">
                    <div className="absolute top-0 right-0 p-2 opacity-10">
                         <Hammer className="w-20 h-20 text-stone-500" />
                    </div>
                    <div className={`w-24 h-24 bg-stone-900 rounded-full border-4 ${qColor.replace('text-', 'border-')} flex items-center justify-center mb-4 shadow-2xl transform hover:scale-110 transition-transform duration-500`}>
                        <img 
                            src={imageUrl} 
                            className="w-16 h-16 object-contain drop-shadow-lg" 
                            onError={(e) => { e.currentTarget.style.display = 'none'; e.currentTarget.nextElementSibling?.classList.remove('hidden'); }}
                        />
                        <span className="hidden text-5xl">{item.icon || '📦'}</span>
                    </div>
                    <h2 className="text-2xl font-bold text-stone-200 font-serif tracking-wide">{data.name}</h2>
                    <div className={`flex items-center gap-2 mt-2 px-3 py-1 rounded-full bg-stone-950 border border-stone-800 font-bold uppercase tracking-widest text-[10px] ${qColor}`}>
                        <Star className="w-3 h-3 fill-current" />
                        {label} Quality
                    </div>
                </div>

                {/* Content */}
                <div className="p-6 space-y-5">
                    <p className="text-stone-400 text-sm text-center italic leading-relaxed px-4">
                        "{item.description}"
                    </p>

                    <div className="grid grid-cols-2 gap-3">
                        {renderStatItem(<Sword className="w-3 h-3" />, "P.Atk", "physicalAttack", data.stats.physicalAttack)}
                        {renderStatItem(<Shield className="w-3 h-3" />, "P.Def", "physicalDefense", data.stats.physicalDefense)}
                        {renderStatItem(<Zap className="w-3 h-3" />, "M.Atk", "magicalAttack", data.stats.magicalAttack)}
                        {renderStatItem(<Brain className="w-3 h-3" />, "M.Def", "magicalDefense", data.stats.magicalDefense)}
                    </div>

                    <div className="flex justify-between items-center text-xs border-t border-stone-800 pt-4 px-2">
                        <span className="text-stone-500 uppercase font-bold tracking-tighter">Market Value</span>
                        <span className="text-amber-500 font-mono font-bold text-lg">{data.price} G</span>
                    </div>
                </div>

                {/* Footer */}
                <div className="p-4 border-t border-stone-800 bg-stone-850">
                    <button 
                        onClick={actions.dismissCraftingResult}
                        className="w-full py-4 bg-amber-600 hover:bg-amber-500 text-white font-bold rounded-xl shadow-lg flex items-center justify-center gap-2 transition-all transform active:scale-95"
                    >
                        <Check className="w-5 h-5" />
                        Complete Forge
                    </button>
                </div>
            </div>
        </div>
    );
};

export default CraftingResultModal;

import { GameState, InventoryItem } from '../../types/index';
import { EquipmentItem } from '../../types/inventory';
import { getEnergyCost, generateEquipment } from '../../utils/craftingLogic';
import { MATERIALS } from '../../data/materials';

// Helper for Quality Label mapping (110+ is Masterwork)
const getQualityLabel = (q: number): string => {
    if (q >= 110) return "MASTERWORK";
    if (q >= 100) return "PRISTINE";
    if (q >= 90) return "SUPERIOR";
    if (q >= 80) return "FINE";
    if (q >= 70) return "STANDARD";
    if (q >= 60) return "RUSTIC";
    return "CRUDE";
};

export const handleStartCrafting = (state: GameState, payload: { item: EquipmentItem }): GameState => {
    const { item } = payload;
    const masteryCount = state.craftingMastery[item.id] || 0;
    const energyCost = getEnergyCost(item, masteryCount);

    if (state.stats.energy < energyCost) return state;

    // Check Resources
    const hasResources = item.requirements.every(req => {
        const invItem = state.inventory.find(i => i.id === req.id);
        return invItem && invItem.quantity >= req.count;
    });
    if (!hasResources) return state;

    // Deduct Resources
    let newInventory = [...state.inventory];
    item.requirements.forEach(req => {
        newInventory = newInventory.map(invItem => {
            if (invItem.id === req.id) {
                return { ...invItem, quantity: invItem.quantity - req.count };
            }
            return invItem;
        }).filter(i => i.quantity > 0);
    });

    return {
        ...state,
        isCrafting: true,
        stats: { ...state.stats, energy: state.stats.energy - energyCost },
        inventory: newInventory,
    };
};

export const handleCancelCrafting = (state: GameState, payload: { item: EquipmentItem }): GameState => {
    const { item } = payload;
    const masteryCount = state.craftingMastery[item.id] || 0;
    const energyCost = getEnergyCost(item, masteryCount);

    // Refund Resources
    let newInventory = [...state.inventory];
    item.requirements.forEach(req => {
        const existing = newInventory.find(i => i.id === req.id);
        if (existing) {
            newInventory = newInventory.map(i => i.id === req.id ? { ...i, quantity: i.quantity + req.count } : i);
        } else {
            const itemDef = Object.values(MATERIALS).find(m => m.id === req.id);
            if (itemDef) {
                newInventory.push({ ...itemDef, quantity: req.count } as InventoryItem);
            }
        }
    });

    return {
        ...state,
        isCrafting: false,
        stats: { ...state.stats, energy: state.stats.energy + energyCost },
        inventory: newInventory,
        logs: [`Cancelled work on ${item.name}. Materials restored.`, ...state.logs]
    };
};

export const handleFinishCrafting = (state: GameState, payload: { item: EquipmentItem; quality: number; bonus?: number }): GameState => {
    const { item, quality, bonus = 0 } = payload;
    const masteryCount = state.craftingMastery[item.id] || 0;

    const equipment = generateEquipment(item, quality, masteryCount, bonus);
    const newInventory = [...state.inventory];

    const newItem: InventoryItem = {
        id: equipment.id, 
        name: equipment.name,
        type: 'EQUIPMENT',
        description: item.description,
        baseValue: equipment.price,
        icon: item.icon,
        quantity: 1,
        equipmentData: equipment
    };

    newInventory.push(newItem);

    const newMastery = { ...state.craftingMastery };
    newMastery[item.id] = (masteryCount || 0) + 1;

    const label = getQualityLabel(quality);
    // Use generic phrasing and remove numeric percentage
    let logMsg = `Successfully crafted ${label.toLowerCase()} quality ${item.name}!`;
    if (bonus > 0) logMsg += ` Masterful technique applied a stat bonus.`;

    return {
        ...state,
        isCrafting: false,
        inventory: newInventory,
        craftingMastery: newMastery,
        lastCraftedItem: newItem,
        logs: [logMsg, ...state.logs]
    };
};

export const handleSetCrafting = (state: GameState, isCrafting: boolean): GameState => {
    return { ...state, isCrafting };
};

export const handleUpdateForgeStatus = (state: GameState, payload: { temp: number }): GameState => {
    return {
        ...state,
        forgeTemperature: payload.temp,
        lastForgeTime: Date.now()
    };
};

import Phaser from 'phaser';
import { getAssetUrl } from '../utils';

export interface SmithingSceneData {
  onComplete: (score: number) => void;
  onStatusUpdate?: (temp: number) => void;
  onHeatUpRequest?: () => void;
  difficulty: number;
  initialTemp: number;
  charcoalCount: number;
}

export default class SmithingScene extends Phaser.Scene {
  // Core Systems
  private backgroundTile!: Phaser.GameObjects.TileSprite;
  private bgOverlay!: Phaser.GameObjects.Rectangle;
  private anvilImage!: Phaser.GameObjects.Image;
  private anvilSurface!: Phaser.GameObjects.Graphics;
  private targetRing!: Phaser.GameObjects.Graphics;
  private approachRing!: Phaser.GameObjects.Graphics;
  private progressBar!: Phaser.GameObjects.Rectangle;
  private comboText!: Phaser.GameObjects.Text;
  private infoText!: Phaser.GameObjects.Text;
  private ambientGlow!: Phaser.GameObjects.Arc;
  private flashOverlay!: Phaser.GameObjects.Rectangle;

  private bladeContainer!: Phaser.GameObjects.Container;
  private bladeFallbackRect!: Phaser.GameObjects.Rectangle;
  private bladeImage?: Phaser.GameObjects.Image;

  private hammerHitArea!: Phaser.GameObjects.Rectangle;
  private hitPoly!: Phaser.Geom.Polygon;

  // Layout Constants
  private centerX: number = 0;
  private centerY: number = 0;
  private hitX: number = 0;
  private hitY: number = 0;

  private anvilConfig = {
    topWidthRatio: 0.65,
    botWidthRatio: 1.1,
    heightRatio: 0.4,
    yOffset: 60,
    imageOffsetX: 0,
    imageOffsetY: 40,
    hitAreaOffset: 45, 
  };

  // Game State
  private score: number = 0; // Progress
  private targetScore: number = 100;
  private combo: number = 0;
  private lastHitTime: number = 0;
  private hitCooldown: number = 200;
  private lastStage: number = -1;
  private isFinished: boolean = false;
  private isPlaying: boolean = false;
  private isReadyToStart: boolean = false;

  // Quality System
  private currentQuality: number = 100;
  private perfectCount: number = 0;
  private qualityText!: Phaser.GameObjects.Text;

  // Temperature System
  private temperature: number = 0;
  private coolingRate: number = 2;
  private currentTempStage: 'COLD' | 'AURA' | 'HOT' | 'WARM' | 'NORMAL' = 'COLD';
  private charcoalCount: number = 0;

  // Ring System
  private startRadius: number = 220;
  private targetRadius: number = 55;
  private currentRadius: number = 220;
  private shrinkDuration: number = 2000;
  private ringTimer: number = 0;

  // UI
  private tempBar!: Phaser.GameObjects.Rectangle;
  private tempValueText!: Phaser.GameObjects.Text;
  private bellowsContainer!: Phaser.GameObjects.Container;
  private bellowsSprite!: Phaser.GameObjects.Sprite;
  private heatUpBtnContainer!: Phaser.GameObjects.Container;
  private uiContainer!: Phaser.GameObjects.Container;
  private isPumping: boolean = false;

  // External Callbacks
  private onComplete?: (score: number) => void;
  private onStatusUpdate?: (temp: number) => void;
  private onHeatUpRequest?: () => void;

  constructor() {
    super('SmithingScene');
  }

  public getQualityLabel(q: number): string {
    if (q >= 110) return "MASTERWORK";
    if (q >= 100) return "PRISTINE";
    if (q >= 90) return "SUPERIOR";
    if (q >= 80) return "FINE";
    if (q >= 70) return "STANDARD";
    if (q >= 60) return "RUSTIC";
    return "CRUDE";
  }

  private getLabelColor(q: number): string {
    if (q >= 110) return '#f59e0b';
    if (q >= 100) return '#fbbf24';
    if (q >= 90) return '#10b981';
    if (q >= 80) return '#3b82f6';
    if (q >= 70) return '#a8a29e';
    if (q >= 60) return '#d97706';
    return '#ef4444';
  }

  init(data: SmithingSceneData) {
    this.onComplete = data.onComplete;
    this.onStatusUpdate = data.onStatusUpdate;
    this.onHeatUpRequest = data.onHeatUpRequest;
    this.charcoalCount = data.charcoalCount;
    this.shrinkDuration = Math.max(800, 2000 - data.difficulty * 200);
    this.coolingRate = 2 + data.difficulty * 0.8;

    this.score = 0;
    this.combo = 0;
    this.lastStage = -1;
    this.temperature = data.initialTemp || 0;
    this.isFinished = false;
    this.isPlaying = false;
    this.isReadyToStart = this.temperature > 0;

    this.currentQuality = 100;
    this.perfectCount = 0;
  }

  preload() {
    this.load.crossOrigin = 'anonymous';
    this.load.image('tile_forge', getAssetUrl('tile_forge.png'));
    this.load.image('anvil_img', getAssetUrl('anvil.png'));
    this.load.image('spark_perfect', getAssetUrl('particle_spark1.png'));
    this.load.image('spark_normal', getAssetUrl('particle_spark2.png'));
    this.load.image('blade_stage_0', getAssetUrl('billet_default.png'));
    this.load.image('blade_stage_1', getAssetUrl('billet_blade_01.png'));
    this.load.image('blade_stage_2', getAssetUrl('billet_blade_02.png'));
    this.load.image('blade_stage_3', getAssetUrl('billet_blade_03.png'));
    this.load.image('blade_stage_4', getAssetUrl('billet_blade_04.png'));
    this.load.image('blade_stage_5', getAssetUrl('billet_blade_05.png'));

    this.load.spritesheet('bellows', getAssetUrl('bellows_sprite.png'), {
      frameWidth: 298,
      frameHeight: 188,
    });
  }

  create() {
    if (!this.anims.exists('bellows_pump')) {
      this.anims.create({
        key: 'bellows_pump',
        frames: [0, 1, 2, 3, 4, 5, 6, 7].map(i => ({ key: 'bellows', frame: i })),
        frameRate: 18,
        repeat: 0,
      });
    }

    this.centerX = this.scale.width / 2;
    this.centerY = this.scale.height / 2;

    this.backgroundTile = this.add.tileSprite(0, 0, this.scale.width, this.scale.height, 'tile_forge').setOrigin(0).setDepth(-2).setAlpha(0.7);
    this.bgOverlay = this.add.rectangle(0, 0, this.scale.width, this.scale.height, 0x000000, 0.4).setOrigin(0).setDepth(-1);

    this.anvilImage = this.add.image(0, 0, 'anvil_img').setDepth(1).setOrigin(0.5, 0.5);
    this.anvilSurface = this.add.graphics().setDepth(2);

    this.bladeContainer = this.add.container(0, 0).setDepth(3).setAngle(-12);
    this.bladeFallbackRect = this.add.rectangle(0, 0, 600, 120, 0x57534e).setOrigin(0.5, 0.5);
    this.bladeContainer.add(this.bladeFallbackRect);

    if (this.textures.exists('blade_stage_0')) {
      this.bladeImage = this.add.image(0, 0, 'blade_stage_0').setOrigin(0.5);
      this.bladeContainer.add(this.bladeImage);
    }

    this.hammerHitArea = this.add.rectangle(0, 0, 500, 120, 0x00ff00).setDepth(3).setAlpha(0).setAngle(-12);
    this.targetRing = this.add.graphics().setDepth(5);
    this.approachRing = this.add.graphics().setDepth(5);

    this.uiContainer = this.add.container(0, 0).setDepth(20);
    this.setupUI();

    this.ambientGlow = this.add.circle(0, 0, 500, 0xea580c, 0).setFillStyle(0xea580c, 0.25).setDepth(0);
    this.flashOverlay = this.add.rectangle(0, 0, this.scale.width, this.scale.height, 0xffaa00, 0).setOrigin(0).setDepth(100);

    this.handleResize();

    this.input.keyboard?.on('keydown-SPACE', () => this.handleInput(), this);
    this.input.on('pointerdown', (pointer: Phaser.Input.Pointer, objs: any[]) => {
      if (objs.includes(this.bellowsContainer) || this.bellowsContainer.list.some(c => objs.includes(c))) {
        this.pumpBellows();
        return;
      }
      if (objs.includes(this.heatUpBtnContainer) || this.heatUpBtnContainer.list.some(c => objs.includes(c))) {
        this.requestHeatUp();
        return;
      }

      if (!this.isPlaying) {
        this.handleInput(pointer);
        return;
      }
      const px = pointer.worldX;
      const py = pointer.worldY;
      if (!this.isPointerInHitArea(px, py)) {
        this.handleMiss();
        return;
      }
      const dist = Phaser.Math.Distance.Between(px, py, this.hitX, this.hitY);
      if (dist > this.currentRadius + 4) {
        this.handleMiss();
        return;
      }
      this.handleInput(pointer);
    }, this);

    this.scale.on('resize', this.handleResize, this);
  }

  private setupUI() {
    this.progressBar = this.add.rectangle(0, 40, 0, 12, 0xeab308).setOrigin(0, 0.5);
    this.uiContainer.add([
      this.add.rectangle(0, 40, 300, 16, 0x000000, 0.5).setStrokeStyle(2, 0x57534e).setName('progBg'),
      this.progressBar,
    ]);

    this.qualityText = this.add.text(0, 65, 'PRISTINE', {
        fontFamily: 'monospace', fontSize: '18px', color: '#fbbf24', fontStyle: 'bold'
    }).setOrigin(0.5);
    this.uiContainer.add(this.qualityText);

    this.tempBar = this.add.rectangle(0, 0, 18, 250, 0x3b82f6).setOrigin(0.5, 1).setScale(1, 0);
    this.tempValueText = this.add.text(0, 0, '20°C', { fontFamily: 'monospace', fontSize: '18px', color: '#fff', fontStyle: 'bold' }).setOrigin(0.5);
    this.uiContainer.add([
      this.add.rectangle(0, 0, 32, 260, 0x1c1917).setStrokeStyle(3, 0x57534e).setName('tempFrame'),
      this.add.rectangle(0, 0, 24, 250, 0x0c0a09).setName('tempBg'),
      this.tempBar,
      this.tempValueText,
    ]);

    this.createBellows();
    this.createHeatUpButton();

    this.comboText = this.add.text(0, 0, '', { fontFamily: 'Impact', fontSize: '48px', color: '#fcd34d', stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setAlpha(0);
    this.infoText = this.add.text(0, 0, this.isReadyToStart ? 'CLICK TO START' : 'FORGE IS COLD\nADD FUEL TO HEAT', { fontFamily: 'monospace', fontSize: '28px', color: this.isReadyToStart ? '#fbbf24' : '#3b82f6', align: 'center', stroke: '#000', strokeThickness: 5 }).setOrigin(0.5);
    this.uiContainer.add([this.comboText, this.infoText]);
    this.tweens.add({ targets: this.infoText, alpha: 0.5, yoyo: true, repeat: -1, duration: 800 });
  }

  private createBellows() {
    this.bellowsContainer = this.add.container(0, 0);
    this.bellowsSprite = this.add.sprite(0, 0, 'bellows').setScale(0.35);
    const txt = this.add.text(0, 25, 'PUMP', { fontSize: '10px', color: '#fde68a', fontFamily: 'monospace', fontStyle: 'bold' }).setOrigin(0.5);
    this.bellowsContainer.add([this.bellowsSprite, txt]);
    this.bellowsContainer.setInteractive(new Phaser.Geom.Rectangle(-60, -45, 120, 90), Phaser.Geom.Rectangle.Contains);
    this.bellowsSprite.on('animationcomplete-bellows_pump', () => { this.isPumping = false; });
    this.uiContainer.add(this.bellowsContainer);
  }

  private createHeatUpButton() {
    this.heatUpBtnContainer = this.add.container(0, 0);
    const bg = this.add.rectangle(0, 0, 90, 70, 0x1c1917).setStrokeStyle(2, 0x57534e).setName('btnBg');
    const icon = this.add.text(0, -12, '🔥', { fontSize: '20px' }).setOrigin(0.5).setName('btnIcon');
    const label = this.add.text(0, 10, 'HEAT UP', { fontSize: '10px', color: '#fbbf24', fontStyle: 'bold', fontFamily: 'monospace' }).setOrigin(0.5);
    const countTxt = this.add.text(0, 22, `x${this.charcoalCount}`, { fontSize: '11px', color: '#78716c', fontFamily: 'monospace' }).setOrigin(0.5).setName('countTxt');
    this.heatUpBtnContainer.add([bg, icon, label, countTxt]);
    this.heatUpBtnContainer.setInteractive(new Phaser.Geom.Rectangle(-45, -35, 90, 70), Phaser.Geom.Rectangle.Contains);
    this.uiContainer.add(this.heatUpBtnContainer);
    this.refreshHeatUpButton();
  }

  private refreshHeatUpButton() {
    if (!this.heatUpBtnContainer) return;
    const bg = this.heatUpBtnContainer.getByName('btnBg') as Phaser.GameObjects.Rectangle;
    const countTxt = this.heatUpBtnContainer.getByName('countTxt') as Phaser.GameObjects.Text;
    const icon = this.heatUpBtnContainer.getByName('btnIcon') as Phaser.GameObjects.Text;
    countTxt.setText(`x${this.charcoalCount}`);
    if (this.charcoalCount > 0) {
      bg.setStrokeStyle(2, 0xea580c);
      countTxt.setColor('#a8a29e');
      icon.setAlpha(1);
    } else {
      bg.setStrokeStyle(2, 0x292524);
      countTxt.setColor('#44403c');
      icon.setAlpha(0.3);
    }
  }

  public updateCharcoalCount(count: number) {
    this.charcoalCount = count;
    this.refreshHeatUpButton();
  }

  private pumpBellows() {
    if (this.isPumping) return;
    this.isPumping = true;
    this.bellowsSprite.play('bellows_pump');

    if (this.temperature > 0) {
      this.temperature = Math.min(100, this.temperature + 5);
      if (!this.isPlaying && !this.isReadyToStart) {
        this.isReadyToStart = true;
        this.infoText.setText('CLICK TO START').setColor('#fbbf24');
      }
    }
  }

  private requestHeatUp() {
    if (this.charcoalCount > 0) {
      this.tweens.add({ targets: this.heatUpBtnContainer, scale: 0.9, duration: 50, yoyo: true });
      if (this.onHeatUpRequest) this.onHeatUpRequest();
    } else {
      this.cameras.main.shake(100, 0.005);
    }
  }

  public heatUp() {
    this.temperature = Math.min(100, this.temperature + 40);
    if (!this.isPlaying) {
      this.isReadyToStart = true;
      this.infoText.setText('CLICK TO START').setColor('#fbbf24');
    }
    this.flashOverlay.setFillStyle(0xff8800, 1).setAlpha(0.4);
    this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 400, ease: 'Cubic.easeOut' });
  }

  private handleResize() {
    this.centerX = this.scale.width / 2;
    this.centerY = this.scale.height / 2;
    if (this.backgroundTile) this.backgroundTile.setSize(this.scale.width, this.scale.height);
    if (this.bgOverlay) this.bgOverlay.setSize(this.scale.width, this.scale.height);
    if (this.flashOverlay) this.flashOverlay.setSize(this.scale.width, this.scale.height);

    const surfaceH = this.scale.height * this.anvilConfig.heightRatio;
    const b = this.centerY + surfaceH / 2 + this.anvilConfig.yOffset;

    if (this.anvilImage && this.anvilImage.texture.key !== '__MISSING') {
      const targetWidth = this.scale.width * 1.3;
      this.anvilImage.setScale(targetWidth / this.anvilImage.width);
      this.anvilImage.setPosition(this.centerX, b + this.anvilConfig.imageOffsetY);
    }

    if (this.ambientGlow) {
      this.ambientGlow.setPosition(this.centerX, b);
    }

    const bladeY = b - surfaceH * 0.55; 
    this.bladeContainer.setPosition(this.centerX, bladeY);
    const rad = Phaser.Math.DegToRad(this.bladeContainer.angle);
    this.bladeContainer.x += Math.cos(rad) * 80;
    this.bladeContainer.y += Math.sin(rad) * 80;

    const ox = -Math.sin(rad) * this.anvilConfig.hitAreaOffset;
    const oy = Math.cos(rad) * this.anvilConfig.hitAreaOffset;
    this.hammerHitArea.setPosition(this.bladeContainer.x + ox, this.bladeContainer.y + oy);
    this.rebuildHitPoly();

    this.repositionUIElements();
  }

  private repositionUIElements() {
    const w = this.scale.width;
    (this.uiContainer.getByName('progBg') as any).setPosition(this.centerX, 40);
    this.progressBar.setPosition(this.centerX - 150, 40);
    this.qualityText.setPosition(this.centerX, 65);
    const stackX = w - 70;
    const stackTopY = this.centerY - 100;
    this.tempValueText.setPosition(stackX, stackTopY - 165);
    (this.uiContainer.getByName('tempFrame') as any).setPosition(stackX, stackTopY);
    (this.uiContainer.getByName('tempBg') as any).setPosition(stackX, stackTopY);
    this.tempBar.setPosition(stackX, stackTopY + 125);
    this.bellowsContainer.setPosition(stackX, stackTopY + 205);
    this.heatUpBtnContainer.setPosition(stackX, stackTopY + 300);
    this.infoText.setPosition(this.centerX, this.centerY - 220);
    this.comboText.setPosition(this.centerX, this.centerY - 300);
  }

  private rebuildHitPoly() {
    const w = this.hammerHitArea.width * this.hammerHitArea.scaleX;
    const h = this.hammerHitArea.height * this.hammerHitArea.scaleY;
    const cx = this.hammerHitArea.x;
    const cy = this.hammerHitArea.y;
    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    const cos = Math.cos(rad);
    const sin = Math.sin(rad);
    const corners = [
      { x: -w / 2, y: -h / 2 }, { x: w / 2, y: -h / 2 },
      { x: w / 2, y: h / 2 }, { x: -w / 2, y: h / 2 },
    ].map((p) => ({ x: cx + p.x * cos - p.y * sin, y: cy + p.x * sin + p.y * cos }));
    this.hitPoly = new Phaser.Geom.Polygon(corners);
  }

  private isPointerInHitArea(px: number, py: number) {
    return this.hitPoly && Phaser.Geom.Polygon.Contains(this.hitPoly, px, py);
  }

  private handleInput(pointer?: Phaser.Input.Pointer) {
    if (this.isFinished) return;
    if (!this.isPlaying) {
      if (this.isReadyToStart) { 
        this.isPlaying = true; 
        this.infoText.setVisible(false); 
        this.resetRing(); 
        this.flashOverlay.setFillStyle(0xffffff, 1).setAlpha(0.2);
        this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 300 });
      } else { this.cameras.main.shake(50, 0.005); this.showFeedback('TOO COLD!', 0x3b82f6, 1.0); }
      return;
    }
    if (this.time.now - this.lastHitTime < this.hitCooldown) return;
    this.lastHitTime = this.time.now;
    const swingX = pointer ? pointer.worldX : this.hitX;
    const swingY = pointer ? pointer.worldY : this.hitY;
    if (this.currentTempStage === 'COLD' || this.currentTempStage === 'NORMAL') { this.showFeedback('TOO COLD!', 0x3b82f6, 1.0); return; }

    const diff = Math.abs(this.currentRadius - this.targetRadius);
    const eff = this.currentTempStage === 'AURA' ? 1.5 : this.currentTempStage === 'HOT' ? 1.0 : 0.5;

    if (diff < 18) {
      this.score += Math.ceil(8 * eff); 
      this.combo++; 
      this.perfectCount++;
      if (this.perfectCount >= 6) {
          this.currentQuality += 1;
          this.showFeedback('QUALITY UP!', 0xfbbf24, 1.3, swingX, swingY - 40);
      }
      this.createSparks(40, 0xffaa00, 2.0, 'spark_perfect', swingX, swingY); 
      this.showFeedback('PERFECT!', 0xffb300, 1.5, swingX, swingY); 
      this.cameras.main.shake(200, 0.025);
    } else if (diff < 55) {
      this.score += Math.ceil(5 * eff); 
      this.combo = 0; 
      this.currentQuality = Math.max(0, this.currentQuality - 2);
      this.createSparks(20, 0xffffff, 1.3, 'spark_normal', swingX, swingY); 
      this.showFeedback('GOOD', 0xe5e5e5, 1.0, swingX, swingY);
    } else {
      this.handleMiss(swingX, swingY);
    }

    this.updateProgressBar();
    if (this.score >= this.targetScore) this.winGame(); else this.resetRing();
  }

  private handleMiss(x?: number, y?: number) {
    this.score = Math.max(0, this.score - 5); 
    this.combo = 0; 
    this.currentQuality = Math.max(0, this.currentQuality - 5);
    this.cameras.main.shake(120, 0.012);
    this.showFeedback('MISS', 0xef4444, 1.2, x, y); 
    this.updateProgressBar(); 
    this.resetRing();
  }

  update(time: number, delta: number) {
    if (this.isFinished) return;
    if (this.isPlaying) this.handleRingLogic(delta);
    this.temperature = Math.max(0, this.temperature - this.coolingRate * (delta / 1000));
    this.refreshVisuals();
    if (!this.isPlaying && this.isReadyToStart && this.temperature <= 0) {
      this.isReadyToStart = false;
      this.infoText.setText('FORGE IS COLD\nADD FUEL TO HEAT').setColor('#3b82f6');
    }
  }

  private refreshVisuals() {
    const label = this.getQualityLabel(this.currentQuality);
    const colorStr = this.getLabelColor(this.currentQuality);
    this.qualityText.setText(label);
    this.qualityText.setColor(colorStr);

    const ratio = this.temperature / 100;
    this.tempBar.scaleY = ratio;
    this.tempValueText.setText(`${Math.floor(20 + ratio * 1480)}°C`);
    const current = Phaser.Display.Color.Interpolate.ColorWithColor(new Phaser.Display.Color(63, 63, 70), new Phaser.Display.Color(253, 230, 138), 100, ratio * 100);
    const color = Phaser.Display.Color.GetColor(current.r, current.g, current.b);
    this.bladeFallbackRect.setFillStyle(color, 1);
    if (this.bladeImage) this.bladeImage.setTint(color);
    const progress = Phaser.Math.Clamp(this.score / this.targetScore, 0, 1);
    const stage = Math.min(5, Math.floor(progress * 6));
    if (stage !== this.lastStage) { this.setBladeStage(stage); this.lastStage = stage; }
    if (this.ambientGlow) this.ambientGlow.setAlpha(ratio * 0.4);
    if (this.temperature <= 0) this.currentTempStage = 'COLD';
    else if (this.temperature > 75) this.currentTempStage = 'AURA';
    else if (this.temperature > 40) this.currentTempStage = 'HOT';
    else if (this.temperature > 15) this.currentTempStage = 'WARM';
    else this.currentTempStage = 'NORMAL';
  }

  private setBladeStage(stage: number) {
    const key = `blade_stage_${stage}`;
    if (this.textures.exists(key)) {
      if (!this.bladeImage) { this.bladeImage = this.add.image(0, 0, key).setOrigin(0.5); this.bladeContainer.add(this.bladeImage); } 
      else this.bladeImage.setTexture(key);
      this.bladeImage.setVisible(true);
      this.bladeFallbackRect.setVisible(true).setAlpha(0.15);
      if (this.lastStage !== -1) {
          this.createOmniBurst(70, 0xffcc00, 2.5, 'spark_perfect', this.bladeContainer.x, this.bladeContainer.y);
          this.flashOverlay.setFillStyle(0xffcc00, 1).setAlpha(0.35);
          this.tweens.add({ targets: this.flashOverlay, alpha: 0, duration: 250, ease: 'Quad.easeOut' });
          this.tweens.add({ targets: this.bladeContainer, scale: 1.15, duration: 100, yoyo: true, ease: 'Quad.easeOut' });
      }
    }
  }

  private handleRingLogic(delta: number) {
    this.ringTimer += delta;
    const t = Math.min(this.ringTimer / this.shrinkDuration, 1.5);
    this.currentRadius = this.startRadius * (1 - t * t);
    const ringColor = this.currentRadius < this.targetRadius ? 0xffffff : 0xfabf24;
    this.approachRing.clear().lineStyle(8, ringColor, 0.6).strokeCircle(this.hitX, this.hitY, Math.max(0, this.currentRadius));
    if (this.currentRadius < this.targetRadius - 30) { 
        this.combo = 0; 
        this.resetRing(); 
    }
  }

  private resetRing() {
    if (this.temperature <= 0) {
      this.isPlaying = false; this.isReadyToStart = false;
      this.targetRing.clear(); this.approachRing.clear();
      this.infoText.setVisible(true).setText('FORGE IS COLD\nADD FUEL TO HEAT').setColor('#3b82f6');
      return;
    }
    this.currentRadius = this.startRadius; this.ringTimer = 0;
    const w = this.hammerHitArea.width * this.hammerHitArea.scaleX;
    const h = this.hammerHitArea.height * this.hammerHitArea.scaleY;
    const u = Phaser.Math.Between(-w * 0.35, w * 0.35);
    const v = Phaser.Math.Between(-h * 0.25, h * 0.25);
    const rad = Phaser.Math.DegToRad(this.hammerHitArea.angle);
    this.hitX = this.hammerHitArea.x + (u * Math.cos(rad) - v * Math.sin(rad));
    this.hitY = this.hammerHitArea.y + (u * Math.sin(rad) + v * Math.cos(rad));
    if (this.isPlaying) {
      this.targetRing.clear().fillStyle(0xfabf24, 0.1).fillCircle(this.hitX, this.hitY, this.targetRadius).lineStyle(5, 0xfabf24, 0.4).strokeCircle(this.hitX, this.hitY, this.targetRadius);
    }
  }

  private updateProgressBar() { this.progressBar.width = Phaser.Math.Clamp((this.score / this.targetScore) * 300, 0, 300); }

  private createSparks(count: number, color: number, scale: number, key: string, x: number, y: number) {
    const emitter = this.add.particles(x, y, this.textures.exists(key) ? key : 'white', { lifespan: 800, speed: { min: 300 * scale, max: 700 * scale }, angle: { min: 230, max: 310 }, scale: { start: 0.7, end: 0 }, gravityY: 1200, blendMode: 'ADD', tint: color });
    emitter.explode(count);
  }

  private createOmniBurst(count: number, color: number, scale: number, key: string, x: number, y: number) {
    const emitter = this.add.particles(x, y, this.textures.exists(key) ? key : 'white', { lifespan: 1200, speed: { min: 200 * scale, max: 500 * scale }, angle: { min: 0, max: 360 }, scale: { start: 0.8, end: 0 }, gravityY: 400, blendMode: 'ADD', tint: color });
    emitter.explode(count);
  }

  private showFeedback(text: string, color: number, scale: number, x?: number, y?: number) {
    const fx = x ?? this.hitX; const fy = y ?? this.hitY;
    const fb = this.add.text(fx, fy - 140, text, { fontFamily: 'Arial', fontSize: '36px', fontStyle: 'bold', color: '#' + color.toString(16).padStart(6, '0'), stroke: '#000', strokeThickness: 5 }).setOrigin(0.5).setScale(0.5).setAlpha(0).setDepth(25);
    this.tweens.add({ targets: fb, y: fy - 200, alpha: 1, scale: scale, duration: 250, hold: 400, yoyo: true, onComplete: () => fb.destroy() });
    if (this.combo > 1) { this.comboText.setText(`${this.combo} COMBO!`).setAlpha(1); this.tweens.add({ targets: this.comboText, scale: { from: 1.5, to: 1 }, duration: 200, alpha: { from: 1, to: 0 }, delay: 500 }); }
  }

  private winGame() {
    this.isFinished = true; this.isPlaying = false; this.targetRing.clear(); this.approachRing.clear();
    if (this.onStatusUpdate) this.onStatusUpdate(this.temperature);
    const bg = this.add.rectangle(this.centerX, this.centerY, this.scale.width, this.scale.height, 0x000000).setAlpha(0).setDepth(100);
    this.tweens.add({ targets: bg, alpha: 0.85, duration: 500 });
    const label = this.getQualityLabel(this.currentQuality);
    const txt = this.add.text(this.centerX, this.centerY, `${label} CRAFT!`, { fontFamily: 'Georgia', fontSize: '72px', color: this.getLabelColor(this.currentQuality), stroke: '#000', strokeThickness: 3 }).setOrigin(0.5).setAlpha(0).setDepth(101);
    this.tweens.add({ targets: txt, alpha: 1, scale: { from: 0.5, to: 1.2 }, duration: 600, ease: 'Back.out', onComplete: () => { this.time.delayedCall(1000, () => { if (this.onComplete) this.onComplete(this.currentQuality); }); } });
  }

  public getTemperature() { return this.temperature; }
}

import React, { useState, useCallback, useMemo, useEffect } from 'react';
import { EQUIPMENT_SUBCATEGORIES, EQUIPMENT_ITEMS } from '../../../data/equipment';
import { EquipmentCategory, EquipmentItem } from '../../../types/index';
import SmithingMinigame from './SmithingMinigame';
import WorkbenchMinigame from './WorkbenchMinigame';
import { Hammer, Shield, Sword, ChevronRight, Info, ChevronLeft, Lock, Check, X as XIcon, Box, Flame, ChevronDown, Heart, Star, Zap, Award, Wrench, X, ShoppingCart, Brain } from 'lucide-react';
import { useGame } from '../../../context/GameContext';
import { GAME_CONFIG } from '../../../config/game-config';
import { MASTERY_THRESHOLDS } from '../../../config/mastery-config';
import { MATERIALS } from '../../../data/materials';
import { getAssetUrl } from '../../../utils';

interface ForgeTabProps {
    onNavigate: (tab: any) => void;
}

const ForgeTab: React.FC<ForgeTabProps> = ({ onNavigate }) => {
  const { state, actions } = useGame();

  const { inventory, stats, isCrafting, craftingMastery, activeEvent } = state;
  const { hasFurnace, hasWorkbench } = state.forge;

  const [activeCategory, setActiveCategory] = useState<EquipmentCategory>('WEAPON');
  const [selectedItem, setSelectedItem] = useState<EquipmentItem | null>(null);
  const [isPanelOpen, setIsPanelOpen] = useState(true);
  const [hasPromptedFurnace, setHasPromptedFurnace] = useState(false);

  const [expandedSubCat, setExpandedSubCat] = useState<string | null>(null);
  const [favorites, setFavorites] = useState<string[]>([]);

  const [hoveredItem, setHoveredItem] = useState<EquipmentItem | null>(null);
  const [tooltipPos, setTooltipPos] = useState({ x: 0, y: 0 });

  const getInventoryCount = useCallback((id: string) => {
      return inventory.find(i => i.id === id)?.quantity || 0;
  }, [inventory]);

  const getResourceName = (id: string) => {
      const itemDef = Object.values(MATERIALS).find(i => i.id === id);
      return itemDef ? itemDef.name : id;
  };

  const GLOBAL_COOLING_RATE_PER_SEC = 5; 
  const timeDiffSec = (Date.now() - (state.lastForgeTime || 0)) / 1000;
  const coolingAmount = timeDiffSec * GLOBAL_COOLING_RATE_PER_SEC;
  const currentResidualTemp = Math.max(0, (state.forgeTemperature || 0) - coolingAmount);

  const hasHeat = currentResidualTemp > 0;
  const charcoalCount = getInventoryCount('charcoal');
  const hasFuel = charcoalCount > 0;

  useEffect(() => {
    if (!hasFurnace && !hasPromptedFurnace && !activeEvent) {
        actions.triggerEvent({
            id: 'CUSTOMER_VISIT',
            title: "The Forge lies in Ruins",
            description: "Your journey as a blacksmith starts with a single spark. To begin forging weapons and armor, you must first install a Furnace from the market.",
            options: [
                {
                    label: "Visit Market (500 G)",
                    action: () => onNavigate('MARKET')
                },
                {
                    label: "I'll look around first",
                    action: () => {}
                }
            ]
        });
        setHasPromptedFurnace(true);
    }
  }, [hasFurnace, hasPromptedFurnace, activeEvent, actions, onNavigate]);

  const canEnterForge = useMemo(() => {
      if (!selectedItem) return false;
      if (selectedItem.craftingType === 'WORKBENCH') return true;
      return hasFuel || hasHeat;
  }, [selectedItem, hasFuel, hasHeat]);

  const requiredEnergy = useMemo(() => {
      if (!selectedItem) return GAME_CONFIG.ENERGY_COST.CRAFT;
      const count = craftingMastery[selectedItem.id] || 0;
      if (count >= MASTERY_THRESHOLDS.ARTISAN) {
          return GAME_CONFIG.ENERGY_COST.CRAFT - MASTERY_THRESHOLDS.ARTISAN_BONUS.energyDiscount;
      }
      return GAME_CONFIG.ENERGY_COST.CRAFT;
  }, [selectedItem, craftingMastery]);

  const hasEnergy = stats.energy >= requiredEnergy;

  const canAffordResources = useCallback((item: EquipmentItem) => {
      return item.requirements.every(req => getInventoryCount(req.id) >= req.count);
  }, [getInventoryCount]);

  const visibleItems = useMemo(() => {
      return EQUIPMENT_ITEMS.filter(item => {
          if (item.tier > stats.tierLevel) return false;
          const subCatDef = EQUIPMENT_SUBCATEGORIES.find(sc => sc.id === item.subCategoryId);
          return subCatDef?.categoryId === activeCategory;
      });
  }, [activeCategory, stats.tierLevel]);

  const favoriteItems = useMemo(() => {
      return visibleItems.filter(item => favorites.includes(item.id));
  }, [visibleItems, favorites]);

  const groupedItems = useMemo(() => {
      const groups: Record<string, EquipmentItem[]> = {};
      visibleItems.forEach(item => {
          if (!groups[item.subCategoryId]) groups[item.subCategoryId] = [];
          groups[item.subCategoryId].push(item);
      });
      return groups;
  }, [visibleItems]);

  const visibleSubCats = useMemo(() => {
      return EQUIPMENT_SUBCATEGORIES.filter(sc => 
          sc.categoryId === activeCategory && groupedItems[sc.id] && groupedItems[sc.id].length > 0
      );
  }, [activeCategory, groupedItems]);

  useEffect(() => {
      if (favoriteItems.length > 0) {
          setExpandedSubCat('FAVORITES');
      } else if (visibleSubCats.length > 0) {
          setExpandedSubCat(visibleSubCats[0].id);
      } else {
          setExpandedSubCat(null);
      }
  }, [activeCategory, visibleSubCats, favoriteItems.length]);

  const handleCategoryChange = useCallback((cat: EquipmentCategory) => {
    setActiveCategory(cat);
    setSelectedItem(null);   
  }, []);

  const toggleSubCategory = useCallback((subCatId: string) => {
      setExpandedSubCat(prev => (prev === subCatId ? null : subCatId));
  }, []);

  const toggleFavorite = useCallback((e: React.MouseEvent, itemId: string) => {
      e.stopPropagation(); 
      setFavorites(prev => 
          prev.includes(itemId)
              ? prev.filter(id => id !== itemId)
              : [...prev, itemId]
      );
  }, []);

  const startCrafting = useCallback(() => {
      if (!selectedItem) return;
      actions.startCrafting(selectedItem);
      setIsPanelOpen(false); 
  }, [actions, selectedItem]);

  const cancelCrafting = useCallback(() => {
      if (selectedItem) {
          actions.cancelCrafting(selectedItem);
      } else {
          actions.setCrafting(false); 
      }
      setIsPanelOpen(true);
  }, [actions, selectedItem]);

  const handleMinigameComplete = useCallback((score: number, bonus?: number) => {
    if (selectedItem) {
        actions.finishCrafting(selectedItem, score, bonus);
    }
    setIsPanelOpen(true);
  }, [selectedItem, actions]);

  const handleMouseEnter = useCallback((item: EquipmentItem, e: React.MouseEvent) => {
      setHoveredItem(item);
      setTooltipPos({ x: e.clientX, y: e.clientY });
  }, []);

  const handleMouseMove = useCallback((e: React.MouseEvent) => {
      if (hoveredItem) {
          setTooltipPos({ x: e.clientX, y: e.clientY });
      }
  }, [hoveredItem]);

  const handleMouseLeave = useCallback(() => {
      setHoveredItem(null);
  }, []);

  const getMasteryLevel = (count: number) => {
      if (count >= MASTERY_THRESHOLDS.ARTISAN) return 2;
      if (count >= MASTERY_THRESHOLDS.ADEPT) return 1;
      return 0;
  };

  const getMasteryIcon = (level: number) => {
      if (level === 2) return <Star className="w-3 h-3 text-yellow-400 fill-yellow-400" />;
      if (level === 1) return <Star className="w-3 h-3 text-stone-300 fill-stone-300" />;
      return <Star className="w-3 h-3 text-amber-700/50" />;
  };

  const renderItemCard = (item: EquipmentItem) => {
      const isSelected = selectedItem?.id === item.id;
      const isFav = favorites.includes(item.id);
      const count = inventory.filter(i => i.name === item.name).length;
      const masteryCount = craftingMastery[item.id] || 0;
      const masteryLevel = getMasteryLevel(masteryCount);

      return (
        <div 
            key={item.id}
            onClick={() => setSelectedItem(item)}
            onMouseEnter={(e) => handleMouseEnter(item, e)}
            onMouseMove={handleMouseMove}
            onMouseLeave={handleMouseLeave}
            className={`relative flex flex-col items-center rounded-lg border transition-all cursor-pointer group text-left h-[130px] overflow-hidden ${
                isSelected 
                ? 'bg-amber-900/20 border-amber-500 shadow-[0_0_15px_rgba(245,158,11,0.2)]' 
                : 'bg-stone-800 border-stone-700 hover:border-stone-500 hover:bg-stone-750'
            }`}
        >
            <div className="w-full flex justify-between items-start p-2 z-10">
                 <span className={`text-[10px] font-bold tracking-wider font-mono ${isSelected ? 'text-amber-400' : 'text-stone-600'}`}>
                    TIER {item.tier}
                </span>

                <div className="flex items-center gap-1 -mt-1 -mr-1">
                    {masteryCount > 0 && (
                        <div className="p-1" title={`Mastery Level ${masteryLevel} (${masteryCount})`}>
                            {getMasteryIcon(masteryLevel)}
                        </div>
                    )}
                    <button 
                        onClick={(e) => toggleFavorite(e, item.id)}
                        className="p-1 rounded-full hover:bg-stone-700 transition-colors"
                    >
                        <Heart className={`w-3.5 h-3.5 ${isFav ? 'fill-red-500 text-red-500' : 'text-stone-600 hover:text-stone-400'}`} />
                    </button>
                </div>
            </div>

            <div className="flex-1 flex items-center justify-center text-3xl group-hover:scale-110 transition-transform -mt-2">
                {item.icon}
            </div>

            <div className="w-full text-center pb-2 px-1 flex flex-col items-center gap-1">
                <div className={`text-xs font-bold leading-tight truncate w-full ${isSelected ? 'text-amber-200' : 'text-stone-300'}`}>
                    {item.name}
                </div>

                <div className="h-5 flex items-center justify-center w-full">
                    {count > 0 ? (
                        <div className="inline-flex items-center gap-0.5 bg-stone-950/50 px-2 py-0.5 rounded text-[10px] font-mono text-stone-500 border border-stone-800/50">
                            <Box className="w-2.5 h-2.5" /> {count}
                        </div>
                    ) : (
                        <div className="h-[18px]"></div>
                    )}
                </div>
            </div>
        </div>
      );
  };

  const isRequirementMet = useMemo(() => {
      if (!selectedItem) return true;
      if (selectedItem.craftingType === 'FORGE') return hasFurnace;
      if (selectedItem.craftingType === 'WORKBENCH') return hasWorkbench;
      return true;
  }, [selectedItem, hasFurnace, hasWorkbench]);

  const content = useMemo(() => {
    const canCraft = selectedItem && canAffordResources(selectedItem) && canEnterForge && hasEnergy && isRequirementMet;
    let masteryInfo = null;
    if (selectedItem) {
        const count = craftingMastery[selectedItem.id] || 0;
        const level = getMasteryLevel(count);
        let nextThreshold = MASTERY_THRESHOLDS.ADEPT;
        let progress = 0;
        let label = "Novice";
        let color = "text-stone-500";
        let benefits = "Base Stats";

        if (level === 0) {
            nextThreshold = MASTERY_THRESHOLDS.ADEPT;
            progress = (count / MASTERY_THRESHOLDS.ADEPT) * 100;
        } else if (level === 1) {
            label = "Adept";
            color = "text-stone-300";
            nextThreshold = MASTERY_THRESHOLDS.ARTISAN;
            progress = ((count - MASTERY_THRESHOLDS.ADEPT) / (MASTERY_THRESHOLDS.ARTISAN - MASTERY_THRESHOLDS.ADEPT)) * 100;
            benefits = "Value +10%, Stats +10%";
        } else {
            label = "Artisan";
            color = "text-yellow-400";
            nextThreshold = count;
            progress = 100;
            benefits = "Value +25%, Stats +20%, Cost -5 Energy";
        }
        masteryInfo = { count, level, nextThreshold, progress, label, color, benefits };
    }

    return (
        <div 
            className="relative h-full w-full bg-stone-950 overflow-hidden"
            style={{ 
                backgroundImage: `url(${getAssetUrl('tile_forge.png')})`,
                backgroundRepeat: 'repeat',
                backgroundBlendMode: 'multiply'
            }}
        >

        {selectedItem && !isRequirementMet && (
            <div className="absolute inset-0 z-[60] flex items-center justify-center">
                <div className="absolute inset-0 bg-stone-950/90 backdrop-blur-md animate-in fade-in duration-700"></div>
                <div className="relative z-10 p-8 max-w-md w-full bg-stone-900 border-2 border-stone-800 rounded-2xl shadow-2xl flex flex-col items-center text-center animate-in zoom-in-95 duration-500">
                    <button 
                        onClick={() => setSelectedItem(null)}
                        className="absolute top-4 right-4 p-2 text-stone-500 hover:text-stone-300 transition-colors"
                    >
                        <X className="w-5 h-5" />
                    </button>
                    <div className="w-20 h-20 bg-stone-800 rounded-full flex items-center justify-center mb-6 border border-stone-700">
                        {selectedItem.craftingType === 'FORGE' ? <Flame className="w-10 h-10 text-stone-600" /> : <Wrench className="w-10 h-10 text-stone-600" />}
                    </div>
                    <h2 className="text-2xl font-bold text-stone-300 font-serif mb-2">
                        {selectedItem.craftingType === 'FORGE' ? 'Furnace Required' : 'Workbench Required'}
                    </h2>
                    <p className="text-stone-500 mb-8 leading-relaxed">
                        Crafting <span className="text-amber-500 font-bold">{selectedItem.name}</span> requires a functional {selectedItem.craftingType === 'FORGE' ? 'furnace' : 'workbench'}. 
                        Visit the market to purchase one.
                    </p>
                    <button 
                        onClick={() => onNavigate('MARKET')}
                        className="w-full py-4 bg-amber-700 hover:bg-amber-600 text-amber-50 font-bold rounded-xl shadow-lg hover:shadow-amber-900/40 transition-all flex items-center justify-center gap-2 group"
                    >
                        Go to Market
                        <ChevronRight className="w-5 h-5 group-hover:translate-x-1 transition-transform" />
                    </button>
                </div>
            </div>
        )}

        <div className={`absolute inset-0 z-0 flex w-full h-full ${((selectedItem && !isRequirementMet) || !hasFurnace) ? 'blur-sm pointer-events-none' : ''}`}>

            <div className={`h-full relative flex flex-col transition-all duration-500 ease-in-out ${isPanelOpen ? 'w-[60%]' : 'w-full'}`}>
            <div className="w-full h-full flex flex-col items-center justify-center p-8 bg-stone-925/40 relative overflow-hidden">

                <div className="absolute inset-0 opacity-10 pointer-events-none flex items-center justify-center">
                    {selectedItem?.craftingType === 'FORGE' ? (
                        <Hammer className="w-96 h-96 text-stone-500" />
                    ) : (
                        <Wrench className="w-96 h-96 text-stone-500" />
                    )}
                </div>

                {selectedItem ? (
                    <div className="z-10 flex flex-col items-center animate-in fade-in zoom-in duration-300 w-full max-w-lg">
                    <div className="relative group">
                        <div className={`w-48 h-48 bg-stone-900 rounded-full border-4 flex items-center justify-center transition-all duration-500 ${
                            selectedItem.craftingType === 'FORGE' 
                            ? 'border-amber-600 shadow-[0_0_40px_rgba(217,119,6,0.2)]' 
                            : 'border-emerald-600 shadow-[0_0_40px_rgba(16,185,129,0.2)]'
                        } mb-8 group-hover:scale-105`}>
                            <span className="text-8xl filter drop-shadow-lg">{selectedItem.icon}</span>
                        </div>
                    </div>

                    <h2 className="text-3xl font-bold text-amber-500 mb-2 font-serif tracking-wide">{selectedItem.name}</h2>
                    <p className="text-stone-400 text-center max-w-md mb-4 italic">"{selectedItem.description}"</p>

                    {/* Base Stats Section Added */}
                    <div className="w-full grid grid-cols-4 gap-2 mb-6">
                        <div className="bg-stone-900/80 border border-stone-800 p-2 rounded-lg flex flex-col items-center">
                            <span className="text-[8px] text-stone-500 font-bold uppercase flex items-center gap-1 mb-1"><Sword className="w-2 h-2"/> P.Atk</span>
                            <span className="text-xs font-mono font-bold text-stone-300">{selectedItem.baseStats?.physicalAttack || 0}</span>
                        </div>
                        <div className="bg-stone-900/80 border border-stone-800 p-2 rounded-lg flex flex-col items-center">
                            <span className="text-[8px] text-stone-500 font-bold uppercase flex items-center gap-1 mb-1"><Shield className="w-2 h-2"/> P.Def</span>
                            <span className="text-xs font-mono font-bold text-stone-300">{selectedItem.baseStats?.physicalDefense || 0}</span>
                        </div>
                        <div className="bg-stone-900/80 border border-stone-800 p-2 rounded-lg flex flex-col items-center">
                            <span className="text-[8px] text-stone-500 font-bold uppercase flex items-center gap-1 mb-1"><Zap className="w-2 h-2"/> M.Atk</span>
                            <span className="text-xs font-mono font-bold text-stone-300">{selectedItem.baseStats?.magicalAttack || 0}</span>
                        </div>
                        <div className="bg-stone-900/80 border border-stone-800 p-2 rounded-lg flex flex-col items-center">
                            <span className="text-[8px] text-stone-500 font-bold uppercase flex items-center gap-1 mb-1"><Brain className="w-2 h-2"/> M.Def</span>
                            <span className="text-xs font-mono font-bold text-stone-300">{selectedItem.baseStats?.magicalDefense || 0}</span>
                        </div>
                    </div>

                    {masteryInfo && (
                        <div className="w-full bg-stone-900/50 p-3 rounded-lg border border-stone-800 mb-6 backdrop-blur-sm">
                            <div className="flex justify-between items-center mb-1 text-xs uppercase font-bold tracking-wider">
                                <span className="text-stone-500 flex items-center gap-1">
                                    <Award className="w-3 h-3" /> Mastery
                                </span>
                                <span className={masteryInfo.color}>{masteryInfo.label}</span>
                            </div>
                            <div className="w-full h-2 bg-stone-800 rounded-full overflow-hidden mb-1.5">
                                <div 
                                    className={`h-full transition-all duration-500 ${masteryInfo.level === 2 ? 'bg-yellow-500' : 'bg-amber-600'}`} 
                                    style={{ width: `${masteryInfo.progress}%` }}
                                ></div>
                            </div>
                            <div className="flex justify-between items-center text-[10px]">
                                <span className="text-stone-500">
                                    {masteryInfo.level < 2 ? `${masteryInfo.count} / ${masteryInfo.nextThreshold} Crafted` : 'Max Level'}
                                </span>
                                <span className="text-emerald-500">{masteryInfo.benefits}</span>
                            </div>
                        </div>
                    )}

                    <div className="flex items-center gap-3 mb-6">
                         <div className={`flex items-center gap-2 px-4 py-2 rounded-full border font-mono text-sm backdrop-blur-sm ${
                            hasEnergy 
                            ? 'bg-blue-900/40 border-blue-700/50 text-blue-400' 
                            : 'bg-red-900/40 border-red-700/50 text-red-500 animate-pulse'
                        }`}>
                            <Zap className="w-4 h-4" />
                            <span>Energy: -{requiredEnergy}</span>
                        </div>
                    </div>

                    <button 
                        onClick={startCrafting}
                        disabled={!canCraft}
                        className={`px-12 py-4 rounded-lg font-bold text-lg shadow-lg transition-all transform hover:-translate-y-1 flex items-center gap-3 border ${
                            canCraft 
                            ? selectedItem.craftingType === 'FORGE'
                                ? 'bg-amber-700 hover:bg-amber-600 text-amber-50 border-amber-500 hover:shadow-amber-900/50'
                                : 'bg-emerald-700 hover:bg-emerald-600 text-emerald-50 border-emerald-500 hover:shadow-emerald-900/50'
                            : 'bg-stone-800 text-stone-500 border-stone-700 cursor-not-allowed opacity-70'
                        }`}
                    >
                        {!isRequirementMet ? (
                            <>
                                <Lock className="w-6 h-6" />
                                Facility Required
                            </>
                        ) : !canEnterForge ? (
                            <>
                                <Flame className="w-6 h-6 text-red-500" />
                                Need Heat or Fuel
                            </>
                        ) : !hasEnergy ? (
                             <>
                                <Zap className="w-6 h-6 text-red-500" />
                                Need Energy
                            </>
                        ) : !canAffordResources(selectedItem) ? (
                            <>
                                <Lock className="w-6 h-6" />
                                Missing Resources
                            </>
                        ) : (
                            <>
                                {selectedItem.craftingType === 'FORGE' ? <Hammer className="w-6 h-6" /> : <Wrench className="w-6 h-6" />}
                                {selectedItem.craftingType === 'FORGE' ? 'Start Forging' : 'Start Crafting'}
                            </>
                        )}
                    </button>
                    </div>
                ) : (
                    <div className="z-10 flex flex-col items-center text-stone-600">
                    <div className="w-24 h-24 rounded-full border-4 border-dashed border-stone-700 flex items-center justify-center mb-4">
                        <Hammer className="w-10 h-10" />
                    </div>
                    <h3 className="text-xl font-bold text-stone-500 drop-shadow-md">The Anvil is Cold</h3>
